-- Poems batch 188
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('27e10616-32b5-4cca-ae1b-1df9eb19de45','丙申六月二十六日作飄風行','釋居簡','宋','宋诗','song-poetry','','[]','疎櫺夜肅肅，須臾復蕭蕭。',276,'全唐诗/poet.song.180000.json','["疎櫺夜肅肅，須臾復蕭蕭。", "怒穴土囊口，倏若錢塘潮。", "舉屋如斷梗，拔木如拔苗。", "破山老蒼髯，深林古風標。", "蟠錯黄金園，戛摩叢玉霄。", "九秋婁戰伯，萬竅皆聲銷。", "拗折巢鶴頂，攧折潜虬腰。", "斷裂到臃腫，更復論楚翹。", "閲世今幾何，殞身不崇朝。", "遂使青童童，不及紅夭夭。", "痛此梁棟具，充它烹飪樵。", "多應蜚廉慵，虐致生物妖。", "至今月蝕篇，首惡當嘲調。", "因依獲附麗，傲很仍矜驕。", "佳樹首見凌，綠髮首見彫。", "曷若凉解慍，又令不鳴條。", "生春日酣酣，吹雪停瀌瀌。", "昌稷豐薿薿，殄莠除翹翹。", "四郊掃烽煙，九天清泬寥。", "雲開鬰藍天，觀闕飛岧嶤。", "群后靈在茲，不曰舜與堯。", "願輟股肱佐，下昌熙洽朝。", "天遠雲不來，借便摶扶摇。"]'),
('ea812081-ba20-41e9-9301-bffae6eaf060','既作飄風行十有七日風雨倍前乃賦後篇','釋居簡','宋','宋诗','song-poetry','','[]','夏首魃爲虐，種插喧戽車。',291,'全唐诗/poet.song.180000.json','["夏首魃爲虐，種插喧戽車。", "駸駸六七月，原野皆菁華。", "再拜田祖賜，熨帖海若家。", "大有課水耨，小康占山畬。", "因依瞻江雲，西北起礮車。", "歸來省戶牖，綢繆亟撐叉。", "須臾眂溝壍，揞塞深搔杷。", "大塊果噫欠，天闊誰能遮。", "水立十丈渾，吹沙復流沙。", "江海尚若此，柰此箇稌花。", "再駕纔浹旬，怒很尤雄夸。", "簷聲挾霶𩃱，谷口應{含牙}谺。", "豈其發育初，繼以肅殺加。", "吹噓咸失中，刑賞仍過差。", "鄉來赤壁火，萬艘沈碧涯。", "鬼操逃天誅，不勦殘賊芽。", "巽二死餘責，噬臍徒咨嗟。", "矯矯水中龍，浮硤千萬艖。", "尺箠笞獨夫，鼎足成一家。", "至今說蜚廉，慷慨徒拜嘉。", "云胡艱難際，狂暴相紛拏。", "耕夫日懸懸，饁媼霜髿髿。", "欲刈爭淬鐮，欲穫競整耞。", "私償憂并吞，官輸虞扑撾。"]'),
('2b37b4dd-f049-4217-bf90-68d52d1b32f7','寄王平江侍郎  其一','釋居簡','宋','宋诗','song-poetry','','[]','在御無絃別有音，音中逸響豈難尋。',64,'全唐诗/poet.song.180000.json','["在御無絃別有音，音中逸響豈難尋。", "一彈首讋乘軒貴，萬古群空立仗瘖。", "肆狡缺唇安夜穴，憑妖九尾遠城陰。", "雙旌不駐夫差國，誰振延陵季子心。"]'),
('cacff8e4-9cd0-46fd-836f-06ecb1962017','寄王平江侍郎  其二','釋居簡','宋','宋诗','song-poetry','','[]','浮俗伽梨水上萍，池塘密密蔽澄明。',64,'全唐诗/poet.song.181000.json','["浮俗伽梨水上萍，池塘密密蔽澄明。", "疏開堂印邀麾節，袖出臺緘救劓黥。", "才辦買山錢未了，又營捩鼻木隨行。", "懸知不是緇雲福，詎敢忘憂衒獨清。"]'),
('9f7a1fc6-96d1-4319-b5c4-4c8288a0a776','王侍守治生魂神徐提點','釋居簡','宋','宋诗','song-poetry','','[]','日月何私等照臨，坦然明白洞幽陰。',64,'全唐诗/poet.song.181000.json','["日月何私等照臨，坦然明白洞幽陰。", "其餘不信信諸己，所以無求求放心。", "妖可擊蛇惟笏在，河當娶婦遣巫沈。", "不知今夕復何夕，起我懲姦誌怪吟。"]'),
('4383946d-51bc-435c-8fcf-e1f1348b67ed','餞燕  其一','釋居簡','宋','宋诗','song-poetry','','[]','去時不似來時好，舊海棠叢錦幄低。',32,'全唐诗/poet.song.181000.json','["去時不似來時好，舊海棠叢錦幄低。", "未必秋風便翻幕，樓空巢冷不堪棲。"]'),
('5cac46f1-2b5b-4472-9334-32b729240b1f','餞燕  其二','釋居簡','宋','宋诗','song-poetry','','[]','歌樓經雨損花枝，魂斷無情白傅詩。',32,'全唐诗/poet.song.181000.json','["歌樓經雨損花枝，魂斷無情白傅詩。", "不啄阿京墳上土，地遒天老總愁思。"]'),
('e07b4de2-faba-48ab-9517-55f28a633573','聞笛  其一','釋居簡','宋','宋诗','song-poetry','','[]','天籟無聲地籟沈，一轟千仞裂層陰。',32,'全唐诗/poet.song.181000.json','["天籟無聲地籟沈，一轟千仞裂層陰。", "朣朣喚得關山月，不作離鸞別鵠吟。"]'),
('7d6a08c3-2733-457f-843a-931c47c296b8','聞笛  其二','釋居簡','宋','宋诗','song-poetry','','[]','煖力輕盈透鳳膺，借商喚得老龍應。',32,'全唐诗/poet.song.181000.json','["煖力輕盈透鳳膺，借商喚得老龍應。", "不知孤負秋多少，盍向坡翁謝不能。"]'),
('2a127498-e1ca-4f3a-9e93-4e69895bae99','第三度風潮','釋居簡','宋','宋诗','song-poetry','','[]','風顛雨橫田爲陂，沒頭禾穎靡孑遺。',64,'全唐诗/poet.song.181000.json','["風顛雨橫田爲陂，沒頭禾穎靡孑遺。", "佃夫睨我謂我語，不德致此繄誰爲。", "肉食標吾稼螟蟘，舊章僭亂民蝥蠈。", "民不畏虎寧畏官，汝遑卹我輸官難。"]'),
('f593b43a-b869-4d69-a519-de863320153e','垂虹中秋','釋居簡','宋','宋诗','song-poetry','','[]','晚來林屋仙，鸞尾掃疎煙。',96,'全唐诗/poet.song.181000.json','["晚來林屋仙，鸞尾掃疎煙。", "未嘯騎鯨侶，先遮下瀨船。", "一規霜冏冏，萬頃玉漣漣。", "拈却明河詠，收還金薤篇。", "鐵檠烏足擬，石鼎弗須聯。", "等是春風手，清諧湘水絃。", "空書聊復爾，風御已泠然。", "傍睨休驚怪，吟中別有天。"]'),
('0e585a30-e393-41ed-803e-ae35a190c679','十六夜月','釋居簡','宋','宋诗','song-poetry','','[]','今宵較些子，猶自勝閑時。',120,'全唐诗/poet.song.181000.json','["今宵較些子，猶自勝閑時。", "圓缺有常守，陰晴無定期。", "伊人紛好惡，嫌鏡改妍媸。", "玉臼藥長在，霜蟾家不移。", "金波仍眩轉，掌露儘華滋。", "連璧何妨晚，修輪莫問遲。", "纔逢桂殿冷，便結庾樓知。", "十事九違意，浮生幾展眉。", "淵明十日菊，蘇子一聯詩。", "不是心如月，安知月不虧。"]'),
('6b3cf7b2-fd1e-46fa-9e4d-fed37e4b8141','送趙左司','釋居簡','宋','宋诗','song-poetry','','[]','故園風物望歸遲，趁得棖黄橘綠時。',64,'全唐诗/poet.song.181000.json','["故園風物望歸遲，趁得棖黄橘綠時。", "潮不失期惟自信，象非無膽愧頻移。", "素知天定齊榮辱，應有人嫌不詭隨。", "試問王家第七叔，群山何似蕺山奇。"]'),
('8aa1dd2f-1a08-40a0-8262-bfa93ae4c1da','趙憲使席上','釋居簡','宋','宋诗','song-poetry','','[]','鄉來踏雪旴水濱，雪雲貼水一樣清。',128,'全唐诗/poet.song.181000.json','["鄉來踏雪旴水濱，雪雲貼水一樣清。", "老玉堂仙在江上，玉色照耀梅花明。", "亦有過庭一雙玉，翠鸞矯矯停梧竹。", "乃翁事業在太史，天遺塤箎響相續。", "淛江以西秋雨餘，一道十九幾爲魚。", "懸金併日相喣濡，官憂輸賦私憂租。", "鮮明綉衣霄漢立，終日講明荒政急。", "只今人命在盆底，猶解倒懸端不啻。"]'),
('4e6dacea-ca4f-4801-b0d6-9526a485dad7','孤山石泉','釋居簡','宋','宋诗','song-poetry','','[]','改火煮泠泠，坡翁夢亦靈。',48,'全唐诗/poet.song.181000.json','["改火煮泠泠，坡翁夢亦靈。", "曉花雖滿鏡，夜影不移星。", "疏石供茶鼎，教誰續水經。", "每來頻鑑止，同渭不同涇。"]'),
('ce322ee3-7232-4cfd-ae7e-0f5c8c9e3878','送泉南趙帥機赴湖南之辟','釋居簡','宋','宋诗','song-poetry','','[]','潭北湘南路，迢迢幾許遥。',48,'全唐诗/poet.song.181000.json','["潭北湘南路，迢迢幾許遥。", "十連開帥幕，萬斛趁秋潮。", "地籟喧如市，天漿旨在瓢。", "典刑具前席，以次應佳招。"]'),
('ea22d7d6-f407-4de0-8973-3fce3077dd06','荆山劉成道語別','釋居簡','宋','宋诗','song-poetry','','[]','帆歸自淛西，又是海棠時。',48,'全唐诗/poet.song.181000.json','["帆歸自淛西，又是海棠時。", "多壘爲誰耻，六奇何處施。", "酒壺東向月，心事北征詩。", "長嘯萬松影，傍觀萬戶棋。"]'),
('c637b8c5-bcd3-4228-816b-75cfa5a9ea6a','謝懷安州王守','釋居簡','宋','宋诗','song-poetry','','[]','一寸長淮一寸金，金城千里障塵侵。',64,'全唐诗/poet.song.181000.json','["一寸長淮一寸金，金城千里障塵侵。", "犬羊未識元戎面，廊廟先知國士心。", "坐使春風生掌握，行孚大信控喉襟。", "夜嚴玉帳清如水，小復輕裘緩带吟。"]'),
('aeed9ebf-0381-464b-9ea9-f363ad88abe4','湖上送客','釋居簡','宋','宋诗','song-poetry','','[]','恰則春歸後，分携又一年。',48,'全唐诗/poet.song.181000.json','["恰則春歸後，分携又一年。", "絮生萍點點，藕泛葉田田。", "濃綠草如染，輕黄梅未傳。", "出關錢有禁，貰得百金船。"]'),
('25f33b7a-32b6-49e0-9c25-5af77bda0225','送朱監簿','釋居簡','宋','宋诗','song-poetry','','[]','纔解北歸驂，鋒車又指南。',48,'全唐诗/poet.song.181000.json','["纔解北歸驂，鋒車又指南。", "致身當重鎮，掩耳謝空譚。", "山歛層層䯰，江平曲曲藍。", "拈將桃柳恨，留與退之參。"]'),
('7ac3c8ed-39a1-455d-8f97-9782cedea03c','書米元暉寫蘇黄秦贈元章詩卷後','釋居簡','宋','宋诗','song-poetry','','[]','南宮逸蹟直欲飛，元祐諸老嘗品題。',128,'全唐诗/poet.song.181000.json','["南宮逸蹟直欲飛，元祐諸老嘗品題。", "新生之犢未易控，仲由未見孔子時。", "紹興天子紆宸思，詔寫前朝斷碑字。", "縝密中藏軒豁意，鄉黨篇中見孔子。", "坡仙滑稽肆吟謔，獨與黄秦細商畧。", "平原太守錐畫沙，柳家新樣元和脚。", "顔筋柳骨人不知，有子夜半親傳衣。", "換鵝風味超凡調，換羊更索坡仙笑。"]'),
('b3b3d66d-00c4-44d5-b026-9ba4674d0639','送徑山元書記歸池陽','釋居簡','宋','宋诗','song-poetry','','[]','又說池陽去，先尋弄水亭。',48,'全唐诗/poet.song.181000.json','["又說池陽去，先尋弄水亭。", "且藏雙眼碧，歸對九華青。", "栗稻霜纔穫，雲房夜莫扃。", "有來無逸駕，勒駕有山靈。"]'),
('9a493f1c-971f-4d81-8d3d-d1a7d56012f9','謝常州蔡提幹','釋居簡','宋','宋诗','song-poetry','','[]','蘭陵傳近信，喜似得鄉音。',48,'全唐诗/poet.song.181000.json','["蘭陵傳近信，喜似得鄉音。", "州篆六龍鼎，門標齊斗金。", "故人仍道北，逸興似山陰。", "綠繞簷前水，扁舟欲訪尋。"]'),
('1ee9208f-9677-46d8-8ff8-385581364ee8','郭教授自常州來得蔡提幹書','釋居簡','宋','宋诗','song-poetry','','[]','門丁通刺字，道是小汾陽。',48,'全唐诗/poet.song.181000.json','["門丁通刺字，道是小汾陽。", "宅相有梅屋，子衿森鴈行。", "蟾犀排麝馥，魚蠹避芸香。", "冷帳春風暖，何時話對床。"]'),
('b8457b80-dca1-4e2f-b75d-605abf44b251','問天慶觀奚高士病','釋居簡','宋','宋诗','song-poetry','','[]','蕙帳癯仙老，因仍病日侵。',48,'全唐诗/poet.song.181000.json','["蕙帳癯仙老，因仍病日侵。", "樓寬恰方丈，策瘦甫逾尋。", "谷響呼頻應，瓢虛捺不沈。", "百年渾得醉，不醉百年心。"]'),
('d54b9923-3900-4250-810a-b5852d1e51b6','泊万俟子紹書院','釋居簡','宋','宋诗','song-poetry','','[]','舍櫂吳松曲，來尋獨冷盟。',48,'全唐诗/poet.song.181000.json','["舍櫂吳松曲，來尋獨冷盟。", "誤聽對床雨，喚作打篷聲。", "漏緩更籌滴，春從水驛生。", "曉雲驅宿翳，我欲趁新晴。"]'),
('dea56be8-1b17-42e0-8889-e3e40f69f08b','風泊淀山','釋居簡','宋','宋诗','song-poetry','','[]','船壓濤山碎，風顛玉雪零。',48,'全唐诗/poet.song.181000.json','["船壓濤山碎，風顛玉雪零。", "未瞻孤塔影，先乞小姑靈。", "汗漫開天險，聰明在德馨。", "丘之禱久矣，爾自扣心扃。"]'),
('8930b12c-7676-4556-92d8-c5a65b15fb83','淀山寺在湖中','釋居簡','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','千港亂流歸，天沈影弗畦。',48,'全唐诗/poet.song.181000.json','["千港亂流歸，天沈影弗畦。", "遠疑浮玉小，高步落星低。", "舊日觀潮雪，新來罷水犀。", "闌干憑月午，一眼碧玻璃。"]'),
('bceddb71-ed66-47b3-aa9d-03b1a532be82','別孫都倉','釋居簡','宋','宋诗','song-poetry','','[]','節制作鹹利，悠然見設施。',48,'全唐诗/poet.song.181000.json','["節制作鹹利，悠然見設施。", "工夫雖自小，鼎鼐却相宜。", "盟鷺鷗同適，及瓜梅未知。", "有書聞季父，爲致別時思。"]'),
('c8c28e24-60a3-405c-861c-4bfd2553c472','如隠索賦雙梧','釋居簡','宋','宋诗','song-poetry','','[]','朝陽盤錯地，分植在庭墀。',48,'全唐诗/poet.song.181000.json','["朝陽盤錯地，分植在庭墀。", "百尺凜雙操，九包來幾時。", "孫枝雲雨上，星履典刑垂。", "莫遣鶢鶋類，頻來振羽儀。"]'),
('cc264dd3-5356-4fa8-b9b3-e136434c2a9d','過周驤甫勉其教子  其一','釋居簡','宋','宋诗','song-poetry','','[]','勿謂幽居弗自怡，見成湖泖作盆池。',32,'全唐诗/poet.song.181000.json','["勿謂幽居弗自怡，見成湖泖作盆池。", "淀山只在虛簷下，又當山蕉與水梔。"]'),
('6ec44c69-1cd9-4231-9b0f-a20d5cc14f25','過周驤甫勉其教子  其二','釋居簡','宋','宋诗','song-poetry','','[]','勤儉工夫自足娛，又將餘暇課兒書。',32,'全唐诗/poet.song.181000.json','["勤儉工夫自足娛，又將餘暇課兒書。", "盍先撙節儲脩脯，莫放春風冷帳虛。"]'),
('e2faec0b-b4f3-4d88-9998-4ee55a5cd157','響山閣','釋居簡','宋','宋诗','song-poetry','','[]','有耳誣牆壁，無聲謗瑟琴。',48,'全唐诗/poet.song.181000.json','["有耳誣牆壁，無聲謗瑟琴。", "一機纔破敵，何處弗知音。", "澹墨微茫古，哀絲夭閼沈。", "天風號萬籟，終始不曾瘖。"]'),
('10d02842-9163-4bf8-a5b1-9037a1876e90','過泖','釋居簡','宋','宋诗','song-poetry','','[]','問骨水驛夜迢迢，泖闊風微水不摇。',32,'全唐诗/poet.song.181000.json','["問骨水驛夜迢迢，泖闊風微水不摇。", "船似井蓮花葉小，不禁吹鬢冷蕭蕭。"]'),
('3a25edcf-874d-48f5-85b2-50df44b8454e','致爽梅移自崔中書後圃秋種冬花','釋居簡','宋','宋诗','song-poetry','','[]','根從鼎實振華風，春自岧嶤直禁中。',64,'全唐诗/poet.song.181000.json','["根從鼎實振華風，春自岧嶤直禁中。", "與紫薇花分殿最，带黄昏月尚朦朧。", "玉堂踏雪司空慣，金谷從他白首同。", "遥想樹梅如樹德，小酬冰質洞玲瓏。"]'),
('f9e0e277-d947-46b7-93b3-a1d3f9b31d18','觀物初瓶梅予析爲二其一奇而不怪其一怪而不奇  其一','釋居簡','宋','宋诗','song-poetry','','[]','的皪同枝獨擅奇，沖和分寸偶相違。',32,'全唐诗/poet.song.181000.json','["的皪同枝獨擅奇，沖和分寸偶相違。", "不尋別調酬清婉，橫玉聲中怨孰歸。"]'),
('bd6ea3b5-1ce1-4ed9-bcf4-f3d5ca0ce987','觀物初瓶梅予析爲二其一奇而不怪其一怪而不奇  其二','釋居簡','宋','宋诗','song-poetry','','[]','鶴膝歧分把瘦枝，節拳支局老支離。',32,'全唐诗/poet.song.181000.json','["鶴膝歧分把瘦枝，節拳支局老支離。", "解嘲不入時宜處，只合儀刑月蝕詩。"]'),
('52f13d06-f28a-458e-9fec-c7a52e996e46','湖上曉晴','釋居簡','宋','宋诗','song-poetry','','[]','彤霞煖照碧玻璃，一點蜚光欲墮遲。',32,'全唐诗/poet.song.181000.json','["彤霞煖照碧玻璃，一點蜚光欲墮遲。", "恰似峨眉山半麓，紫兜羅霧布巖時。"]'),
('f8cf5a78-1086-4a2d-92e7-141b54fbad44','寄唐察院','釋居簡','宋','宋诗','song-poetry','','[]','他日臺綱整頓難，獨觀風旨弗他觀。',64,'全唐诗/poet.song.181000.json','["他日臺綱整頓難，獨觀風旨弗他觀。", "脩名夙振鴛鸞序，元服絻加獬豸冠。", "已肆濁流隄衮衮，更教華月振團團。", "都人快覩青驄馬，不作從前款段看。"]'),
('9285865f-0f4b-41e1-abb8-17fce3a059bc','淵明畫像','釋居簡','宋','宋诗','song-poetry','','[]','司馬家兒曆數窮，可能特地振孤蹤。',32,'全唐诗/poet.song.181000.json','["司馬家兒曆數窮，可能特地振孤蹤。", "永懷東土清風遠，不把元嘉紀歲終。"]'),
('6b3ac3d4-82bf-4801-a0d2-1918bc4b1011','龔料院挽章','釋居簡','宋','宋诗','song-poetry','','[]','滌噐笑相如，呼兒誦子虛。',48,'全唐诗/poet.song.181000.json','["滌噐笑相如，呼兒誦子虛。", "諸公方薦鶚，仙舄已騎魚。", "臨餗俄翻鼎，儲林未結廬。", "只成幾望月，無路問蟾蜍。"]'),
('cc0d6abc-b76c-4ca5-ae73-606b0bcf0ab6','錢知府葵窗挽章','釋居簡','宋','宋诗','song-poetry','','[]','仁者胡爲勇，全師不足加。',48,'全唐诗/poet.song.181000.json','["仁者胡爲勇，全師不足加。", "一身百夫禦，三世四王家。", "脩竹老彌動，甘棠春自花。", "白華詩欲補，有子振光華。"]'),
('a9264fe0-fc32-4efd-8b38-5333b974bfd1','謁趙倉使二十一韻','釋居簡','宋','宋诗','song-poetry','','[]','昔分淮東天，河海幸潜濟。',252,'全唐诗/poet.song.181000.json','["昔分淮東天，河海幸潜濟。", "悠悠不知遠，僅一衣带水。", "今茲一道惠，列城洞明偉。", "可望不可及，弱水三萬里。", "山林日深窅，踸踔坎井底。", "勇聞譽盛德，半屬天下士。", "古調振騷雅，時樣列駢儷。", "苦語雜頌詠，惡石必先耆。", "在御必驍騰，在治必精美。", "謹於千慮失，詎忍一得棄。", "谽呀浩如海，就下拓涯涘。", "朝夕不知了，莫測方寸地。", "老我不足爲，把茅冷雲際。", "樓欠元龍卧，門尋子雲倚。", "小振伽梨肩，載整蒙茸刺。", "高視藐豪放，細意問奇字。", "倚門勿麾之，我欲見君子。", "况夫君子鄉，疇曩屢游止。", "蓋代品題手，聲光動天地。", "公乎皆雋髦，願聽星辰履。", "大雅儻可作，鄭衛頼一洗。"]'),
('3f333046-ae3f-4cf4-983d-1c1dcee292f6','舟中絮','釋居簡','宋','宋诗','song-poetry','','[]','弱弄輕陰却又前，析雲洴霧不成綿。',32,'全唐诗/poet.song.181000.json','["弱弄輕陰却又前，析雲洴霧不成綿。", "籧篨破處隨風入，驀地因風又出船。"]'),
('ce6e2c17-35ee-493b-9779-9b71a9e45bb4','陶窗','釋居簡','宋','宋诗','song-poetry','','[]','如在羲皇上，都忘我是誰。',48,'全唐诗/poet.song.181000.json','["如在羲皇上，都忘我是誰。", "聞鍾還入寺，無酒却攢眉。", "籬落西風晚，琴書白晝遲。", "千年續遺響，側枕答凉颸。"]'),
('2aa5e681-d499-4716-85d3-3567b436ca42','羌村圖','釋居簡','宋','宋诗','song-poetry','','[]','河朔塵昏孰解紛，零丁獨走不忘君。',32,'全唐诗/poet.song.181000.json','["河朔塵昏孰解紛，零丁獨走不忘君。", "麻鞋見了重瞳子，還憶江東日暮雲。"]'),
('b749e2b5-735c-4204-87d8-cc363bf99873','書先天秀鴈圖','釋居簡','宋','宋诗','song-poetry','','[]','舊隨燕燕擅周詩，海北天南却背馳。',32,'全唐诗/poet.song.181000.json','["舊隨燕燕擅周詩，海北天南却背馳。", "惆悵同經弗同里，好懷長似燕差池。"]'),
('574fedaf-cbac-4f2b-9510-a9e0ea740041','雲錦','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十丈花如織，酣酣拓具區。',144,'全唐诗/poet.song.181000.json','["十丈花如織，酣酣拓具區。", "新於機上落，勻似鏡中鋪。", "容與翠綃幌，渥丹鉛粉膚。", "越溪霞湛染，楚夢玉敷腴。", "隋棹新帆遠，吳宮小隊殊。", "綠欹檠雨蓋，碧間褭風蒲。", "勺月清秋冷，生凉暑晝蘇。", "天孫旌浦溆，水帝展屠蘇。", "紅白香無別，明光影可𣂏。", "蛻塵古君子，具體小西湖。", "彷象雖曾賦，形容似按圖。", "奚囊如可製，闊剪貯陶珠。"]'),
('710dfdcb-c11f-4b1b-a3cc-f7e31f414894','石罅水僊','釋居簡','宋','宋诗','song-poetry','','[]','緇雲淺拂襯中單，蘇石蒙茸伴月寒。',32,'全唐诗/poet.song.181000.json','["緇雲淺拂襯中單，蘇石蒙茸伴月寒。", "欲與南枝分伯仲，爲兄恐自季方難。"]'),
('d60ec40f-3bb4-4ec0-8086-1d159aedcf31','石罅蘭竹','釋居簡','宋','宋诗','song-poetry','','[]','篠叢疎薄總虛心，傾國香葩闖石陰。',32,'全唐诗/poet.song.181000.json','["篠叢疎薄總虛心，傾國香葩闖石陰。", "不是阿清幽思苦，屬誰洴墨寫蕭森。"]'),
('c870fc2e-2939-4d8e-8da8-900ee104a898','酬方司法一首','釋居簡','宋','宋诗','song-poetry','','[]','五字堪呈佛，投珍頗惜哉。',48,'全唐诗/poet.song.181000.json','["五字堪呈佛，投珍頗惜哉。", "湯湯大雅後，衮衮建安來。", "逸思屬萬象，空庭步幾回。", "海陵藕花幕，已爲故人開。"]'),
('e8477cf5-a1d2-4a2e-bea8-913b628ab8ff','劉改之葬崑山山寺下邑人不知葬處  其一','釋居簡','宋','宋诗','song-poetry','','[]','凌煙不著老風騷，劍沕深雲鐵未消。',32,'全唐诗/poet.song.181000.json','["凌煙不著老風騷，劍沕深雲鐵未消。", "獨欠張華眸子碧，寒芒千丈夜迢迢。"]'),
('5ed02bd7-e197-4528-a21a-69e2a9608dc8','劉改之葬崑山山寺下邑人不知葬處  其二','釋居簡','宋','宋诗','song-poetry','','[]','酒酹墳頭土易乾，何如黄鶴斷磯船。',32,'全唐诗/poet.song.181000.json','["酒酹墳頭土易乾，何如黄鶴斷磯船。", "會看潮雪莆萄綠，喚起長鯨快吸川。"]'),
('8f4f17f4-748b-48cf-bed0-0ccf68c6caf6','書嚮禪師開山石壁','釋居簡','宋','宋诗','song-poetry','','[]','虎馴石上倚藤枝，細把興亡問嚮師。',35,'全唐诗/poet.song.181000.json','["虎馴石上倚藤枝，細把興亡問嚮師。", "千柱已隨煙焰{火烕}，何如表剎未開時。"]'),
('53fe1723-daf9-4c89-af10-b73ae17666e0','雨後','釋居簡','宋','宋诗','song-poetry','','[]','老火無蹤鴈有聲，雨絻戰伯八紘清。',32,'全唐诗/poet.song.181000.json','["老火無蹤鴈有聲，雨絻戰伯八紘清。", "西風帆落崑山曉，隠隠青岑玉色明。"]'),
('5b5ea752-c3e2-4044-919a-15f73d520868','中秋月','釋居簡','宋','宋诗','song-poetry','','[]','月是尋常月，云胡迥鮮潔。',120,'全唐诗/poet.song.181000.json','["月是尋常月，云胡迥鮮潔。", "老火日就灺，盡掃群陰屑。", "三萬頃天秋作底，連天灝氣清如水。", "金波炫轉光流澌，團團曷若初學眉。", "玉虹跨水腰百圍，翩然飛佩湖雲低。", "尺箠緩把單于笞，且復鞭虹隨月飛。", "月中先枝少年日，老蟾老兔曾相識。", "鏡裏功名兩鬢青，却碾冰輪洞八紘。"]'),
('5688aa0c-a5f7-4073-991b-1a40648159a6','送王侍郎改除二首  其一','釋居簡','宋','宋诗','song-poetry','','[]','闔閭春秋城，風煙俟時振。',144,'全唐诗/poet.song.181000.json','["闔閭春秋城，風煙俟時振。", "乾坤不改色，民物見天定。", "因仍古道漓，靡然隨俗移。", "中流屹頹瀾，萬派皆東之。", "沈機靜弗譁，澄湛物斯格。", "和煦生點點，陽春蘇頟頟。", "翩翩不容駐，宣化思盟主。", "問之何因爾，去留有常數。", "真宰知何心，惜閑如惜金。", "天慳不容破，破不爲佞壬。", "我知真宰心，暫適滄洲趣。", "恐此復偶然，還須濟川具。"]'),
('f70fc8a6-ee21-446d-be2e-6535225d7cd4','送王侍郎改除二首  其二','釋居簡','宋','宋诗','song-poetry','','[]','泉石豈不好，老我泉石心。',180,'全唐诗/poet.song.181000.json','["泉石豈不好，老我泉石心。", "可無鷦鷯枝，來傍威鳳林。", "鳳兮千仞翔，覽德斯下臨。", "青冥叢玉霄，洞視潜伏深。", "槍榆六月息，共聽朝陽吟。", "梧桐生朝陽，老榦垂層陰。", "夕靄聯晨霏，凉入薰風琴。", "扣弦借清商，千里秋沈沈。", "鄉來嘲哳聲，不復沸釜鬵。", "卷舌絕音響，泯默如病瘖。", "采羽仍嚶嚶，善類還愔愔。", "醴泉與竹實，報效杳莫尋。", "且復事頌禱，聳德齊巍岑。", "詞藻苦羞澀，戛擊非球琳。", "佇爲王者瑞，九成儀韶音。"]'),
('ed79738b-fa6c-4819-88c6-e056404e74a6','華亭明行院','釋居簡','宋','宋诗','song-poetry','','[]','三女岡邊寺，樓臺舊鬰峩。',48,'全唐诗/poet.song.181000.json','["三女岡邊寺，樓臺舊鬰峩。", "近郊聞梵放，陸地出芬陁。", "天福雖營剎，中原尚枕戈。", "煙塵絕淮海，熨帖看鯨波。"]'),
('8e423e78-b6c8-4f18-a2af-417976fed551','禱雨龍祠','釋居簡','宋','宋诗','song-poetry','','[]','魃奚爲旱虐，亟問海嵎龍。',48,'全唐诗/poet.song.181000.json','["魃奚爲旱虐，亟問海嵎龍。", "山吐四更月，樓敲三疊鐘。", "天應憐獨苦，年亦豈終凶。", "霹靂轟平地，霶然足四封。"]'),
('e748ec3f-d231-4f29-9033-0d68f382f2b5','熱甚','釋居簡','宋','宋诗','song-poetry','','[]','四壁除遮障，炎風似熾爐。',48,'全唐诗/poet.song.181000.json','["四壁除遮障，炎風似熾爐。", "汗隨停扇滴，氣逐漱冰蘇。", "銷暑露寒殿，歸仁扇暍圖。", "一盃槐葉冷，誰致錦屠蘇。"]'),
('385b7ce9-91b9-4a63-80d1-32f85bf5cd82','賀湖州太守劉右司','釋居簡','宋','宋诗','song-poetry','','[]','輔郡殊非列郡同，樓居闊著水晶宮。',64,'全唐诗/poet.song.181000.json','["輔郡殊非列郡同，樓居闊著水晶宮。", "膽嘗故壘煙塵外，心在清流湛染中。", "看不足山歸賦詠，發無餘藴到鴻濛。", "華陽壁記多名輩，先爲蘇家述長公。"]'),
('cf9fcfcf-e946-4de3-bf16-265e42bc68ea','送陳時齋赴湖北憲辟','釋居簡','宋','宋诗','song-poetry','','[]','曷與元龍別，河梁五字詩。',48,'全唐诗/poet.song.181000.json','["曷與元龍別，河梁五字詩。", "多君堅素守，交臂得深知。", "憶過鴈回處，料當梅放時。", "驛馳行卷外，更寄向南枝。"]'),
('038cf163-b227-4eb8-a02b-fb27e48d1a64','倫間雲偕時齋行','釋居簡','宋','宋诗','song-poetry','','[]','諾重黄金俗，倫名與布齊。',48,'全唐诗/poet.song.181000.json','["諾重黄金俗，倫名與布齊。", "不情山可改，定見水難西。", "七澤雲生硯，千江月透犀。", "寄聲種桃者，且在武陵溪。"]'),
('4d6040ee-743d-48c2-9563-b2cf75b01b4c','趙大卿歸自四明','釋居簡','宋','宋诗','song-poetry','','[]','玉輪碾秋旻，一印印百川。',120,'全唐诗/poet.song.181000.json','["玉輪碾秋旻，一印印百川。", "分光落涇渭，湛染尤澄鮮。", "素魄當清流，似喜清流賢。", "冰澌鑑伊洛，支脈逮澗瀍。", "悠悠涵萬象，冏冏洞九淵。", "可照濁水源，豈異投漪漣。", "涇也自由渾，月也虧仍圜。", "各不改故常，亦復無黨偏。", "不知夫如何，竟爲渾者獧。", "天高杳難問，此理何時宣。"]'),
('8e7805f8-d72b-4d61-b6de-226ec5975826','中秋無月寄吳侍郎','釋居簡','宋','宋诗','song-poetry','','[]','鏖殘老火豁瑶空，誰遣雲生桂殿東。',64,'全唐诗/poet.song.181000.json','["鏖殘老火豁瑶空，誰遣雲生桂殿東。", "未必清明如五馬，故令霶霔洗垂虹。", "凉燈薦喜占晨霽，渴稼懷新樂歲豐。", "遥想半輪秋未老，朣朣襟袖振華風。"]'),
('49d53425-7700-4d23-99d5-ecc9094fe4d1','送王常熟左藏二首  其一','釋居簡','宋','宋诗','song-poetry','','[]','常熟端平政，難於子産初。',48,'全唐诗/poet.song.181000.json','["常熟端平政，難於子産初。", "有田皆可井，無港不容流。", "龍斷家安業，閭閻夜讀書。", "山謠出林疃，處處樂樵漁。"]'),
('ea8a66d5-eaa8-4833-ad9a-e7d4155f87fe','送王常熟左藏二首  其二','釋居簡','宋','宋诗','song-poetry','','[]','志士殊超俗，平常不作奇。',48,'全唐诗/poet.song.181000.json','["志士殊超俗，平常不作奇。", "到官如去日，歸橐似來時。", "尚友皆名世，沿流逮武夷。", "由來清操別，端的畏人知。"]'),
('ef8a90c5-aae8-4ba5-919e-9b9bc5ac30fa','送趙知丞','釋居簡','宋','宋诗','song-poetry','','[]','或謂公當去，人誰不喟然。',48,'全唐诗/poet.song.181000.json','["或謂公當去，人誰不喟然。", "獨清非衒俗，衆醜自憎妍。", "華月終能滿，蒼蠅弗足扇。", "滔滔五絃水，千里共芳鮮。"]'),
('e6624ee4-4999-44bd-a3dd-9701cdd1a25b','善權修造訖事','釋居簡','宋','宋诗','song-poetry','','[]','林表煥丹碧，化出一段奇。',252,'全唐诗/poet.song.181000.json','["林表煥丹碧，化出一段奇。", "鄉者未始見，今也其誰爲。", "金錫來自閩，萍跡纔止茲。", "跨門懷往昔，視篆恢宏規。", "所立志先定，志定山弗移。", "苦心忘艱勤，佇思常委蛇。", "複道行半天，雲影低四垂。", "叢玉坐上天，白花水中坻。", "兩忘深且高，旁列崇與卑。", "天人既交際，物我咸熙怡。", "殿以舍空王，空王顰兩眉。", "長恐屋打頭，東拄西防墮。", "稜層加峭峙，柱礎奠仄欹。", "彫零古象設，一一皆新之。", "瑣屑與滅裂，整頓靡孑遺。", "凄凉佛前燈，蘭膏添滿而。", "明光號無盡，安知無盡時。", "咨爾北山密，爾吾無學兒。", "曷如然此燈，千花開不萎。", "鬰密暝雲蔽，浩蕩剛風吹。", "剛風吹不滅，相配天陽熙。"]'),
('579cb7b3-5f21-474a-ac81-99c000de6fa0','寄趙左司可齋','釋居簡','宋','宋诗','song-poetry','','[]','橙露薦華滋，江干記語離。',48,'全唐诗/poet.song.181000.json','["橙露薦華滋，江干記語離。", "斷虹收雨後，風馬駕潮時。", "夢喜登門婁，書慙去翼遲。", "橙今還可剪，浩蕩鄉來思。"]'),
('bd7d7a1b-a948-4153-bf82-74a6fdb98a23','讀曹侍郎去國表','釋居簡','宋','宋诗','song-poetry','','[]','立螭持橐孰非榮，未若江頭一葦輕。',64,'全唐诗/poet.song.181000.json','["立螭持橐孰非榮，未若江頭一葦輕。", "失侶鴛鴻空悵望，喜歸鷗鷺亟將迎。", "雍容譚笑不但已，去就始終如此明。", "疏似南陽出師表，盡傾肝鬲寫生平。"]'),
('ce52cfb5-3089-4526-a554-c7d7e66db761','寄江東運使唐察院','釋居簡','宋','宋诗','song-poetry','','[]','勳業可曾看曉鏡，垂虹回首鑑澄波。',64,'全唐诗/poet.song.181000.json','["勳業可曾看曉鏡，垂虹回首鑑澄波。", "明鮮叵惜隨時染，瞑眩其如變證何。", "舌在未忘輸諤諤，邊儲聊復辦多多。", "驕嘶只識瑶池路，仗下如何噤得他。"]'),
('11419b73-0ff5-45e5-b9a1-af40fb357310','强齋高秘閣過訪二子侍','釋居簡','宋','宋诗','song-poetry','','[]','囊粟排金破黑甜，曉來乾鵲響晴簷。',64,'全唐诗/poet.song.181000.json','["囊粟排金破黑甜，曉來乾鵲響晴簷。", "西游佳氣作秋爽，東聚列星應夜占。", "雙玉佩聲隨步武，老人躔度動沈潜。", "豈惟蕭寺生晶色，白叟黄童亦快瞻。"]'),
('5bd27bd9-554e-4e8a-9aed-b1e9e93f9eb5','破山夜集','釋居簡','宋','宋诗','song-poetry','','[]','出戶天疑雪，幡然雨滴簷。',48,'全唐诗/poet.song.181000.json','["出戶天疑雪，幡然雨滴簷。", "未飛盈尺霰，先失半規蟾。", "寫壁催更盡，銜枚戒夜嚴。", "却須重刻燭，橐粟剪纖纖。"]'),
('91b52e2a-3dcd-4732-8431-7a5426da831c','次丘監丞破山夜集并纖字韻  其一','釋居簡','宋','宋诗','song-poetry','','[]','領客能官樣，鴛鴻戢翼隨。',48,'全唐诗/poet.song.181000.json','["領客能官樣，鴛鴻戢翼隨。", "題無流處葉，續有醉時詩。", "聽雨思歸者，尋梅且已之。", "小池疏積淤，何必賦盆池。"]'),
('d1a91d6e-ffc8-4cd0-a896-46fcd3b92d96','次丘監丞破山夜集并纖字韻  其二','釋居簡','宋','宋诗','song-poetry','','[]','擬把南枝雪，簪坡醉帽簷。',48,'全唐诗/poet.song.181000.json','["擬把南枝雪，簪坡醉帽簷。", "袖春如有脚，鑑冰影無蟾。", "采筆吟方勇，長城令更嚴。", "僧房雖冷落，簡古發穠纖。"]'),
('1d3174fb-41e4-48be-b4e4-3dd5e331563a','萬竹陳兄伯仲相過','釋居簡','宋','宋诗','song-poetry','','[]','伯塤曾奏雅，仲氏又同參。',48,'全唐诗/poet.song.181000.json','["伯塤曾奏雅，仲氏又同參。", "眼白難爲俗，衫青定出藍。", "綴蟲燈剪婁，談麈鼎分三。", "寂寞空山曙，無從駐兩驂。"]'),
('e9355100-746b-45b5-9daf-e1265c1987d6','送王梁山','釋居簡','宋','宋诗','song-poetry','','[]','置書學劍漫遊畋，百萬樗蒱一擲先。',64,'全唐诗/poet.song.181000.json','["置書學劍漫遊畋，百萬樗蒱一擲先。", "結客締交南蕩寺，買花載酒後湖船。", "三邊百險常單騎，五馬雙旌未十年。", "莫作楊州貴人樣，兜牟更解出貂蟬。"]'),
('0d30ab3e-7c35-4051-b9fe-c57bd500728b','謝喬丞相','釋居簡','宋','宋诗','song-poetry','','[]','神樞卓絕當環中，物物虛應無終窮。',128,'全唐诗/poet.song.181000.json','["神樞卓絕當環中，物物虛應無終窮。", "華風一點妙埏埴，精神千里看折衝。", "判然經濟歸詳鍊，有若星光繞檀篆。", "崎嶇詰曲到無餘，冷地靜分千緒亂。", "空山觸蠻亦云慘，山鬼陸梁僧䫲頷。", "施及無求益見真，惠當適用偏多感。", "千古拓提成再造，百粉直慙酬不了。", "垣傍紫微何處祝，道場山頂何山麓。"]'),
('adbf7303-b22b-47db-a591-109cda071c8d','題丘使君竹坡','釋居簡','宋','宋诗','song-poetry','','[]','人間苦炎熱，君家窗戶凉。',240,'全唐诗/poet.song.181000.json','["人間苦炎熱，君家窗戶凉。", "人間苦埃壒，君家如瀟湘。", "入門洞真趣，繞戶皆篔簹。", "華月篩碎金，鮮風戛叢琅。", "初疑低地碧，忽觀拂雲長。", "不倚見特立，側挺終弗僵。", "弗延醉名流，只著雛鳳凰。", "奇草時自芬，幽蘭時自芳。", "歌鳥時自新，風玉時自鏘。", "枯榆與老柳，莫蔓夫子牆。", "牆固不在高，賜也不足方。", "市聲辟三舍，苔痕寬一方。", "衡斜露頭角，扶疎嚴奧堂。", "凉薰入冰弦，古軫橫石床。", "悠然於此時，物我各兩忘。", "孰辨桀與跖，更說羲與皇。", "無人不種花，長恐負艷陽。", "我則異於是，無復相較量。", "藏春在懷袖，不使蜂蝶狂。", "願結虛心友，晚節同蒼蒼。"]'),
('7a875df8-a3d8-4489-aaa4-bc73e6b371a0','宿化度','釋居簡','宋','宋诗','song-poetry','','[]','烈日燉雲僦一單，曲肱聊復謝輕紈。',32,'全唐诗/poet.song.181000.json','["烈日燉雲僦一單，曲肱聊復謝輕紈。", "夢回不復疑蝴蝶，疑是蟾枝宿廣寒。"]'),
('adf168ea-f6b2-49b5-ad80-d3fd256f917f','宿天目山西浄行寺','釋居簡','宋','宋诗','song-poetry','','[]','有水有石又有竹，竹裏僧窗皆面山。',32,'全唐诗/poet.song.181000.json','["有水有石又有竹，竹裏僧窗皆面山。", "沆瀣弗勝和玉屑，可能來隠碧孱顔。"]'),
('f6d7b113-7ec3-4b77-a53e-98028bbe4005','送吳侍郎婺州之官','釋居簡','宋','宋诗','song-poetry','','[]','坤維日望虜塵消，鴛序坤珍壓大僚。',64,'全唐诗/poet.song.181000.json','["坤維日望虜塵消，鴛序坤珍壓大僚。", "持橐愛兄同法從，牧羊友弟並僊鑣。", "清流未漲雙溪碧，浮俗先傳五袴謠。", "八詠斷弦如可續，爲君折葦度秋潮。"]'),
('8da12d78-486b-476b-bed6-8b01c8706127','送吳尚書溫州之官','釋居簡','宋','宋诗','song-poetry','','[]','纔指金華餞阿連，永嘉迓吏復聯翩。',64,'全唐诗/poet.song.181000.json','["纔指金華餞阿連，永嘉迓吏復聯翩。", "東藩等是二千石，此樂已無三百年。", "學士即真尤鮮儷，使君獨立恐難先。", "懶雲倘借鮮風便，容與東西刺史天。"]'),
('6cbe7446-0618-4a22-9a22-0509c11c02ce','禮韶國師塔','釋居簡','宋','宋诗','song-poetry','','[]','不到通玄頂，如何見國師。',48,'全唐诗/poet.song.181000.json','["不到通玄頂，如何見國師。", "了無心外法，喪却目前機。", "法眼那知此，天台復讖誰。", "三峰高岌岌，孤塔更巍巍。"]'),
('3643a1ff-d31e-4383-a560-dcf32edd5452','禮此菴塔','釋居簡','宋','宋诗','song-poetry','','[]','痛遭圓悟手，悔上毒龍岡。',48,'全唐诗/poet.song.181000.json','["痛遭圓悟手，悔上毒龍岡。", "義斷生難續，冤深死弗忘。", "出言非動口，驗賊不須贓。", "火後紅蓮舌，堂堂現廣長。"]'),
('5d26fc7e-1172-44a1-9a5e-d1474f366ecc','禮真歇了菩薩塔','釋居簡','宋','宋诗','song-poetry','','[]','洞上芙蓉老，殘花發舊枝。',48,'全唐诗/poet.song.181000.json','["洞上芙蓉老，殘花發舊枝。", "話行三十載，瑞應半千期。", "一掌空凡聖，羣靈入範圍。", "老胡如不會，却許老胡知。"]'),
('4317d24a-8520-48c9-839f-5cd7d052f5c7','禮光狀元塔','釋居簡','宋','宋诗','song-poetry','','[]','江湖行脚後，洋嶼喫拳初。',48,'全唐诗/poet.song.181000.json','["江湖行脚後，洋嶼喫拳初。", "死路從頭活，生涯盡底除。", "纖毫無著實，萬口錯傳虛。", "金鎖今猶暖，同心媿瞎馿。"]'),
('d16fae5b-077f-435c-b559-d6bddedd5516','禮應庵塔','釋居簡','宋','宋诗','song-poetry','','[]','直指心成曲，單傳蔓更滋。',48,'全唐诗/poet.song.181000.json','["直指心成曲，單傳蔓更滋。", "全身入荒草，赤膊上東司。", "一向攻人短，多方徇己私。", "楊歧五世後，作者不如斯。"]'),
('cef057f8-18de-45bf-afff-e3f98694404d','禮別峰塔','釋居簡','宋','宋诗','song-poetry','','[]','濟北參天樹，何時此活埋。',48,'全唐诗/poet.song.181000.json','["濟北參天樹，何時此活埋。", "人天知敬畏，佛祖憚擠排。", "父祖萬人傑，兒孫一樣乖。", "𣰦毶穿布衲，誰復裹芒鞵。"]'),
('944c02b9-988d-4014-894a-810d73ec31bd','禮密庵塔','釋居簡','宋','宋诗','song-poetry','','[]','監本白拈賊，行家福建僧。',48,'全唐诗/poet.song.181000.json','["監本白拈賊，行家福建僧。", "分甘行異類，名不挂傳燈。", "一句定宗旨，通身是葛藤。", "葛藤樁倒也，此道復中興。"]'),
('c6dad9bd-be60-4ef3-8c94-56a3521ac2a2','禮尼總持塔','釋居簡','宋','宋诗','song-poetry','','[]','誦蓮華品謗斯經，業識芬陀舌上生。',32,'全唐诗/poet.song.181000.json','["誦蓮華品謗斯經，業識芬陀舌上生。", "舊日阿閦如再見，定應無此惡名聲。"]'),
('60e80e3d-aec1-4353-8728-674603b530eb','擬寒山送明達二侍者歸蜀','釋居簡','宋','宋诗','song-poetry','','[]','不住有佛處，不住無佛處。',96,'全唐诗/poet.song.181000.json','["不住有佛處，不住無佛處。", "萬里一條鐵，孤鸞無伴侶。", "無處不蹉過，有處還却步。", "挂角少羚羊，枯樁多死兔。", "達也二十九，興盡復回首。", "簡也四十餘，寸長竟何有。", "人皆笑我愚，我愚學未就。", "撲碎古菱花，孰與分妍醜。"]'),
('d6da451c-50c7-45a9-9684-0f4d157ccfcd','擬寒山送洪州因上人省母','釋居簡','宋','宋诗','song-poetry','','[]','爲法來尋訪，病眼翳花發。',48,'全唐诗/poet.song.181000.json','["爲法來尋訪，病眼翳花發。", "爲母復歸去，特地重添屑。", "父母所生口，終不爲汝說。", "問之何因爾，吾嘗於此切。"]'),
('6fff52a6-0630-4c88-a87b-badb385d079d','擬寒山送吉州壽侍者奔父母喪','釋居簡','宋','宋诗','song-poetry','','[]','家書報平安，父母沒荒草。',48,'全唐诗/poet.song.181000.json','["家書報平安，父母沒荒草。", "回首寂無覩，閉眼長相照。", "合笑不合哭，曠情遠相吊。", "雖云朴實頭，掠虛尤不少。"]'),
('c8764b08-9db2-4b7d-a6b9-b1ac9f658b31','送遂寧海泉州權二友  其一','釋居簡','宋','宋诗','song-poetry','','[]','狐涎纔點著，病已在膏肓。',48,'全唐诗/poet.song.181000.json','["狐涎纔點著，病已在膏肓。", "跳入野狐隊，聊施起死方。", "瞥然馿性發，護短不從長。", "無地容棲泊，全身在帝鄉。"]'),
('27a85f56-b766-44da-a96f-b71f6e6ddca4','送遂寧海泉州權二友  其二','釋居簡','宋','宋诗','song-poetry','','[]','權也名家駒，遇我以父執。',48,'全唐诗/poet.song.181000.json','["權也名家駒，遇我以父執。", "謂可張吾軍，咄咄反見逼。", "慣以劣閗勝，况乃緩縛急。", "福建與漳泉，佗州終不及。"]'),
('2db97b6b-2184-4f6c-a4e0-ab81028444b9','送復書狀歸溫州','釋居簡','宋','宋诗','song-poetry','','[]','玉几兩年餘，詠歸何草草。',48,'全唐诗/poet.song.181000.json','["玉几兩年餘，詠歸何草草。", "曹谿一宿覺，知幾良不早。", "一人不解禪，一人不解道。", "全主復全賓，扶起仍扶倒。"]'),
('9374bf7e-65a0-405b-b432-257c09383c60','送祖柏庭知客歸鄉','釋居簡','宋','宋诗','song-poetry','','[]','十載區區探海藏，懷藏如意來尋訪。',72,'全唐诗/poet.song.181000.json','["十載區區探海藏，懷藏如意來尋訪。", "直造凌霄峰頂上。", "逢大匠，一鎚擊碎真佳賞。", "活計從茲俱掃蕩，等閑平地滔天浪。", "萬里風雲都一槳。", "尤宏放，折衝佛祖休相讓。"]'),
('8cdef7af-a6db-45c1-8d7d-5578e91e62d2','空東山忌日','釋居簡','宋','宋诗','song-poetry','','[]','笑別金鑾歸玉几，鰻井無風波浪起。',176,'全唐诗/poet.song.181000.json','["笑別金鑾歸玉几，鰻井無風波浪起。", "中興天子紫泥新，老牛特地重穿鼻。", "風雲騰踏慶三朝，端自靈山同受記。", "龍湫坐斷最高峰，聖諦提持第一義。", "儂家虀甕深無底，炎炎毒氣難迴避。", "瓠落有容無滴水，無限英靈都浸死。", "有時却作死馬醫，絕後再甦知幾幾。", "忽聞拂袖下層翠，江上截流航一葦。", "一箇閑人天地間，邁古超今誰敢擬。", "浮圖影裏舊經行，祖禰餘殃今未已。", "更運深慈等大千，毒種綿綿亦如是。"]'),
('710da6c9-235e-46bc-bb9e-6fcc08b04c92','謝昌鑑堂','釋居簡','宋','宋诗','song-poetry','','[]','三年雪峰居，飽喫雪峰飯。',72,'全唐诗/poet.song.181000.json','["三年雪峰居，飽喫雪峰飯。", "不弄死鱉鼻，終日視雲漢。", "衆狙紛喜怒，我儂只管看。", "鑑堂賞此音，一唱復三嘆。", "無端高索價，擔起睦州板。", "問之何因爾，佛法不怕爛。"]'),
('98b747e7-5d1f-494b-88d9-08745566f3fd','送雪峰殿主化燈油兼簡臨川道友','釋居簡','宋','宋诗','song-poetry','','[]','沈沈古殿寒光射，金色同然無晝夜。',96,'全唐诗/poet.song.181000.json','["沈沈古殿寒光射，金色同然無晝夜。", "萬象森羅影現中，盲者還同覆盆下。", "周禪見渠不瞥地，金色光中重按指。", "散作人間無盡燈，直下翻身光影裏。", "只今此話難藏覆，掉頭徑出烟蘿去。", "不是臨川舊賞音，此段風流與誰舉。"]'),
('152d22aa-07b1-47ef-9b4e-30465ee5d5f1','寄元柏庭','釋居簡','宋','宋诗','song-poetry','','[]','慧林未試擊虎術，已覺堂前草狼藉。',96,'全唐诗/poet.song.181000.json','["慧林未試擊虎術，已覺堂前草狼藉。", "更說全提與半提，大空小空皆辟易。", "壁立萬仞二十年，不與諸方較目前。", "願從伏波老禪將，相與掎角摧其堅。", "龍門餘波靡不至，矻然中流一人耳。", "事難方見丈夫心，委地宏綱看振起。"]'),
('259147a1-c01f-4b68-8697-3ca2e2462713','送琦後堂住薦福','釋居簡','宋','宋诗','song-poetry','','[]','錦屏之英老大隋，孤芳寄林非所宜。',160,'全唐诗/poet.song.181000.json','["錦屏之英老大隋，孤芳寄林非所宜。", "南堂特榻越常軌，東山陷虎藏深機。", "稽山之琦後來秀，倔强不落古人後。", "後堂新破北山荒，奪食驅耕誇敏手。", "古已往矣不可覓，胡爲區區蹈陳跡。", "衲僧懷袖捲風雲，何地不容轟霹靂。", "吾常學古不學今，確持讜直甘陸沈。", "顧影自立時自箴，舍公其誰知此心。", "公今老牯群中去，轉位回機頭角露。", "所存匪石不可移，萬里驍騰在初步。"]'),
('4b793061-6b6c-477a-aa54-3f0d68303c11','送權孤雲爲母歸鄉','釋居簡','宋','宋诗','song-poetry','','[]','不踞千峯萬峰頂，謾勞半座分雙徑。',96,'全唐诗/poet.song.181000.json','["不踞千峯萬峰頂，謾勞半座分雙徑。", "情知覆水不容收，再向鄮峰提此令。", "大器晚成天所托，不怕者些渾爛却。", "俯視群飛已刺天，未反掌間仍撲落。", "試從列祖圖中看，古注與誰同一眼。", "濁港渡頭無姓兒，睦州城西老擔板。"]'),
('6a515fa0-71dd-45ea-8f00-8faa45acd8e6','寄愿毒果','釋居簡','宋','宋诗','song-poetry','','[]','毒果才登靈鷲峰，南山馬群爲一空。',96,'全唐诗/poet.song.181000.json','["毒果才登靈鷲峰，南山馬群爲一空。", "鷲峰亦復無所容，寂寥風味南山同。", "聾人有耳固不聰，雙眼復隨雙耳聾。", "苞苴公行喪真風，祝鮀之佞爲正宗。", "有生窮極變則通，公無留滯蒿蓬中。", "行看勁氣噓長虹，拈出死蛇爲活龍。"]'),
('ae6cee74-fd0c-4af9-af1e-5e8d3051411e','巖首座母死歸自靈隠以此唁之','釋居簡','宋','宋诗','song-poetry','','[]','望斷靈山消息絕，不復倚門吹白髮。',64,'全唐诗/poet.song.181000.json','["望斷靈山消息絕，不復倚門吹白髮。", "或從西向問歸程，臘月蓮花隨步發。", "靈山上首翻途轍，臨喪不哀非曠達。", "回首一會儼然在，將此深心奉塵剎。"]'),
('b7e41c12-c9b6-47a6-9dbb-f89e58502dc1','送潜兄歸西山','釋居簡','宋','宋诗','song-poetry','','[]','虛空講得花狼藉，正坐膏肓必死疾。',96,'全唐诗/poet.song.181000.json','["虛空講得花狼藉，正坐膏肓必死疾。", "西山一去杳無聞，空使脩名光照日。", "阿潜竭斗不如是，晝不暇食夜不寐。", "凜然鐵石乃其心，要出古人一頭地。", "只今猛省天平錯，烏藤影動千山邈。", "到家消息在途中，莫向途中小了却。"]'),
('48fb57ce-f4dc-41ce-937a-cf7068a57ee6','送六人起雪峰歸江西','釋居簡','宋','宋诗','song-poetry','','[]','西河獅子迷子訣，馿年夢見者一橛。',96,'全唐诗/poet.song.181000.json','["西河獅子迷子訣，馿年夢見者一橛。", "若謂六人成大器，何得人荒仍路絕。", "古澗瞪目不見底，透得網來猶滯水。", "六鰲矯首抃三山，霹靂一聲平地起。", "直下羅籠不肯住，行看爲雲復爲雨。", "浪花翻處看龍翔，掀倒江西葛藤樹。"]'),
('eabe20bf-7382-4aad-b3d5-9c22c5a73b01','寄西禪驥無稱','釋居簡','宋','宋诗','song-poetry','','[]','凌霄峰頂三年別，信亦不通書不達。',128,'全唐诗/poet.song.181000.json','["凌霄峰頂三年別，信亦不通書不達。", "怡山素約已休論，更欲染雲歌一鉢。", "鷦鷯一枝在林杪，三穴空嗟秋兔狡。", "况復疎慵與世乖，乘流却把烏藤拗。", "隨流入流眼卓朔，胸中涇渭元清濁。", "曲爲今時一線通，老鼠何妨入牛角。", "無限旁觀皆罔措，它家自有通霄路。", "此理明明說向誰，笑倒無稱老禪虎。"]'),
('a609f919-f367-4f0f-8602-15f6d8d53126','海門','釋居簡','宋','宋诗','song-poetry','','[]','目斷滄溟徒却步，此中豈是無門戶。',32,'全唐诗/poet.song.181000.json','["目斷滄溟徒却步，此中豈是無門戶。", "不犯波瀾過得來，海天風月無分付。"]'),
('c03abc92-45eb-4086-95ce-a96f0ff35c81','澤侍者參隨硤山琛老覓語','釋居簡','宋','宋诗','song-poetry','','[]','硤山一關無鎖鑰，從門入者踏不著。',64,'全唐诗/poet.song.181000.json','["硤山一關無鎖鑰，從門入者踏不著。", "若是行家上上流，肯向那邊輕著脚。", "澤禪已是失照顧，不覺全身在裏許。", "莫嫌裏許寂寥生，記取硤山最初句。"]'),
('26c3ce0d-dde4-4b4f-be79-e8e2d5dee51e','送振上人歸永康','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u592a\u6e56"]','未發足時已超越，萬里岷江濫觴發。',96,'全唐诗/poet.song.181000.json','["未發足時已超越，萬里岷江濫觴發。", "瞻風撥草走天涯，滔天汩汩誰能過。", "太湖死水混不得，濁涇清渭明如日。", "重向西湖疏正脈，渺渺狂瀾歸一滴。", "只今滴水既還源，四海一味忘中邊。", "岷山之人莫輕忽，平地行看漲溟渤。"]'),
('39e29255-fed9-4267-a87e-cf2e5b86c4b2','送達上人歸鄉','釋居簡','宋','宋诗','song-poetry','','[]','肯堂不曉巴蜀音，卍菴錯以心傳心。',64,'全唐诗/poet.song.181000.json','["肯堂不曉巴蜀音，卍菴錯以心傳心。", "當時盡道有分付，一盲衆盲訛至今。", "上人覷破便西泝，醜惡却須善藏護。", "若也輕輕露一斑，連汝惡名無雪處。"]'),
('77870978-08b2-41b5-a70d-d53bb94c3054','送暉上人辭拙庵老人過靈隠','釋居簡','宋','宋诗','song-poetry','','[]','退欄老{牜占}饒竭斗，雲卧指南成過咎。',70,'全唐诗/poet.song.181000.json','["退欄老{牜占}饒竭斗，雲卧指南成過咎。", "阿師一見便回首，不復待渠開臭口。", "冷泉眼耳一關{尢叟}，見聞絕處誰深委。", "爲伊拈出者些兒，占取明窗下單位。"]'),
('6bfd3f02-64a1-42b3-9b1a-f0af15421491','與開老','釋居簡','宋','宋诗','song-poetry','','[]','自負平生識湛庵，只今又與阿戎談。',32,'全唐诗/poet.song.181000.json','["自負平生識湛庵，只今又與阿戎談。", "須知父子不傳底，豈在南詢五十三。"]'),
('bb48091b-7841-4a84-a82d-19649c2bec20','送真上人歸洋川','釋居簡','宋','宋诗','song-poetry','','[]','卓地無錐强點胸，不知將底當家風。',32,'全唐诗/poet.song.181000.json','["卓地無錐强點胸，不知將底當家風。", "橫行海上無知己，氣宇軒昂入漢中。"]'),
('67b2cc21-86d7-4fde-8589-5c7264efbfe1','倦菴王德政','釋居簡','宋','宋诗','song-poetry','','[]','有耳慵將聽是非，無心只據目前機。',32,'全唐诗/poet.song.181000.json','["有耳慵將聽是非，無心只據目前機。", "不隨十二時辰去，却解差排十二時。"]'),
('22c2061d-a530-49bb-93ab-b5e7acfd8a00','和劉文伯春牛韻','釋居簡','宋','宋诗','song-poetry','','[]','不獨分身在此州，通身灰土渾常牛。',32,'全唐诗/poet.song.181000.json','["不獨分身在此州，通身灰土渾常牛。", "一從惱亂春風後，千古春風不斷頭。"]'),
('28905195-3c6c-4a9f-989b-38a88290ac67','吊朱堅老','釋居簡','宋','宋诗','song-poetry','','[]','昔日當軒百步威，幾人到此竪降旗。',32,'全唐诗/poet.song.181000.json','["昔日當軒百步威，幾人到此竪降旗。", "若非居士通方眼，誰識川僧陷虎機。"]'),
('e79ad1df-bdf5-437f-ad9b-ca3439fdb6b1','送定上人歸潼川','釋居簡','宋','宋诗','song-poetry','','[]','故國江山杳靄中，半千尊者駐靈蹤。',32,'全唐诗/poet.song.181000.json','["故國江山杳靄中，半千尊者駐靈蹤。", "知君萬里飛歸錫，已豎降旗立下風。"]'),
('7373411e-657a-47d8-ad46-95e30a018d5e','感山讀蘿湖野錄呈雲卧菴主  其一','釋居簡','宋','宋诗','song-poetry','','[]','住山活計一般無，不數朣朣照乘珠。',32,'全唐诗/poet.song.181000.json','["住山活計一般無，不數朣朣照乘珠。", "試探篋中何所有，珠回玉轉一蘿湖。"]'),
('7518cae0-93c6-426e-95d2-ec7588116ca6','感山讀蘿湖野錄呈雲卧菴主  其二','釋居簡','宋','宋诗','song-poetry','','[]','管城饒舌析玄微，一字何曾療得饑。',32,'全唐诗/poet.song.181000.json','["管城饒舌析玄微，一字何曾療得饑。", "文彩既彰非得已，知音未舉要先知。"]'),
('3894df5b-9d89-4dc6-8415-98445e8577fd','送善藏主出嶺  其一','釋居簡','宋','宋诗','song-poetry','','[]','一度遭佗痒處抓，憤然回首要翻交。',32,'全唐诗/poet.song.181000.json','["一度遭佗痒處抓，憤然回首要翻交。", "誰知到後重遭毒，劫石銷時恨不消。"]'),
('9e95600f-10be-4f19-9008-778fa322cd88','送善藏主出嶺  其二','釋居簡','宋','宋诗','song-poetry','','[]','老漢檉样已活埋，七閩從此更無灾。',32,'全唐诗/poet.song.181000.json','["老漢檉样已活埋，七閩從此更無灾。", "可憐毒種收餘毒，虎行狼心挽不回。"]'),
('cc11319b-e4a0-48ae-bfd8-d9423be64916','送二僧見拙菴老人','釋居簡','宋','宋诗','song-poetry','','[]','道契聖天子，年高王老師。',48,'全唐诗/poet.song.181000.json','["道契聖天子，年高王老師。", "惡聲人不喜，拙處佛猶疑。", "未委聞名後，何如覿面時。", "欲言言不及，落賺自然知。"]'),
('bfc40441-fa1f-49d0-af80-fd7fb0c92272','和海藏主韵','釋居簡','宋','宋诗','song-poetry','','[]','海涵地負避無門，萬象森羅托此恩。',32,'全唐诗/poet.song.181000.json','["海涵地負避無門，萬象森羅托此恩。", "萬象之中全體露，胸襟流出盡乾坤。"]'),
('683fe180-4bcf-4929-afd1-af82914db6a8','題手軸十六羅漢送洪兄歸劍州  其一','釋居簡','宋','宋诗','song-poetry','','[]','鈍根捏怪辱先宗，寫影圖形在此中。',32,'全唐诗/poet.song.181000.json','["鈍根捏怪辱先宗，寫影圖形在此中。", "今日卷舒都在我，看渠何處現神通。"]'),
('b11268f8-5413-454e-b153-2ba1f446770f','題手軸十六羅漢送洪兄歸劍州  其二','釋居簡','宋','宋诗','song-poetry','','[]','七八千里劍門路，十五六僧方外人。',32,'全唐诗/poet.song.181000.json','["七八千里劍門路，十五六僧方外人。", "擬欲大家携手去，爲伊公驗不分明。"]'),
