('b175dcf4-6d61-412e-a8c2-cd9a1277eb14','偈頌一百三十三首  其七','釋居簡','宋','宋诗','song-poetry','','[]','還債金輪種，陳年甘蔗苗。',24,'全唐诗/poet.song.181000.json','["還債金輪種，陳年甘蔗苗。", "九龍翻雪浪，滴水也難消。"]'),
('ba404244-da23-4507-a035-59bc9e3a8268','偈頌一百三十三首  其八','釋居簡','宋','宋诗','song-poetry','','[]','師子當門，誰敢覷著。',20,'全唐诗/poet.song.181000.json','["師子當門，誰敢覷著。", "仁義道中，放過一著。"]'),
('fe731dd6-c515-49e7-b0a6-99a76c134dee','偈頌一百三十三首  其九','釋居簡','宋','宋诗','song-poetry','','[]','節外生枝，劣中取勝。',20,'全唐诗/poet.song.181000.json','["節外生枝，劣中取勝。", "輟己爲人，無乃太甚。"]'),
('08a540b5-ac76-48f8-b48e-5e2b564afedc','偈頌一百三十三首  其一○','釋居簡','宋','宋诗','song-poetry','','[]','黄梅七百，如龍爭珠。',30,'全唐诗/poet.song.181000.json','["黄梅七百，如龍爭珠。", "因甚今日，劫在這裏。", "爭之不足，讓之有餘。"]'),
('e89228b9-1f5d-49ba-a613-f6cb5ec22567','偈頌一百三十三首  其一一','釋居簡','宋','宋诗','song-poetry','','[]','從來不解强安排，擲地金聲破草鞋。',32,'全唐诗/poet.song.181000.json','["從來不解强安排，擲地金聲破草鞋。", "無位真人無面目，何妨運水及搬柴。"]'),
('cf9c8810-a8e1-44c8-a887-73769d4327c3','偈頌一百三十三首  其一二','釋居簡','宋','宋诗','song-poetry','','[]','試問卧雲深處客，不知何以答升平。',32,'全唐诗/poet.song.181000.json','["試問卧雲深處客，不知何以答升平。", "蕩然至化難逃避，萬里堯天一點雲。"]'),
('814400de-7a41-499c-83fe-f152250c5331','偈頌一百三十三首  其一三','釋居簡','宋','宋诗','song-poetry','','[]','枯木寒灰，銅崖鐵壁。',38,'全唐诗/poet.song.181000.json','["枯木寒灰，銅崖鐵壁。", "春到無痕，春歸無跡。", "桃花紅，李花白。", "明眼人前，一場狼藉。"]'),
('c5e84d19-6237-4978-bb33-6675ac95ba3d','偈頌一百三十三首  其一四','釋居簡','宋','宋诗','song-poetry','','[]','初於聞中，入流忘所。',32,'全唐诗/poet.song.181000.json','["初於聞中，入流忘所。", "圓通路絕，滿面塵埃。", "洞門無鎖鑰，俗客不曾來。"]'),
('a0e002e1-5ea8-4637-8cec-8c3642a893fb','偈頌一百三十三首  其一五','釋居簡','宋','宋诗','song-poetry','','[]','學道如鑽火，逢煙未可休。',24,'全唐诗/poet.song.181000.json','["學道如鑽火，逢煙未可休。", "直待金星現，曹門取鄭州。"]'),
('bddee133-c4f0-4285-bfac-cb98e9611469','偈頌一百三十三首  其一六','釋居簡','宋','宋诗','song-poetry','','[]','鼎湖龍去不知還，遥想清都虎豹閑。',32,'全唐诗/poet.song.181000.json','["鼎湖龍去不知還，遥想清都虎豹閑。", "欲借剛風朝紫闕，九天閶闔正開關。"]'),
('1fa7d867-609b-4df0-b392-be0cc1f35d8e','偈頌一百三十三首  其一七','釋居簡','宋','宋诗','song-poetry','','[]','晷運推移，日南長至。',32,'全唐诗/poet.song.181000.json','["晷運推移，日南長至。", "應時納祜，看樓打樓。", "群陰消剝盡，特地一場愁。"]'),
('7171051b-f3d7-4a50-a0bf-69539e8832f0','偈頌一百三十三首  其一八','釋居簡','宋','宋诗','song-poetry','','[]','六年勤苦竟何如，爲問君王記得無。',32,'全唐诗/poet.song.181000.json','["六年勤苦竟何如，爲問君王記得無。", "直下雖知難抵諱，到頭終不受塗糊。"]'),
('10507c5a-bf39-4dba-a7f2-dcfe5cf09db8','偈頌一百三十三首  其一九','釋居簡','宋','宋诗','song-poetry','','[]','三到投子，含元殿裏。',36,'全唐诗/poet.song.181000.json','["三到投子，含元殿裏。", "九上洞山，更覓長安。", "自從夜雪擁鰲山，一度思量一度寒。"]'),
('ae685520-9d17-4891-b6b4-b9211e11e91e','偈頌一百三十三首  其二○','釋居簡','宋','宋诗','song-poetry','','[]','窮廝煎，餓廝吵。',18,'全唐诗/poet.song.181000.json','["窮廝煎，餓廝吵。", "古岸風高，玉壺春曉。"]'),
('c0e07aaa-0190-4f9f-ac34-23b3a7689546','偈頌一百三十三首  其二一','釋居簡','宋','宋诗','song-poetry','','[]','今日中夏了也，畢竟事作麽生。',46,'全唐诗/poet.song.181000.json','["今日中夏了也，畢竟事作麽生。", "當陽一機，轉身一步。", "左右逢原，了無回互。", "本等牧牛人，何曾頭角露。"]'),
('f9a02331-212b-47b8-8e0a-70e2f1448e4d','偈頌一百三十三首  其二二','釋居簡','宋','宋诗','song-poetry','','[]','千年父祖舊田疇，萬寶垂成及早收。',32,'全唐诗/poet.song.181000.json','["千年父祖舊田疇，萬寶垂成及早收。", "無底鉢盂開口笑，聖凡一等飽齁齁。"]'),
('6f904449-3408-4ea0-b12a-2743786fae69','偈頌一百三十三首  其二三','釋居簡','宋','宋诗','song-poetry','','[]','天中天，聖中聖。',26,'全唐诗/poet.song.181000.json','["天中天，聖中聖。", "贊不及，述不盡。", "四海九州，一印印定。"]'),
('eb0ad5a6-a9b8-400f-9bc3-2361c2404d88','偈頌一百三十三首  其二四','釋居簡','宋','宋诗','song-poetry','','[]','今日開爐，報恩隨例。',52,'全唐诗/poet.song.181000.json','["今日開爐，報恩隨例。", "火筯香匙，各有節制。", "若待豆爆冷灰，未免遞相鈍置。", "識火色，辨風旨。", "曲突徙薪，已落第二。"]'),
('aa07db66-3926-4a5d-bef6-1f0a06768a56','偈頌一百三十三首  其二五','釋居簡','宋','宋诗','song-poetry','','[]','一大藏教，總是魔說。',28,'全唐诗/poet.song.181000.json','["一大藏教，總是魔說。", "日可冷，月可熱。", "是假易除，是真難滅。"]'),
('17b10682-ad06-4fac-bd18-8bf31b387b47','偈頌一百三十三首  其二六','釋居簡','宋','宋诗','song-poetry','','[]','亂山裹雪玉崔嵬，萬行門庭八字開。',32,'全唐诗/poet.song.181000.json','["亂山裹雪玉崔嵬，萬行門庭八字開。", "惆悵善財歸去後，寥寥不見一人來。"]'),
('ab18cea6-e678-4516-b7dc-eeca9f75bc49','偈頌一百三十三首  其二七','釋居簡','宋','宋诗','song-poetry','','[]','華鯨吼月，虛籟沈秋。',22,'全唐诗/poet.song.181000.json','["華鯨吼月，虛籟沈秋。", "裂破玄關了，隨流復入流。"]'),
('8d6e1527-cc4f-464b-879a-bba7611b1bf3','偈頌一百三十三首  其二八','釋居簡','宋','宋诗','song-poetry','','["\u592a\u6e56"]','南來底下載，北來底上載。',22,'全唐诗/poet.song.181000.json','["南來底下載，北來底上載。", "月白風清，太湖無蓋。"]'),
('b0e71017-b718-4390-a198-d796f2a12566','偈頌一百三十三首  其二九','釋居簡','宋','宋诗','song-poetry','','[]','窮廝煎，餓廝炒。',40,'全唐诗/poet.song.181000.json','["窮廝煎，餓廝炒。", "東家兒啼，西家婦笑。", "暗寫愁腸，善說法要。", "良哉觀世音，郎當也不少。"]'),
('8f981d55-cc1d-49c8-ac65-cd714230c82e','偈頌一百三十三首  其三○','釋居簡','宋','宋诗','song-poetry','','[]','曲吹徹，鼓皮穿。',26,'全唐诗/poet.song.181000.json','["曲吹徹，鼓皮穿。", "夜深人靜，燈盌油乾。", "一道神光萬境閑。"]'),
('4b81af65-44fe-4732-b949-35fd434c3519','偈頌一百三十三首  其三一','釋居簡','宋','宋诗','song-poetry','','[]','纔生便剗，不得一半。',20,'全唐诗/poet.song.181000.json','["纔生便剗，不得一半。", "失之東隅，桑榆已晚。"]'),
('303c5760-6462-48e4-b14d-8b6a3715d317','偈頌一百三十三首  其三二','釋居簡','宋','宋诗','song-poetry','','[]','非不非，是不是。',20,'全唐诗/poet.song.181000.json','["非不非，是不是。", "無事困人心，莫將無事會。"]'),
('e10b72ba-c8bb-44a5-ba1c-e9e01853bfb4','偈頌一百三十三首  其三三','釋居簡','宋','宋诗','song-poetry','','[]','薤露凄凉亦可憐，白楊丹旐去翩翩。',32,'全唐诗/poet.song.181000.json','["薤露凄凉亦可憐，白楊丹旐去翩翩。", "哀哀聲裏無消息，打著南邊動北邊。"]'),
('d8b0fc68-97e9-4a29-adc2-15f2ccacb5e7','偈頌一百三十三首  其三四','釋居簡','宋','宋诗','song-poetry','','[]','病來病去無聊頼，及至除根病轉多。',34,'全唐诗/poet.song.181000.json','["病來病去無聊頼，及至除根病轉多。", "事久多變，年老成魔。", "看它此去又如何。"]'),
('ab0973af-7019-4694-95ce-1aae9f4aff2c','偈頌一百三十三首  其三五','釋居簡','宋','宋诗','song-poetry','','[]','隻手擡，隻手搦。',18,'全唐诗/poet.song.181000.json','["隻手擡，隻手搦。", "毫釐有差，天地懸隔。"]'),
('3a174d20-98fe-491d-bcb8-3157b27b0551','偈頌一百三十三首  其三六','釋居簡','宋','宋诗','song-poetry','','[]','餘二即非真，惟此一事實。',22,'全唐诗/poet.song.181000.json','["餘二即非真，惟此一事實。", "密在汝邊，我說不密。"]'),
('3d982f30-3fba-4747-babc-27c7d556c51b','偈頌一百三十三首  其三七','釋居簡','宋','宋诗','song-poetry','','[]','諸方說禪，地藏種田。',42,'全唐诗/poet.song.181000.json','["諸方說禪，地藏種田。", "西余門下，又却不然。", "饑來喫飯，困來打眠。", "不是知音者，徒勞話歲寒。"]'),
('9c7dc2c0-bafc-4a54-8752-d975726b4a88','偈頌一百三十三首  其三八','釋居簡','宋','宋诗','song-poetry','','[]','十四年，四月一。',34,'全唐诗/poet.song.181000.json','["十四年，四月一。", "流水無情，落花無跡。", "一句了然超百億，莫待當來問彌勒。"]'),
('7365ebb9-a067-43bf-a4f7-313ca3b01328','偈頌一百三十三首  其三九','釋居簡','宋','宋诗','song-poetry','','[]','汲井花水，煮薔薇露，清浄法身遭點污。',28,'全唐诗/poet.song.181000.json','["汲井花水，煮薔薇露，清浄法身遭點污。", "活戾世界，一年一度。"]'),
('81712a9b-3c96-4544-b6cb-4b6085256d0a','偈頌一百三十三首  其四○','釋居簡','宋','宋诗','song-poetry','','[]','三分光陰二早過，向下文長。',47,'全唐诗/poet.song.181000.json','["三分光陰二早過，向下文長。", "靈臺一點不揩磨，彼自無瘡。", "貪生逐日區區去，終日茫茫。", "喚不回頭爭奈何。"]'),
('f469547c-e82e-4305-9738-1fd4aa398cf6','偈頌一百三十三首  其四一','釋居簡','宋','宋诗','song-poetry','','[]','三月十五，落花飛絮。',38,'全唐诗/poet.song.181000.json','["三月十五，落花飛絮。", "業識茫茫，無本可據。", "把得定，作得主。", "伶俐衲僧，不恁麽去。"]'),
('607e6252-f40f-417e-a237-87c3bacb3988','偈頌一百三十三首  其四二','釋居簡','宋','宋诗','song-poetry','','[]','晃晃在心目，昭昭居色塵。',24,'全唐诗/poet.song.181000.json','["晃晃在心目，昭昭居色塵。", "莫將銀世界，喚作假銀城。"]'),
('d87dc06d-381f-4e0a-adc4-e94beed92555','偈頌一百三十三首  其四三','釋居簡','宋','宋诗','song-poetry','','[]','跛跛挈挈，百醜千拙。',20,'全唐诗/poet.song.181000.json','["跛跛挈挈，百醜千拙。", "鬭諸方勝，勝諸方劣。"]'),
('57c87f90-371d-4b53-88ea-8a3fc112de4d','偈頌一百三十三首  其四四','釋居簡','宋','宋诗','song-poetry','','[]','瞿曇幾箇舌頭，衆會幾箇眼睛。',36,'全唐诗/poet.song.181000.json','["瞿曇幾箇舌頭，衆會幾箇眼睛。", "頭頭物物，剎剎塵塵。", "自瞞猶自可，最苦是瞞人。"]'),
('134785d0-1645-4796-8c32-79416e8e24fd','偈頌一百三十三首  其四五','釋居簡','宋','宋诗','song-poetry','','[]','是佛亦拜，是魔亦拜。',20,'全唐诗/poet.song.181000.json','["是佛亦拜，是魔亦拜。", "大膽小心，不妨忒煞。"]'),
('eab43fa4-5929-4a3d-9465-0a7c0c9de647','偈頌一百三十三首  其四六','釋居簡','宋','宋诗','song-poetry','','[]','目前機，摩竭令。',18,'全唐诗/poet.song.181000.json','["目前機，摩竭令。", "無法商量，一印印定。"]'),
('88cec5d8-aa4a-43c7-a900-5fcbe8858c43','偈頌一百三十三首  其四七','釋居簡','宋','宋诗','song-poetry','','[]','衲僧家，不瀟洒。',80,'全唐诗/poet.song.181000.json','["衲僧家，不瀟洒。", "嫌人贊，愛人駡。", "無諍三昧，知音者寡。", "三昧即且置，如何是無諍。", "客來須接，賊來須打。", "浪宕樓頭無藉在，零丁利帝可憐生。", "惡叉聚是此中人，佛子住非他處成。"]'),
('1f2a7ee7-9737-4996-b0ba-5a3008b1bbce','偈頌一百三十三首  其四八','釋居簡','宋','宋诗','song-poetry','','[]','佛真法身，抵死謾生。',28,'全唐诗/poet.song.181000.json','["佛真法身，抵死謾生。", "自沽村酒，自把磁瓶。", "却著衫來作主人。"]'),
('77ca6abe-af00-415f-a988-435d6e34a832','偈頌一百三十三首  其四九','釋居簡','宋','宋诗','song-poetry','','[]','擬破一微塵，分明昧此經。',24,'全唐诗/poet.song.181000.json','["擬破一微塵，分明昧此經。", "如何破經卷，出此一微塵。"]'),
('a3a19a3b-3d95-470d-9a09-6db1371c87e6','偈頌一百三十三首  其五○','釋居簡','宋','宋诗','song-poetry','','[]','惡星臨照命宮時，雪重山寒眼𥉌癡。',32,'全唐诗/poet.song.181000.json','["惡星臨照命宮時，雪重山寒眼𥉌癡。", "我似釣魚船上客，還將哥邏報君知。"]'),
('d861a074-6d0b-453c-b6b7-ad7828e4b228','偈頌一百三十三首  其五一','釋居簡','宋','宋诗','song-poetry','','[]','日日雨，夜夜雨。',42,'全唐诗/poet.song.181000.json','["日日雨，夜夜雨。", "鎖了日輪，閉了月戶。", "稻也壞，麥也壞。", "不知者箇壞不壞，問取明州憨布袋。"]'),
('fe0539c2-59e6-4a4b-96dd-4312450a6686','偈頌一百三十三首  其五二','釋居簡','宋','宋诗','song-poetry','','[]','行亦禪，坐亦禪。',35,'全唐诗/poet.song.181000.json','["行亦禪，坐亦禪。", "饑噇飯，困噇眠。", "三到投子，九上洞山，無端掘地覓青天。"]'),
('6a7a7081-c887-49c2-b0db-d6ccb1ffaf80','偈頌一百三十三首  其五三','釋居簡','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','門對廬山，岸橫湓浦。',20,'全唐诗/poet.song.181000.json','["門對廬山，岸橫湓浦。", "把定要津，鴉飛不渡。"]'),
('426ac6ab-93a5-4817-8a1f-7527b2162194','偈頌一百三十三首  其五四','釋居簡','宋','宋诗','song-poetry','','[]','死便埋，死便埋，本來無位次，僧趁俗安排。',39,'全唐诗/poet.song.181000.json','["死便埋，死便埋，本來無位次，僧趁俗安排。", "赤洪崖，白洪崖，是我冤家一樣乖，哀哀。"]'),
('780426b2-e2eb-4f0e-b52f-450b0e2bdc13','偈頌一百三十三首  其五五','釋居簡','宋','宋诗','song-poetry','','[]','今日靜悄悄，昨日閙啾啾。',22,'全唐诗/poet.song.181000.json','["今日靜悄悄，昨日閙啾啾。", "風定花猶落，山更幽。"]'),
('b4450065-dde1-4a8a-8919-e9c576d4c9f6','偈頌一百三十三首  其五六','釋居簡','宋','宋诗','song-poetry','','[]','肉還父，骨還母。',16,'全唐诗/poet.song.181000.json','["肉還父，骨還母。", "日西沈，水東注。"]'),
('636913ac-3e87-49d9-ae53-08da8c1aee24','偈頌一百三十三首  其五七','釋居簡','宋','宋诗','song-poetry','','[]','從者裏入，向那邊行。',22,'全唐诗/poet.song.181000.json','["從者裏入，向那邊行。", "到家消息斷，日午打三更。"]'),
('53aebc71-f11c-4e96-898b-ffc33f94aa6e','偈頌一百三十三首  其五八','釋居簡','宋','宋诗','song-poetry','','[]','不爲禮，禮必壞。',26,'全唐诗/poet.song.181000.json','["不爲禮，禮必壞。", "千人來，萬人拜。", "黄面瞿曇，喫者一解。"]'),
('73d56304-1e6a-4070-8b34-d73bd31c2838','偈頌一百三十三首  其五九','釋居簡','宋','宋诗','song-poetry','','[]','七縱八橫，千重百匝。',20,'全唐诗/poet.song.181000.json','["七縱八橫，千重百匝。", "正令全提，是計不納。"]'),
('30d77ff0-eeb2-4f36-93ea-ec27029e91e4','偈頌一百三十三首  其六○','釋居簡','宋','宋诗','song-poetry','','[]','金猊鐵脊鐵腰頑，逐隊隨群屈節難。',32,'全唐诗/poet.song.181000.json','["金猊鐵脊鐵腰頑，逐隊隨群屈節難。", "要打衲僧門下過，避些炎熱耐些寒。"]'),
('e71d89b7-396a-4903-986d-785419185598','偈頌一百三十三首  其六一','釋居簡','宋','宋诗','song-poetry','','[]','據虎頭，收虎尾。',36,'全唐诗/poet.song.181000.json','["據虎頭，收虎尾。", "未見其人，第一句下明宗旨。", "嘗聞其語，踢起便行，白雲萬里。"]'),
('bcef5b79-b149-4065-821c-d37bca694e53','偈頌一百三十三首  其六二','釋居簡','宋','宋诗','song-poetry','','[]','未發足南方已前，早知錯了底十有五雙。',60,'全唐诗/poet.song.181000.json','["未發足南方已前，早知錯了底十有五雙。", "往往當面諱却，不肯承當。", "若不將錯就錯，未免雪上加霜。", "我者裏纂節去處，聽他烟棹上瞿塘。"]'),
('f31f7172-795f-405f-a937-193119d2489b','偈頌一百三十三首  其六三','釋居簡','宋','宋诗','song-poetry','','[]','浄名有無盡燈法門，後世機巧，取次翻騰。',55,'全唐诗/poet.song.181000.json','["浄名有無盡燈法門，後世機巧，取次翻騰。", "一燈十鏡，十鏡一燈。", "交光相羅。", "徵詰無痕。", "鏡自鏡，燈自燈，大家吹滅暗中行。"]'),
('e547040d-02f5-49d2-ab30-aadeeaf46e22','偈頌一百三十三首  其六四','釋居簡','宋','宋诗','song-poetry','','[]','敗闕在雙林，都無跡可尋。',24,'全唐诗/poet.song.181000.json','["敗闕在雙林，都無跡可尋。", "海枯終見底，人死不知心。"]'),
('b65fa37e-c773-4229-b91b-91e53609aee6','偈頌一百三十三首  其六五','釋居簡','宋','宋诗','song-poetry','','[]','賊來須打，客來須接。',51,'全唐诗/poet.song.181000.json','["賊來須打，客來須接。", "明慶長老來，打即是，接即是。", "若打來不見贓物，若接來未問蹤由，休休，不是冤家不聚頭。"]'),
('b3c01fc4-0e41-4f76-be84-660666a10d28','偈頌一百三十三首  其六六','釋居簡','宋','宋诗','song-poetry','','[]','元正啟祚，萬物咸新。',36,'全唐诗/poet.song.181000.json','["元正啟祚，萬物咸新。", "即日伏惟，無位真人。", "飽莫喜，饑莫嗔，一日從頭五合陳。"]'),
('9750b0be-8013-4841-a3eb-b550c07e66f4','偈頌一百三十三首  其六七','釋居簡','宋','宋诗','song-poetry','','[]','扁舟兩岸依林樾，蕭蕭兩鬢吹華髮。',32,'全唐诗/poet.song.181000.json','["扁舟兩岸依林樾，蕭蕭兩鬢吹華髮。", "萬事不理醉復醒，長占烟波弄明月。"]'),
('05420cd2-bf43-4896-aaef-fd2f6fb004be','偈頌一百三十三首  其六八','釋居簡','宋','宋诗','song-poetry','','[]','量才補職，修德養閑。',28,'全唐诗/poet.song.181000.json','["量才補職，修德養閑。", "一動一靜，妙轉機關，輝天鑑地許誰看。"]'),
('797f83f3-e383-4080-af0d-8d4bd1317fe2','偈頌一百三十三首  其六九','釋居簡','宋','宋诗','song-poetry','','[]','虛空無相身，墮地惹埃塵。',24,'全唐诗/poet.song.181000.json','["虛空無相身，墮地惹埃塵。", "不入紅塵裏，馿年洗得清。"]'),
('de83377e-fab3-450b-884c-e067416ef4bc','偈頌一百三十三首  其七○','釋居簡','宋','宋诗','song-poetry','','[]','羅漢山當戶，朝來有聖燈。',24,'全唐诗/poet.song.181000.json','["羅漢山當戶，朝來有聖燈。", "藩籬俱剖破，不揀小乘僧。"]'),
('140bfe23-a356-4df2-a0dc-325005b24feb','偈頌一百三十三首  其七一','釋居簡','宋','宋诗','song-poetry','','[]','一發中的，百發破的。',24,'全唐诗/poet.song.181000.json','["一發中的，百發破的。", "碧雲十字路頭，又添三害之一。"]'),
('62126237-7188-4cc9-9db8-862a8b1f04e3','偈頌一百三十三首  其七二','釋居簡','宋','宋诗','song-poetry','','[]','日可冷，月可熱，衆魔不能壞真說。',34,'全唐诗/poet.song.181000.json','["日可冷，月可熱，衆魔不能壞真說。", "且道如何是真說，三人證龜，定不是鱉。"]'),
('06d6c20e-2be2-4e28-a963-ae28dddf6d34','偈頌一百三十三首  其七三','釋居簡','宋','宋诗','song-poetry','','[]','十方同聚會，各夢同床。',33,'全唐诗/poet.song.181000.json','["十方同聚會，各夢同床。", "箇箇學無爲，彼自無瘡。", "此是選佛場，蠱毒之鄉。"]'),
('aebc2635-ba1d-4a11-8f09-124547938b27','偈頌一百三十三首  其七四','釋居簡','宋','宋诗','song-poetry','','[]','借婆衫子拜婆年，監木匙挑不上禪。',32,'全唐诗/poet.song.181000.json','["借婆衫子拜婆年，監木匙挑不上禪。", "扶起玉龍轟霹靂，明星猶在九重天。"]'),
('b31e07e5-337b-4e03-8cff-fefca17de666','偈頌一百三十三首  其七五','釋居簡','宋','宋诗','song-poetry','','[]','黄蘗下座，南泉上座。',20,'全唐诗/poet.song.181000.json','["黄蘗下座，南泉上座。", "常州紙貴，一狀領過。"]'),
('d95194da-c898-4283-967f-ad5cf3cb0c74','偈頌一百三十三首  其七六','釋居簡','宋','宋诗','song-poetry','','[]','油油，同聲相應，同氣相求。',29,'全唐诗/poet.song.181000.json','["油油，同聲相應，同氣相求。", "金簇慣調曾百戰，鐵鞭多力恨無讎。"]'),
('c0115f68-bbb7-4985-b36d-3534e866859c','偈頌一百三十三首  其七七','釋居簡','宋','宋诗','song-poetry','','[]','露柱通宵守歲兜，燈籠侵早拜年兜。',58,'全唐诗/poet.song.181000.json','["露柱通宵守歲兜，燈籠侵早拜年兜。", "烏藤趁隊無碑記，跳出禪床左畔兜。", "普伸祝頌隨婁搜，享千秋天生富貴。", "切忌他求，好消息兜。"]'),
('60fa5d4d-6260-4296-95ab-dd9ffd195462','偈頌一百三十三首  其七八','釋居簡','宋','宋诗','song-poetry','','[]','人棄我取，人取我與。',41,'全唐诗/poet.song.181000.json','["人棄我取，人取我與。", "弄業識團，無本可據。", "毀於佛，謗於法，不入衆數，分明有眼難緇素。"]'),
('464378d5-1c07-4bbf-b4b3-963d3e78425c','偈頌一百三十三首  其七九','釋居簡','宋','宋诗','song-poetry','','[]','未到忘筌地，携籃等跳蝦。',24,'全唐诗/poet.song.181000.json','["未到忘筌地，携籃等跳蝦。", "錯行樵子徑，却到葛洪家。"]'),
('1d2be211-8bd0-413a-9e8e-db1119474e8a','偈頌一百三十三首  其八○','釋居簡','宋','宋诗','song-poetry','','[]','魯祖見僧便面壁，平生肝膽向人傾。',38,'全唐诗/poet.song.181000.json','["魯祖見僧便面壁，平生肝膽向人傾。", "潦倒北磵，無背無面。", "終不爲君通，任從滄海變。"]'),
('b9e86013-6074-4d26-b6d7-1c6afe0c2d42','偈頌一百三十三首  其八一','釋居簡','宋','宋诗','song-poetry','','[]','泥猪疥狗，不願生天。',22,'全唐诗/poet.song.181000.json','["泥猪疥狗，不願生天。", "行家滅胡種，成佛待馿年。"]'),
('bc70c603-176f-400a-bdd8-b046e363bd04','偈頌一百三十三首  其八二','釋居簡','宋','宋诗','song-poetry','','[]','簷頭滴滴，分明歷歷。',22,'全唐诗/poet.song.181000.json','["簷頭滴滴，分明歷歷。", "明眼衲僧，切忌從者裏入。"]'),
('e6b2baec-286b-4487-aec2-0c641db0a59b','偈頌一百三十三首  其八三','釋居簡','宋','宋诗','song-poetry','','[]','長樂宮深漏箭遲，憂家丙夜細思惟。',32,'全唐诗/poet.song.181000.json','["長樂宮深漏箭遲，憂家丙夜細思惟。", "鐘鳴漏盡龍樓曉，無復鷄人問寢時。"]'),
('a31f1b6e-5afe-4e34-a70f-37318b6f50b2','偈頌一百三十三首  其八四','釋居簡','宋','宋诗','song-poetry','','[]','三月旦，春過半。',36,'全唐诗/poet.song.181000.json','["三月旦，春過半。", "胡孫繫露柱，露柱聲聲喚。", "南山粲，白石爛，只者一著何曾爛。"]'),
('6eb1565b-4b44-4535-a1a4-66586ebc4f22','偈頌一百三十三首  其八五','釋居簡','宋','宋诗','song-poetry','','[]','獨釣海山秋，綸竿五十牛。',24,'全唐诗/poet.song.181000.json','["獨釣海山秋，綸竿五十牛。", "叮嚀螺與蚌，莫傍釣鰲鈎。"]'),
('35973056-32d9-45c7-b7fe-b33ea214f171','偈頌一百三十三首  其八六','釋居簡','宋','宋诗','song-poetry','','[]','東邊移了復西移，不動尊還有動時。',32,'全唐诗/poet.song.181000.json','["東邊移了復西移，不動尊還有動時。", "弗打併他蹲坐處，安知四十九年非。"]'),
('a28c000d-6cde-4b6b-91ca-b701434bb396','偈頌一百三十三首  其八七','釋居簡','宋','宋诗','song-poetry','','[]','透骨寒凝眼不開，陽和一點自何來。',32,'全唐诗/poet.song.181000.json','["透骨寒凝眼不開，陽和一點自何來。", "六年辛苦都休了，不悟明星是禍胎。"]'),
('d9399cfc-5ac4-48cb-9a95-90d51a3af6f2','偈頌一百三十三首  其八八','釋居簡','宋','宋诗','song-poetry','','[]','三應三呼，不辭入草。',46,'全唐诗/poet.song.181000.json','["三應三呼，不辭入草。", "罰錢出院，正要話行。", "軟頑侍者，孟浪克賓。", "數聲羌笛離亭晚，君向瀟湘我向秦。"]'),
('0e9a5b16-a797-4280-9a9c-956caeca2d2c','偈頌一百三十三首  其八九','釋居簡','宋','宋诗','song-poetry','','[]','薑杏盃深恨未消，竹篙只作等閑摇。',32,'全唐诗/poet.song.181000.json','["薑杏盃深恨未消，竹篙只作等閑摇。", "一從收卷波瀾後，誰在坳堂學弄潮。"]'),
('9e897356-8271-4ed6-b64b-aeed364fdecb','偈頌一百三十三首  其九○','釋居簡','宋','宋诗','song-poetry','','[]','莫袖搴旗手，同扶折脚鐺。',24,'全唐诗/poet.song.181000.json','["莫袖搴旗手，同扶折脚鐺。", "高碁放低著，死路活教行。"]'),
('647c6463-9060-4eb6-81c9-a9670ee6c9af','偈頌一百三十三首  其九一','釋居簡','宋','宋诗','song-poetry','','[]','一聲哇地便吒哩，突出如斯大闡提。',32,'全唐诗/poet.song.181000.json','["一聲哇地便吒哩，突出如斯大闡提。", "此土西天起殃害，堂堂洗土不成泥。"]'),
('c647fbd1-9f0a-41dd-a86b-a21c31bc6709','偈頌一百三十三首  其九二','釋居簡','宋','宋诗','song-poetry','','[]','雪溪一漚滅，輥入龍湫裏。',42,'全唐诗/poet.song.181000.json','["雪溪一漚滅，輥入龍湫裏。", "龍湫攪得渾，六月凍連底。", "喝石巖前，菖蒲田裏。", "癡人猶戽夜塘水。"]'),
('5bb7eb11-9ba8-4108-9ab9-22bf3998f5e2','偈頌一百三十三首  其九三','釋居簡','宋','宋诗','song-poetry','','[]','來恨出闕遲，歸嫌入峽遲。',46,'全唐诗/poet.song.181000.json','["來恨出闕遲，歸嫌入峽遲。", "疑今真箇悟，悟昔不曾疑。", "南詢是妄，北謁還非。", "日暮碧雲合，亂山啼子規。"]'),
('de579150-e029-46ee-85d2-055b8157dc20','偈頌一百三十三首  其九四','釋居簡','宋','宋诗','song-poetry','','[]','拙拙，拙盡巧生，一場敗缺。',55,'全唐诗/poet.song.181000.json','["拙拙，拙盡巧生，一場敗缺。", "有時證鱉成龜，驀地證龜成鱉。", "諸郎盡解使爺錢，磹窠不肖子，拍手笑掀天，笑他弄到帝王前。"]'),
('12856ee3-7d84-4476-be32-faf352c3209b','偈頌一百三十三首  其九五','釋居簡','宋','宋诗','song-poetry','','[]','去年梅，今歲柳。',52,'全唐诗/poet.song.181000.json','["去年梅，今歲柳。", "大地有全功，物物還依舊。", "衲子生涯也如舊，頭上青灰三五斗。", "臘雪後，春風前。", "莫教蹉過钁頭邊。"]'),
('b94946cf-d926-44d4-8a4f-46698e659a46','偈頌一百三十三首  其九六','釋居簡','宋','宋诗','song-poetry','','[]','一棹鬼門關，橫飛關外天。',42,'全唐诗/poet.song.181000.json','["一棹鬼門關，橫飛關外天。", "九華天下勝，趁得雪中看。", "碧雲暮合，雲與僧閑。", "偶爾相逢到此間。"]'),
('edf55cf7-7e19-440b-bd02-c09b3c32ea15','偈頌一百三十三首  其九七','釋居簡','宋','宋诗','song-poetry','','[]','八表歸仁，一人有慶。',20,'全唐诗/poet.song.181000.json','["八表歸仁，一人有慶。", "樵唱漁歌，拍拍是令。"]'),
('bd51658d-6999-4437-8a8d-2e71adc78a0e','偈頌一百三十三首  其九八','釋居簡','宋','宋诗','song-poetry','','[]','今朝三月初五，天色半晴半雨。',52,'全唐诗/poet.song.181000.json','["今朝三月初五，天色半晴半雨。", "園林過了清明，無限落花飛絮。", "釋迦慳，彌勒富。", "絕憐杜宇不知時，啼得血流無用處。"]'),
('f0da2e0a-d134-4a35-ae53-d620b6a2fc51','偈頌一百三十三首  其九九','釋居簡','宋','宋诗','song-poetry','','[]','半月出去，鼻孔不見眼睛。',24,'全唐诗/poet.song.181000.json','["半月出去，鼻孔不見眼睛。", "一日歸來，眼睛不見鼻孔。"]'),
('9912ac89-aba1-4549-8a47-675dc7ed9a8c','偈頌一百三十三首  其一○○','釋居簡','宋','宋诗','song-poetry','','[]','九旬禁足，是何三昧。',46,'全唐诗/poet.song.181000.json','["九旬禁足，是何三昧。", "合火成群，東倒西攂。", "忽若箭鋒相拄時，突出眼睛，揭却腦蓋，虎巖向他道未在。"]'),
('14d9b71f-9310-41f3-b86e-87a76bd02c47','偈頌一百三十三首  其一○一','釋居簡','宋','宋诗','song-poetry','','[]','今日因甚，作者模樣。',20,'全唐诗/poet.song.181000.json','["今日因甚，作者模樣。", "覿面相呈，當仁不讓。"]'),
('d46c1cac-d91b-4781-b8eb-0c1be8aeb391','偈頌一百三十三首  其一○二','釋居簡','宋','宋诗','song-poetry','','[]','升九仞之上，吾必與之俱。',34,'全唐诗/poet.song.181000.json','["升九仞之上，吾必與之俱。", "極九淵之底，吾亦與之俱。", "吾不見時，何不見吾。"]'),
('493a5c0b-cc33-4086-ae6f-cc8e4bf0de60','偈頌一百三十三首  其一○三','釋居簡','宋','宋诗','song-poetry','','[]','談玄說妙，落在今時，瓠子落蘇那得知。',18,'全唐诗/poet.song.181000.json','["談玄說妙，落在今時，瓠子落蘇那得知。"]'),
('9d4ae547-c2fa-4bfb-bf71-f669922ce6cd','偈頌一百三十三首  其一○四','釋居簡','宋','宋诗','song-poetry','','[]','諸佛不出世，四十九年說。',34,'全唐诗/poet.song.181000.json','["諸佛不出世，四十九年說。", "祖師不西來，少林有妙訣。", "是假易除，是真難滅。"]'),
('c152ad03-84bb-4d7b-bac6-7266e267d498','偈頌一百三十三首  其一○五','釋居簡','宋','宋诗','song-poetry','','[]','塵劫前事，盡在今時。',32,'全唐诗/poet.song.181000.json','["塵劫前事，盡在今時。", "當斷不斷，千駟莫追。", "花須連夜發，莫待曉風吹。"]'),
('ede02299-a3e1-4bbf-a2db-53869359caea','偈頌一百三十三首  其一○六','釋居簡','宋','宋诗','song-poetry','','[]','智不到處，滿口道著，與你大書特書。',39,'全唐诗/poet.song.181000.json','["智不到處，滿口道著，與你大書特書。", "屢書於虛空中，不怕風吹日炙，有名不用鎸頑石。"]'),
('62ca337b-3c28-43d1-9a34-5c706ff01b42','偈頌一百三十三首  其一○七','釋居簡','宋','宋诗','song-poetry','','[]','久坐大雄峯，寒灰撥不紅。',24,'全唐诗/poet.song.181000.json','["久坐大雄峯，寒灰撥不紅。", "一星螢火出，孤鶴已遼東。"]'),
('fe61a9f0-6ef6-4170-bbaa-60a60aa48b0f','偈頌一百三十三首  其一○八','釋居簡','宋','宋诗','song-poetry','','[]','誤將螢火作明星，發得些兒鬼眼睛。',32,'全唐诗/poet.song.181000.json','["誤將螢火作明星，發得些兒鬼眼睛。", "末代只看王勃記，何殊瘞鶴紫陽銘。"]'),
('149e8c6f-493f-4aa3-867d-61e7ba3a9986','偈頌一百三十三首  其一○九','釋居簡','宋','宋诗','song-poetry','','[]','薑杏盃深恨未消，罰錢出院不同條。',32,'全唐诗/poet.song.181000.json','["薑杏盃深恨未消，罰錢出院不同條。", "等閑放過丹霞後，打折烏藤也不饒。"]'),
('d406e5f7-1efe-4fb4-9c07-07af8e9dd79c','偈頌一百三十三首  其一一○','釋居簡','宋','宋诗','song-poetry','','[]','世事悠悠，不如山丘。',32,'全唐诗/poet.song.181000.json','["世事悠悠，不如山丘。", "避喧求靜，騎牛覓牛。", "黄河合眼跳，特地一場愁。"]'),
('ce7a5bb9-db24-4c59-8301-fe9baa71c968','偈頌一百三十三首  其一一一','釋居簡','宋','宋诗','song-poetry','','[]','擒虎易，告人難。',27,'全唐诗/poet.song.181000.json','["擒虎易，告人難。", "難難。", "鐵門限，鐵心肝，龐老油麻樹上攤。"]'),
('7b922be9-3f77-492c-810f-472c78d66f69','偈頌一百三十三首  其一一二','釋居簡','宋','宋诗','song-poetry','','[]','色不是色，菜花黄梨花白。',59,'全唐诗/poet.song.181000.json','["色不是色，菜花黄梨花白。", "聲不是聲，紫燕語黄鶑鳴。", "觀音菩薩，將錢買胡餠，放下手却是饅頭。", "洞裏春光渾不惜，一時流入武陵谿。"]'),
('0bb1e50a-e88b-4973-bb4c-c9419f467900','偈頌一百三十三首  其一一三','釋居簡','宋','宋诗','song-poetry','','[]','佛子生來浄無垢，今年洗了明年又。',32,'全唐诗/poet.song.181000.json','["佛子生來浄無垢，今年洗了明年又。", "頑頼容他五逆兒，劈面淋頭誇毒手。"]'),
('7734f3d6-72a7-4854-ab38-29dc57959d43','偈頌一百三十三首  其一一四','釋居簡','宋','宋诗','song-poetry','','[]','真人夢出大槐宮，直上鈞天廣樂中。',32,'全唐诗/poet.song.181000.json','["真人夢出大槐宮，直上鈞天廣樂中。", "百世木支皆玉葉，追還舜禹舊家風。"]'),
('fe2c723f-c158-4521-80a8-0eaf6beb726d','偈頌一百三十三首  其一一五','釋居簡','宋','宋诗','song-poetry','','[]','五月五日午時，大書特書屢書。',30,'全唐诗/poet.song.181000.json','["五月五日午時，大書特書屢書。", "不向空中咄咄書，是馬何曾喚作馿。"]'),
('4518c410-96f0-472b-b986-f85a74c33540','偈頌一百三十三首  其一一六','釋居簡','宋','宋诗','song-poetry','','[]','三界無法，何處求心。',68,'全唐诗/poet.song.181000.json','["三界無法，何處求心。", "何處有法，何處無心。", "白雲爲蓋，流水作琴。", "誰是知音，一曲兩曲無人會，慚愧慚愧。", "父母所生口，終不向你道，雨過夜塘秋水深。"]'),
('e66c620b-e16b-440c-a5c4-00770d10aa5c','偈頌一百三十三首  其一一七','釋居簡','宋','宋诗','song-poetry','','[]','壽富如天聖嗣多。',56,'全唐诗/poet.song.181000.json','["壽富如天聖嗣多。", "海不揚波長熨帖，雨當指日肆滂沱。", "火無就燥宜潛德，虜嗜殘生必倒戈。", "草木昆蟲均化育，九州四海聽謳歌。"]'),
('a8139897-cb20-4003-ae64-0af5de6cab85','偈頌一百三十三首  其一一八','釋居簡','宋','宋诗','song-poetry','','[]','老胡今日死日到，四海五天俱太平。',32,'全唐诗/poet.song.181000.json','["老胡今日死日到，四海五天俱太平。", "葱嶺又尋歸去路，看來只有業隨身。"]'),
('a85da96b-45c4-4b5d-9dd4-ec32d66895db','偈頌一百三十三首  其一一九','釋居簡','宋','宋诗','song-poetry','','[]','家賊難防，家財必喪。',20,'全唐诗/poet.song.181000.json','["家賊難防，家財必喪。", "只可錯捉，不可錯放。"]'),
('a37dd73a-7212-4e49-87f8-0b24e94a9fb4','偈頌一百三十三首  其一二○','釋居簡','宋','宋诗','song-poetry','','[]','楓落吳江欲冷時，一堂百衲敗荷衣。',32,'全唐诗/poet.song.181000.json','["楓落吳江欲冷時，一堂百衲敗荷衣。", "憑誰撥取爐中火，莫似溈山眼𥉌癡。"]'),
('3ad5f44c-6fe5-4a15-9f53-0292897fdd9c','偈頌一百三十三首  其一二一','釋居簡','宋','宋诗','song-poetry','','[]','斷頭船子傍人門，七佛威儀可斷魂。',32,'全唐诗/poet.song.181000.json','["斷頭船子傍人門，七佛威儀可斷魂。", "爭似國師無伎倆，天津橋看弄胡孫。"]'),
('fe81a762-7712-405e-b1f2-b1234ecd01a0','偈頌一百三十三首  其一二二','釋居簡','宋','宋诗','song-poetry','','[]','海雲空，海天闊。',34,'全唐诗/poet.song.181000.json','["海雲空，海天闊。", "書不來，信不達。", "既是解道本來無一物，因甚不得它衣鉢。"]'),
('3ba07eba-2c72-419f-b2fe-c184842c8734','偈頌一百三十三首  其一二三','釋居簡','宋','宋诗','song-poetry','','[]','千里駒，九肋鱉，九十三年揭日月。',32,'全唐诗/poet.song.181000.json','["千里駒，九肋鱉，九十三年揭日月。", "生既無言死無說，萬象森羅廣長舌。"]'),
('ab9953bb-7415-4b95-a23a-384c4a55dbb2','偈頌一百三十三首  其一二四','釋居簡','宋','宋诗','song-poetry','','[]','八月秋，何處熱。',46,'全唐诗/poet.song.181000.json','["八月秋，何處熱。", "露冷風高，頭頭漏泄。", "何必三到投子掘地覓天，雪擁鰲山一場敗闕。", "踏著秤鎚硬似鐵。"]'),
('77bc8ed7-2612-4e28-b83e-bde496ef2c15','偈頌一百三十三首  其一二五','釋居簡','宋','宋诗','song-poetry','','[]','通玄峰頂，不是人間。',28,'全唐诗/poet.song.181000.json','["通玄峰頂，不是人間。", "心外無法，壺中有天。", "更於何處覓通玄。"]'),
('cff9356b-bcdd-493f-b1f7-afa127434ade','偈頌一百三十三首  其一二六','釋居簡','宋','宋诗','song-poetry','','[]','仲夏初吉，有好消息。',48,'全唐诗/poet.song.181000.json','["仲夏初吉，有好消息。", "露柱燈籠，參學事畢。", "證據則任汝證據，鞭逼則任汝鞭逼。", "當機覿面提，覿面當機疾。"]'),
('613fbf93-6bcc-4619-8bb7-78fb1eaf76df','偈頌一百三十三首  其一二七','釋居簡','宋','宋诗','song-poetry','','[]','牛頭橫說豎說，不曾動舌。',42,'全唐诗/poet.song.181000.json','["牛頭橫說豎說，不曾動舌。", "魯祖見僧面壁，自納敗闕。", "浄慈敗缺，釘橛向空，熨斗煎茶銚不同。"]'),
('a42fd0ce-d7c4-4369-adfd-719d97aa7b94','偈頌一百三十三首  其一二八','釋居簡','宋','宋诗','song-poetry','','[]','時時具足，日日團欒。',20,'全唐诗/poet.song.181000.json','["時時具足，日日團欒。", "含元殿裏，更問長安。"]'),
('01bcbd51-3c5a-4074-9c12-fbea9feeba39','偈頌一百三十三首  其一二九','釋居簡','宋','宋诗','song-poetry','','[]','散亂定，隨流禪。',20,'全唐诗/poet.song.181000.json','["散亂定，隨流禪。", "莫將安樂法，容易與人傳。"]'),
('ea3b04ac-bc0b-4219-bba4-02d84e705c05','偈頌一百三十三首  其一三○','釋居簡','宋','宋诗','song-poetry','','[]','未得黄梅山裏信，先開大庾嶺頭花。',32,'全唐诗/poet.song.181000.json','["未得黄梅山裏信，先開大庾嶺頭花。", "如何種柏栽松手，流入擔柴賣筊家。"]'),
('843cbd92-7832-45cd-b5d2-d0dd975afa4f','偈頌一百三十三首  其一三一','釋居簡','宋','宋诗','song-poetry','','[]','大地及日月，時至皆歸盡。',24,'全唐诗/poet.song.181000.json','["大地及日月，時至皆歸盡。", "未嘗有一物，不被無常吞。"]'),
('7f704edf-eb10-414f-b61d-eae5e6ba1a82','偈頌一百三十三首  其一三二','釋居簡','宋','宋诗','song-poetry','','[]','末上何曾轉法輪，只今再轉謾勞神。',32,'全唐诗/poet.song.181000.json','["末上何曾轉法輪，只今再轉謾勞神。", "路行人不知天曉，猶把靈符執夜明。"]'),
('548e1a69-a94a-40fe-b330-511171333de3','偈頌一百三十三首  其一三三','釋居簡','宋','宋诗','song-poetry','','[]','倒用橫拈眼似眉，憨憨穩放一頭低。',32,'全唐诗/poet.song.181000.json','["倒用橫拈眼似眉，憨憨穩放一頭低。", "全身輥入草窠裏，東倒何妨復攂西。"]'),
('484d1d65-d720-49a4-a2ec-e5538cf35432','頌古二十一首  其一','釋居簡','宋','宋诗','song-poetry','','[]','吹糠著米，翻成特地。',20,'全唐诗/poet.song.181000.json','["吹糠著米，翻成特地。", "不因一事，不長一智。"]'),
('7949265c-14ca-4b67-ba87-790abe8f4512','頌古二十一首  其二','釋居簡','宋','宋诗','song-poetry','','[]','適我昔所願，今者已滿足。',24,'全唐诗/poet.song.181000.json','["適我昔所願，今者已滿足。", "是玉也大奇，只恐不是玉。"]'),
('047ec098-0ddd-4372-aaf8-9acb0c271eba','頌古二十一首  其三','釋居簡','宋','宋诗','song-poetry','','[]','色空明暗，各不相知。',22,'全唐诗/poet.song.181000.json','["色空明暗，各不相知。", "行到水窮處，坐看雲起時。"]'),
('b6517bda-12f0-46fc-8581-3cf2e2b66481','頌古二十一首  其四','釋居簡','宋','宋诗','song-poetry','','[]','彌滿清浄，終不容他。',20,'全唐诗/poet.song.181000.json','["彌滿清浄，終不容他。", "山河大地，萬象森羅。"]'),
('c8027d74-41ad-4287-a90c-466017f40543','頌古二十一首  其五','釋居簡','宋','宋诗','song-poetry','','[]','結解非殊，存亡無據。',22,'全唐诗/poet.song.181000.json','["結解非殊，存亡無據。", "試問本來宗，當初誰縛汝。"]'),
('2b188995-c7e9-4ee9-b940-7a995368ef7b','頌古二十一首  其六','釋居簡','宋','宋诗','song-poetry','','[]','翻手爲雲，覆手爲雨。',20,'全唐诗/poet.song.181000.json','["翻手爲雲，覆手爲雨。", "業識忙忙，無本可據。"]'),
('b0e47dbe-f782-4aa1-a1f4-39fc639b187d','頌古二十一首  其七','釋居簡','宋','宋诗','song-poetry','','[]','金盤不可動，轆轆轉難住。',24,'全唐诗/poet.song.181000.json','["金盤不可動，轆轆轉難住。", "停待良久間，圓明湛如露。"]'),
('761d628a-6ae8-4ada-8915-5ecd91ecf499','頌古二十一首  其八','釋居簡','宋','宋诗','song-poetry','','[]','三蛇九鼠，一畝之地。',20,'全唐诗/poet.song.181000.json','["三蛇九鼠，一畝之地。", "干木隨身，逢場作戲。"]'),
('af2f5932-8c50-4904-a8a8-a7471ae5a1ea','頌古二十一首  其九','釋居簡','宋','宋诗','song-poetry','','["\u601d\u4e61"]','客舍并州已十霜，歸心日夜憶咸陽。',32,'全唐诗/poet.song.181000.json','["客舍并州已十霜，歸心日夜憶咸陽。", "無端又渡桑乾水，却望并州是故鄉。"]'),
('50455630-abb0-4bbe-93df-e0e3da1cbb1d','頌古二十一首  其一○','釋居簡','宋','宋诗','song-poetry','','[]','挽弓須挽强，用槍須用長。',24,'全唐诗/poet.song.181000.json','["挽弓須挽强，用槍須用長。", "射人先射馬，擒賊先擒王。"]'),
('0709089d-382e-437a-9151-9556a7cff9c0','頌古二十一首  其一一','釋居簡','宋','宋诗','song-poetry','','[]','疾燄過風第二頭，不堪惆悵只堪愁。',32,'全唐诗/poet.song.181000.json','["疾燄過風第二頭，不堪惆悵只堪愁。", "一聲振鬣長鳴後，萬馬皆瘖一戰收。"]'),
('d4bffaa2-8f78-41ac-8c21-d3ea1549b291','頌古二十一首  其一二','釋居簡','宋','宋诗','song-poetry','','[]','當機覿面提，覿面當機疾。',24,'全唐诗/poet.song.181000.json','["當機覿面提，覿面當機疾。", "開眼放癡頑，鞭逼人上壁。"]'),
('83ab9a2e-8704-4d5d-ae90-2b01bbea08b1','頌古二十一首  其一三','釋居簡','宋','宋诗','song-poetry','','[]','去年貧，雷在天上壯。',36,'全唐诗/poet.song.181000.json','["去年貧，雷在天上壯。", "今年貧，水出山下蒙。", "家風不與香嚴別，熨斗煎茶銚不同。"]'),
('79c9c172-fa56-4817-975e-1e6e9dd4686b','頌古二十一首  其一四','釋居簡','宋','宋诗','song-poetry','','[]','爺頑頼，兒還債。',20,'全唐诗/poet.song.181000.json','["爺頑頼，兒還債。", "徹底老婆心，赤土涂牛奶。"]'),
('95d4d550-ff5d-45e5-91ef-c6893da76f5c','頌古二十一首  其一五','釋居簡','宋','宋诗','song-poetry','','[]','絕乳於菟弄爪牙，丹霞去後說丹霞。',32,'全唐诗/poet.song.181000.json','["絕乳於菟弄爪牙，丹霞去後說丹霞。", "棒頭有眼明如日，須是南陽老作家。"]'),
('c6365ee8-164b-4c75-9450-760547a51c42','頌古二十一首  其一六','釋居簡','宋','宋诗','song-poetry','','[]','隔江誰薦箭鋒機，直下橫趨已是遲。',32,'全唐诗/poet.song.181000.json','["隔江誰薦箭鋒機，直下橫趨已是遲。", "惆悵曲終人不見，數峰削玉水瀰瀰。"]'),
('1c2ca57f-1432-463a-b03c-028b60ef0672','頌古二十一首  其一七','釋居簡','宋','宋诗','song-poetry','','[]','三春不是讀書天，九夏炎炎且放禪。',32,'全唐诗/poet.song.181000.json','["三春不是讀書天，九夏炎炎且放禪。", "唯有秋冬較些子，不如打睡過殘年。"]'),
