('fbbe2795-9aaa-43ed-99d6-f14ecf98a81b','示如石上人','釋居簡','宋','宋诗','song-poetry','','[]','直須辦得身如石，一線開時石不如。',32,'全唐诗/poet.song.181000.json','["直須辦得身如石，一線開時石不如。", "自解點頭須自肯，待他人肯費分疎。"]'),
('e3ffc9a8-f949-485b-be50-23b0f9f78eb4','方上人上蔣山兼寄癡絕頑石','釋居簡','宋','宋诗','song-poetry','','[]','闢初錯向諸方求，那堪同來打爺州。',64,'全唐诗/poet.song.181000.json','["闢初錯向諸方求，那堪同來打爺州。", "只今又入鍾阜去，從錯至錯無時瘳。", "待欲商評者兩錯，只有知非無肯諾。", "癡叟頑翁舊同夢，知我從來無鼻孔。"]'),
('6405a0d3-07d8-4179-94c1-4a36a18396b2','出山相贊','釋居簡','宋','宋诗','song-poetry','','[]','脫屣金輪只等閑，六年癡坐碧孱顔。',32,'全唐诗/poet.song.181000.json','["脫屣金輪只等閑，六年癡坐碧孱顔。", "出山不了些兒事，何似當年莫入山。"]'),
('addcde92-1edc-4814-b2d5-735cf13f6907','常思惟大士贊  其一','釋居簡','宋','宋诗','song-poetry','','[]','瞪目諦觀時，風絲萬緒風。',24,'全唐诗/poet.song.181000.json','["瞪目諦觀時，風絲萬緒風。", "一聲潮雪響，打入正思惟。"]'),
('687f084f-b68c-4d3b-864e-5a3d5ca77b5c','常思惟大士贊  其二','釋居簡','宋','宋诗','song-poetry','','[]','海霧歛，山容開。',30,'全唐诗/poet.song.181000.json','["海霧歛，山容開。", "神珠在掌，明鏡當臺。", "普門無鎖鑰，俗客不曾來。"]'),
('028f609c-15e1-4164-aff6-561bdffa4061','常思惟大士贊  其三','釋居簡','宋','宋诗','song-poetry','','[]','聲成文，謂之音。',28,'全唐诗/poet.song.181000.json','["聲成文，謂之音。", "作如是觀，海底摸針。", "空王至今，悠悠我心。"]'),
('714bc8dc-8481-45a7-bc8b-1e582a05bd8e','常思惟大士贊  其四','釋居簡','宋','宋诗','song-poetry','','[]','趁隊選圓通，無端立下風。',24,'全唐诗/poet.song.181000.json','["趁隊選圓通，無端立下風。", "當時供死款，錯說在聞中。"]'),
('603fc47e-7461-4847-80dc-6b0fae6bee72','常思惟大士贊  其五','釋居簡','宋','宋诗','song-poetry','','[]','輪珠一百八，數了從頭數。',36,'全唐诗/poet.song.181000.json','["輪珠一百八，數了從頭數。", "念茲在茲，不知其數。", "自謂初於聞中，馿年入流亡所。"]'),
('9351f448-889f-4b4c-b9c4-744406417ff9','常思惟大士贊  其六','釋居簡','宋','宋诗','song-poetry','','[]','補陀月，龍眠筆。',34,'全唐诗/poet.song.181000.json','["補陀月，龍眠筆。", "筆有痕，月無蹟。", "蹟其迹，普門寂寂。", "迹既忘，四達皇皇。"]'),
('a5103824-db1a-49dc-8eac-aac38e38fc79','常思惟大士贊  其七','釋居簡','宋','宋诗','song-poetry','','[]','聲亦觀，色亦觀。',26,'全唐诗/poet.song.181000.json','["聲亦觀，色亦觀。", "空劫后，空劫前。", "風動塵起，山深水寒。"]'),
('7603ff24-eb8d-4bfb-8e11-b62d085ecbf4','常思惟大士贊  其八','釋居簡','宋','宋诗','song-poetry','','[]','萬竅不風，千波弗瀾。',32,'全唐诗/poet.song.181000.json','["萬竅不風，千波弗瀾。", "天低月高，山深水寒。", "普門無路入，終始不曾關。"]'),
('97b63fa6-b184-434a-b8ae-c071a9e8d353','常思惟大士贊  其九','釋居簡','宋','宋诗','song-poetry','','[]','從聞思修，錯了路頭。',32,'全唐诗/poet.song.181000.json','["從聞思修，錯了路頭。", "將錯就錯，隨流入流。", "補陀山鬼窟，海月半輪秋。"]'),
('803e3022-5f8d-4946-9090-b5329f7f1984','常思惟大士贊  其一○','釋居簡','宋','宋诗','song-poetry','','[]','從聞思修，入三摩地。',36,'全唐诗/poet.song.181000.json','["從聞思修，入三摩地。", "動靜二相，了然不生。", "補陀小白花山上，弗聽流鶑啼一聲。"]'),
('13a8ea52-bb03-4c6e-8125-251de878a28e','常思惟大士贊  其一一','釋居簡','宋','宋诗','song-poetry','','[]','籃盛魚，不盛水。',26,'全唐诗/poet.song.181000.json','["籃盛魚，不盛水。", "弗自噇，提入市。", "秤子無星，鈎頭有餌。"]'),
('2843967c-6d68-4810-854c-4d11f033ca00','常思惟大士贊  其一二','釋居簡','宋','宋诗','song-poetry','','[]','爲散亂人，現如是相。',40,'全唐诗/poet.song.181000.json','["爲散亂人，現如是相。", "方其定時，孰爲此像。", "定亂一如，此像亦無。", "若言無像，天地懸隔。"]'),
('b5575191-13e8-44b1-a5d8-b1a6f6aa9275','布袋贊  其一','釋居簡','宋','宋诗','song-poetry','','[]','赤脚纔穿市，回頭便笑人。',44,'全唐诗/poet.song.181000.json','["赤脚纔穿市，回頭便笑人。", "手中果何物，弄物不知名。", "閉眼瞌睡，開眼業識。", "便恁麽去，著甚死急。"]'),
('5081c0eb-e09f-435c-9fea-cdb2f0647c4c','布袋贊  其二','釋居簡','宋','宋诗','song-poetry','','[]','背後曾開鬼眼睛，雖然有眼又無筋。',32,'全唐诗/poet.song.181000.json','["背後曾開鬼眼睛，雖然有眼又無筋。", "問他覩史宮中事，拈得乾魚舉似人。"]'),
('c8d340f9-95a5-4d43-adb6-8f1551571e7b','布袋贊  其三','釋居簡','宋','宋诗','song-poetry','','[]','笑破古音前，回頭儘可憐。',44,'全唐诗/poet.song.181000.json','["笑破古音前，回頭儘可憐。", "只今無可笑，仰面笑青天。", "赤脚知晴，躡屐知雨。", "只這一著，未敢相許。"]'),
('2d1fd16f-6f8a-4a7f-9ae3-28a382e42a59','布袋贊  其四','釋居簡','宋','宋诗','song-poetry','','[]','魚乾拈起走長街，道是天宮带得來。',32,'全唐诗/poet.song.181000.json','["魚乾拈起走長街，道是天宮带得來。", "鐵奉化人頑似鐵，阿師咍了更誰咍。"]'),
('327aedd2-dce4-499b-8384-2fa3d151af76','布袋贊  其五','釋居簡','宋','宋诗','song-poetry','','[]','正續無名，散聖無位。',20,'全唐诗/poet.song.181000.json','["正續無名，散聖無位。", "秦漢不收，慚愧慚愧。"]'),
('9007fe4a-cd8f-4ff3-a2e3-ef90e6a97efb','布袋贊  其六','釋居簡','宋','宋诗','song-poetry','','[]','天上無，地下無。',30,'全唐诗/poet.song.181000.json','["天上無，地下無。", "只這無無，已自涂胡。", "區區更回首，轉見費分疎。"]'),
('cf9ab580-5b73-4809-9872-ba45a97ca019','問疾維摩贊','釋居簡','宋','宋诗','song-poetry','','[]','賣弄瀾翻舌，文殊是阿誰。',24,'全唐诗/poet.song.181000.json','["賣弄瀾翻舌，文殊是阿誰。", "未曾談不二，已自落思惟。"]'),
('a57d6e33-80db-4e02-b00d-683da35b97df','須菩提贊','釋居簡','宋','宋诗','song-poetry','','[]','洗足已，便趺坐。',24,'全唐诗/poet.song.181000.json','["洗足已，便趺坐。", "突然道希有世尊，你當時見箇什麽。"]'),
('e1c7d138-a5d9-4e86-a246-607392e288c3','寒山贊','釋居簡','宋','宋诗','song-poetry','','[]','寒山指出，拾得執指。',20,'全唐诗/poet.song.181000.json','["寒山指出，拾得執指。", "不曾見月，矮子看戲。"]'),
('4bfac61e-155e-4dcb-903c-dcf7d75ad603','草衣文殊贊','釋居簡','宋','宋诗','song-poetry','','[]','衣紉草，髮如草。',42,'全唐诗/poet.song.181000.json','["衣紉草，髮如草。", "未下五臺，百怪俱兆。", "手中經，義不了。", "我且問你，前三三後三三，是多少。"]'),
('cf77bfc3-5e18-45cc-99ee-cc8a3385b433','馬郎婦贊','釋居簡','宋','宋诗','song-poetry','','[]','念得蓮經便嫁伊，空花無蒂欲誰欺。',32,'全唐诗/poet.song.181000.json','["念得蓮經便嫁伊，空花無蒂欲誰欺。", "金沙灘上黄金鎖，狼藉春風到幾時。"]'),
('208fcf91-93f7-4ee2-ab89-e70606371624','靈照女贊','釋居簡','宋','宋诗','song-poetry','','[]','屋裏橫機抗老爺，門前歛袂對丹霞。',32,'全唐诗/poet.song.181000.json','["屋裏橫機抗老爺，門前歛袂對丹霞。", "爺生娘養好兒女，有得許多無頼吒。"]'),
('6d91ca25-adf0-4150-a0b6-a3858a440f6e','穿破衲贊','釋居簡','宋','宋诗','song-poetry','','[]','針短線難穿，閑拈當負暄。',24,'全唐诗/poet.song.181000.json','["針短線難穿，閑拈當負暄。", "不須嫌破碎，提起自完全。"]'),
('4863c320-8003-43b5-9306-0b5d40f2ea0b','了殘經贊','釋居簡','宋','宋诗','song-poetry','','[]','從朝數黑豆，數到黄昏後。',24,'全唐诗/poet.song.181000.json','["從朝數黑豆，數到黄昏後。", "只見月如眉，不覺靈犀透。"]'),
('48410e54-237e-4364-be31-3736cbae5e2a','初祖贊','釋居簡','宋','宋诗','song-poetry','','[]','五葉芬敷自一花，無人圖蔓剪根牙。',32,'全唐诗/poet.song.181000.json','["五葉芬敷自一花，無人圖蔓剪根牙。", "不教著脚金陵地，猶恨蕭梁未作家。"]'),
('7690c2c0-45ce-4e77-9010-7e7af970094c','爲癡絕和尚贊初祖達磨并馬大師畫象  其一','釋居簡','宋','宋诗','song-poetry','','[]','穿耳耳未嘗穴，缺齒齒未嘗折。',135,'全唐诗/poet.song.181000.json','["穿耳耳未嘗穴，缺齒齒未嘗折。", "北度一葦可航，西歸隻履自挈。", "或謂之空劫已前中流砥柱，或謂之拈花已後金口木舌。", "或曰正宗別調，又曰直指曲說，皆非吾之所謂道也。", "若夫求大乘器，走十萬里，俟人作興，器豈大乘。", "夙負先覺，禮聞來學。", "學而知之，既遠且邈。", "負是四者，吾恐五竺之鐵不足鑄此錯也。"]'),
('77d7ffd1-6a4a-4a15-a7ef-86cfc9ae4e76','爲癡絕和尚贊初祖達磨并馬大師畫象  其二','釋居簡','宋','宋诗','song-poetry','','[]','金鷄毒，一粒粟，未踏殺人，已先跌足。',95,'全唐诗/poet.song.181000.json','["金鷄毒，一粒粟，未踏殺人，已先跌足。", "一十八灘兮障回死水，八十四人兮淹浸弗死。", "洪都兮泐潭，宗風兮肆凌厲。", "一波動兮萬波起，派兮支兮滔滔者皆是。", "更無一箇識玄旨，只有歸宗較些子。", "撿點將來，玄沙道底。"]'),
('bfc59e27-c50c-4d28-9646-61aba9246707','普化贊','釋居簡','宋','宋诗','song-poetry','','[]','風顛用盡到無餘，一箇棺材八箇舁。',32,'全唐诗/poet.song.181000.json','["風顛用盡到無餘，一箇棺材八箇舁。", "舁出鎮州城外去，聽他木鐸自分疎。"]'),
('95a3aef3-b994-42e5-ab37-b89c69431cc6','趙州贊','釋居簡','宋','宋诗','song-poetry','','[]','禪在口皮邊，機攙石火先。',44,'全唐诗/poet.song.181000.json','["禪在口皮邊，機攙石火先。", "破家纔十八，更不使爺錢。", "東南西北，門開兩邊。", "相見了也，十萬八千。"]'),
('8778f837-31f9-405a-be52-93f4a672d385','臨濟贊','釋居簡','宋','宋诗','song-poetry','','[]','白拈賊，是這廝。',62,'全唐诗/poet.song.181000.json','["白拈賊，是這廝。", "捋鬼頭巾，假我服色。", "胡蘆立地便要沈，秤鎚落井不教沒。", "脫間漏架，天下第一。", "自謂建立黄蘗宗旨，不知黄蘗無處雪屈。"]'),
('5ba6222b-4653-467b-8138-5f776ff56a04','楊岐贊','釋居簡','宋','宋诗','song-poetry','','[]','請慈明晚參，對白雪大笑。',52,'全唐诗/poet.song.181000.json','["請慈明晚參，對白雪大笑。", "爲父不慈，爲子不孝。", "箇般駔𩦱行藏，敢稱瞎馿種草。", "爭怪人言不解禪，熨斗煎茶不同銚。"]'),
('57ebc8a8-7c4f-432e-b975-a9f7224976c2','爲癡絕和尚贊三睡','釋居簡','宋','宋诗','song-poetry','','[]','贊也喜，罵也喜。',26,'全唐诗/poet.song.181000.json','["贊也喜，罵也喜。", "醒也睡，困也睡。", "善男子起，法性如是。"]'),
('2164f488-347b-4dd5-9368-c1587ee6a63a','東山贊','釋居簡','宋','宋诗','song-poetry','','[]','棚入囉扎，君子可入。',48,'全唐诗/poet.song.181000.json','["棚入囉扎，君子可入。", "附子同鄉一樣辣，酸餡嚼破一團鐵。", "餡子一句，未敢相許。", "弗是沒人情，箇中無肯路。"]'),
('3d4fa6c9-56c8-4159-85da-d10b0c67b71e','永明壽禪師贊','釋居簡','宋','宋诗','song-poetry','','[]','客吟燈殘，猿啼月落。',95,'全唐诗/poet.song.181000.json','["客吟燈殘，猿啼月落。", "衲帔蒙頭，千岩萬壑。", "指破凡夫，爲等覺妙覺。", "齊大小乘，於錢索井索。", "縱大辯於談笑，寄虛懷於冥莫。", "所謂百軸宗鏡之文，如太山之一毫芒。", "巍巍堂堂，煒煒煌煌。", "非心亦非佛，破鏡不重光。"]'),
('754ff336-0811-457a-adf9-baa5382da968','大慧師祖贊','釋居簡','宋','宋诗','song-poetry','','[]','馽空雲带，補太虛縫。',113,'全唐诗/poet.song.181000.json','["馽空雲带，補太虛縫。", "祕以自傳，公與衆共。", "卷覆大千舌於洋嶼雲門，不與摩竭同條。", "袖擲大千手於梅州衡陽，不與浄名同夢。", "至於三藏十二部，一切修多羅，洎百家異氏之書，雜然前陳，無斷無滅，有元有統。", "瞥轉一機，五峰歛眉。", "伎倆盡也，放下竹篦。"]'),
('2f7c24c1-06fe-4c0f-9504-8ab2cabbb3b7','智者大師贊','釋居簡','宋','宋诗','song-poetry','','["\u8861\u5c71"]','寶几在前，如意在手。',52,'全唐诗/poet.song.181000.json','["寶几在前，如意在手。", "禹背湯肩，河目海口。", "南嶽山中得聖師，投針鉢水了無疑。", "法華同聽真精進，直到靈山未散時。"]'),
('b4d9ff1f-2933-4551-adbc-6a869f191b29','密庵贊','釋居簡','宋','宋诗','song-poetry','','[]','正法眼，曰破沙盆，曰漏燈盞。',57,'全唐诗/poet.song.181000.json','["正法眼，曰破沙盆，曰漏燈盞。", "兩段不殊，一倍相反。", "鈍置雲黄山下老禪魔，匙挑不上，罪不重科。", "但未知虛空消殞，畢竟如何。"]'),
('8c2db493-43ed-42cf-9bb3-8908a78af42c','拙庵贊','釋居簡','宋','宋诗','song-poetry','','[]','讀旁行，倚松立。',24,'全唐诗/poet.song.181000.json','["讀旁行，倚松立。", "義不精，字不識。", "海湧雲興追不及。"]'),
('2712f6a7-626e-453f-8094-70dfc996494f','自贊  其一','釋居簡','宋','宋诗','song-poetry','','[]','幼而不遜，長而無述，老而不死。',32,'全唐诗/poet.song.181000.json','["幼而不遜，長而無述，老而不死。", "賊賊。", "臨濟未是白拈，自出洞來無敵。"]'),
('97c571ab-f60f-4063-9932-1f4dea00cf34','自贊  其二','釋居簡','宋','宋诗','song-poetry','','[]','字不識，禪不會，數米量柴，料水打碓。',56,'全唐诗/poet.song.181000.json','["字不識，禪不會，數米量柴，料水打碓。", "不是末後全提，亦非現前三昧。", "待衆生成佛，盡衆生界空，任從滄海變，終不爲君通。"]'),
('883fef29-9406-4d05-b37e-c2ed1c280101','題慈觀長老求贊','釋居簡','宋','宋诗','song-poetry','','[]','監本倔强，弗善勞謙。',74,'全唐诗/poet.song.181000.json','["監本倔强，弗善勞謙。", "不識拙庵，他最不堪。", "他亦人耳，我亦人耳。", "空自合空，水自合水。", "賣弄跨門一機，至死無人發市。", "父有重牙，其子無齒。", "沒齒穿齦，如是如是。"]'),
('9ec56e32-edb9-48dd-9e3d-ce2d0bef2ccc','小師求贊  其一','釋居簡','宋','宋诗','song-poetry','','[]','平常心，摩竭合。',36,'全唐诗/poet.song.181000.json','["平常心，摩竭合。", "砥柱不摇，風雷不迅。", "拈了也，示祖敬。", "無法商量，一印印定。"]'),
('90341bc2-2ef8-4821-b562-41b35028bfdb','小師求贊  其二','釋居簡','宋','宋诗','song-poetry','','[]','不會道，不會禪。',26,'全唐诗/poet.song.181000.json','["不會道，不會禪。", "更求文墨，掘地覓天。", "別調宮商妙不傳。"]'),
('bc88975f-b605-4f71-9c38-16207e674241','檀木白衣相贊','釋居簡','宋','宋诗','song-poetry','','[]','斤斯運，堊斯斲。',116,'全唐诗/poet.song.181000.json','["斤斯運，堊斯斲。", "鼻不傷，立自若。", "臻極之技，與物不二。", "惟其不然，一理萬致。", "我觀此像，殆非人爲。", "就能爲之，技不宅微。", "矧此匠氏，應以此機。", "應以此身，化巧幻奇。", "曰余眊然，兩眼如鏡。", "弗能審觀，獨以耳聽。", "反聽絕眹，對此殊勝。", "小白花山，下瞰巨浸。"]'),
('333b9e93-f7b8-4a37-a007-7ad8f13292ad','慈感圭老請贊無量壽像','釋居簡','宋','宋诗','song-poetry','','[]','十方取土，曰清泰城。',240,'全唐诗/poet.song.181000.json','["十方取土，曰清泰城。", "又曰極樂，與苦濁鄰。", "厭苦知樂，不毫忽間。", "一念勇往，即念而瞷。", "惟憶惟念，匪疾匪遲。", "憶而不忘，念茲在茲。", "如求亡子，如喪考妣。", "如疢需石，如渴需水。", "以如是故，曾何遠人。", "人人亡羊，入生死輪。", "法法惟心，心亦非心。", "鄭衛嘈雜，水鳥樹林。", "悠悠漸修，頟頟闡提。", "同攝罔遺，妙在不疑。", "疑則疑城，日劫倍蓰。", "東隅既失，桑榆可冀。", "粵若二仲，達圓頓機。", "路壅般舟，手自剪夷。", "池栽芬陁，社結名勝。", "一十有八，是修是証。", "天台嗣響，的傳自衡。", "和者如雲，調高倡宏。", "六朝逮今，衣冠緇褐。", "愚夫愚婦，爰同此筏。"]'),
('08df0eb8-028a-4b5f-97f3-d6c2770ec580','天樂趙紫芝畫像贊','釋居簡','宋','宋诗','song-poetry','','[]','一點虛明，八窗玲瓏。',78,'全唐诗/poet.song.181000.json','["一點虛明，八窗玲瓏。", "萬波不渾，百川自東。", "殆見其灑然乎外，孰知其淵乎其中。", "謂其襄陽漫仕，曰吾不爲南宮。", "謂其江湖散人，曰吾不爲龜蒙。", "烏在乎儀刑，先進而丹青太空。"]'),
('b6a87749-0f4d-43ce-98ae-bf6efe91f447','東坡畫像贊','釋居簡','宋','宋诗','song-poetry','','[]','帝哀先生，爲天下忌。',120,'全唐诗/poet.song.181000.json','["帝哀先生，爲天下忌。", "速反其轅，卒不憖遺。", "遂騎箕尾，而分天章。", "雲漢昭回，衣被八荒。", "載驅六丁，收拾文字。", "神京遐陬，旁羅曲致。", "落人間者，太山毫芒。", "寒者綺紈，餒者稻粱。", "取彼譖人，投畀豺虎。", "既粱其餼，而紈其袴。", "豢以人爵，俾敏厥修。", "息公之譖，承天之休。"]'),
('58efe763-e982-4493-94c0-b52fd77b3f61','二桃殺三士贊','釋居簡','宋','宋诗','song-poetry','','[]','大匠不棄櫟社之木，良醫不遺烏喙之毒。',158,'全唐诗/poet.song.181000.json','["大匠不棄櫟社之木，良醫不遺烏喙之毒。", "務急吾用，不一而足。", "苟適其時，雖棄必錄。", "方其用時，有正有奇。", "顛兮吾扶，危兮吾持。", "相道巍巍，二氏似之。", "哂乃齊相，曾不爾思。", "夫三子者，謬以力勝。", "勝力以德，孰敢不敬。", "徒喪厥德，以致其命。", "一念之忍，桃乃其穽。", "欲濟緩急，圖任媕娿。", "爪牙不銛，其如之何。", "盍觀相如，伸秦屈頗。", "隠然長城，無庸干戈。"]'),
('6b52db11-c669-4054-b7aa-bb66c80ae91c','三教贊','釋居簡','宋','宋诗','song-poetry','','[]','此三勝流，一笑聚頭。',80,'全唐诗/poet.song.181000.json','["此三勝流，一笑聚頭。", "其道不同，曷相爲謀。", "至哉儒先，問禮於李。", "李從竺乾，逮真實際。", "商隠於李，白眉最良。", "曰師師師，其來自唐。", "車適大方，萬里一轍。", "差之毫釐，肝膽楚越。"]'),
('57b396d0-7f9f-4d24-bc7b-0fc34ef41759','孤雲畫像贊','釋居簡','宋','宋诗','song-poetry','','[]','閒如雲，寄寥邈。',62,'全唐诗/poet.song.181000.json','["閒如雲，寄寥邈。", "帖水不痕，行空無脚。", "笑從上掃跡生跡，嗟後來以縛解縛。", "於其中間，卷舒自若。", "釘釘却，懸挂却。", "老倒南陽，猶欠一著。"]'),
('ebd5f701-59a4-46bf-b8f4-d9bbf1bba3ed','下竺印畫像贊','釋居簡','宋','宋诗','song-poetry','','[]','窣然短衣，嶄然插犀。',74,'全唐诗/poet.song.181000.json','["窣然短衣，嶄然插犀。", "歲晚寂莫，奮此一夔。", "膠名相求之，則萬言不直杯水。", "外形骸索之，則半芋美於紫泥。", "憲章左谿，鼓吹荆谿。", "使人復見古道顔色，舍斯人其誰歸。"]'),
('1c96f43d-f509-4162-9e2c-0dc977a93ee2','明教禪師五種不壞贊  其一','釋居簡','宋','宋诗','song-poetry','','[]','頂骨嶢然，隠若伏犀。',80,'全唐诗/poet.song.181000.json','["頂骨嶢然，隠若伏犀。", "於烈火中，凄其廩而。", "古鐵錚錚，燼餘不熱。", "擊石拊石，迭中音節。", "舍利團綴，素魄冏如。", "湛湛凝露，累累貫珠。", "豈無他人，欲見其頂。", "月行太空，蛙沉坎井。"]'),
('77c80fcd-2674-4e6c-b8be-0f143046a1ab','明教禪師五種不壞贊  其二','釋居簡','宋','宋诗','song-poetry','','[]','去窒而聰，去塞而通。',80,'全唐诗/poet.song.181000.json','["去窒而聰，去塞而通。", "於無數聲，齊萬竅風。", "風止聲消，音響寂絕。", "谷神不死，聽火焰說。", "說無所說，聞無所聞。", "烟滅灰飛，所亡者存。", "以是耳根，示爾四衆。", "厚德宏功，千二百種。"]'),
('5c9eade8-126f-4657-9d8c-acc3dba07a6b','明教禪師五種不壞贊  其三','釋居簡','宋','宋诗','song-poetry','','[]','宣明心聲，若出金石。',80,'全唐诗/poet.song.181000.json','["宣明心聲，若出金石。", "洶湧辯河，不滲涓滴。", "書獻天子，天顔屢改。", "一笑歸來，此舌猶在。", "韓吾不非，吾奚以爲。", "壅吾不夷，吾奚以馳。", "一生事了，有死無憾。", "身隨劫燒，紅開菡萏。"]'),
('c88775b6-dd42-43c0-bc18-940d30f044c3','明教禪師五種不壞贊  其四','釋居簡','宋','宋诗','song-poetry','','[]','童真出家，死於童真。',80,'全唐诗/poet.song.181000.json','["童真出家，死於童真。", "出沒卷舒，一堅密身。", "嗟多欲人，曲爲欲說。", "於其根中，出火自焫。", "猗歟哲人，哂乃覆轍。", "以古爲鑑，以身代舌。", "火炎昆岡，玉石俱焚。", "石付百粉，玉兮溫溫。"]'),
('33328240-b23b-462e-836f-cc9bdbe8dc5f','明教禪師五種不壞贊  其五','釋居簡','宋','宋诗','song-poetry','','[]','的的紫槵，茸茸素絲。',80,'全唐诗/poet.song.181000.json','["的的紫槵，茸茸素絲。", "自幼至老，念茲在茲。", "譬夫一龕，繞以十鏡。", "此燈長明，一印印定。", "定則離念，反而自求。", "於無求中，以敏厥修。", "物初有終，法無有盡。", "是故此珠，橫絕煨燼。"]'),
('82b5a683-4349-4863-a11c-22ae1dc82062','賢者國師贊','釋居簡','宋','宋诗','song-poetry','','[]','心部根本，身嚴雜華。',81,'全唐诗/poet.song.181000.json','["心部根本，身嚴雜華。", "赤象青牛，跨竺越華。", "半滿字則，五其等差。", "殊聲響則，一其紛拏。", "使登門之魚，駕際天之濤。", "陋潢汙行潦，而觀海若之谽谺。", "瑣屑滅裂，又安知鰋鯉之與鱨魦。"]'),
('1eab2ca0-65ef-4b90-9d5b-6d72634fa147','强齋高使君金書諸經贊','釋居簡','宋','宋诗','song-poetry','','[]','淀藍蘸楮，屑金作字。',140,'全唐诗/poet.song.181000.json','["淀藍蘸楮，屑金作字。", "去字與楮，經果何似。", "曰此諸經，即楮與金。", "續父厥志，寫佛語心。", "惟佛語心，粵如父志。", "一點畫中，具無量義。", "字可悉數，義則無量。", "欲了其源，冥去來相。", "强齋大士，年八十餘。", "目如心明，作蠅頭書。", "於一蠅頭，分可爲二。", "塵毛太華，弗巨弗細。", "佛神力故，初不作難。", "是故北磵，作如是觀。"]'),
('753594ad-ff59-4873-9677-e5778aa2bba3','兩蟆贊  其一','釋居簡','宋','宋诗','song-poetry','','[]','攫而擲，翾而舉之。',30,'全唐诗/poet.song.181000.json','["攫而擲，翾而舉之。", "二蟲請以戰喻。", "翾毋忘於射鈎，攫毋忘於在莒。"]'),
('ca43dd9c-f1fc-4683-bd8a-313aaace5a76','兩蟆贊  其二','釋居簡','宋','宋诗','song-poetry','','[]','蟻戰酣，蟆襲其後，非大嚼盍反相友。',29,'全唐诗/poet.song.181000.json','["蟻戰酣，蟆襲其後，非大嚼盍反相友。", "夢好忽同歸，一麾何足疑。"]'),
('a841753d-8b00-4c9d-a66c-89a4386c8c81','荷屋常不輕畫像贊','釋居簡','宋','宋诗','song-poetry','','[]','芰荷爲屋，芙蓉爲裳。',101,'全唐诗/poet.song.181000.json','["芰荷爲屋，芙蓉爲裳。", "芳茝紉佩，落英貯粻。", "熏以石林，書傳之香。", "瀹以太華，玉井之凉。", "濯人間烟火氣，毋干吾丘壑姿。", "洎夫錦心之與綉腸，發卍菴之韜畧，示我武之維揚。", "適妙喜國拓吾故疆。", "安在乎廣莫之野，而無何有之鄉。"]'),
('4356b926-7b13-4d33-8867-5767df453d25','義鑑堂畫像贊','釋居簡','宋','宋诗','song-poetry','','[]','魁梧軒昂，耿介孤潔。',70,'全唐诗/poet.song.181000.json','["魁梧軒昂，耿介孤潔。", "大珠縞夜，輕雲拂月。", "作成潑天問端來前，只似釘頭難于敲折。", "東山發源，雙峰卷衣。", "把大蘇狂瀾，障而東之。", "微此老孫子，已而已而。"]'),
('0e6b0e3d-c58e-40f0-9651-2d5507847741','高麗指堂講師畫像贊','釋居簡','宋','宋诗','song-poetry','','[]','巖巖指堂，破塵出經。',68,'全唐诗/poet.song.181000.json','["巖巖指堂，破塵出經。", "惟其能然，曰聰慧人。", "隄圓頓之頹瀾，會中下於通津。", "橫說豎說，匪虧匪盈。", "全提半提，匪壞匪成。", "夫是之謂全體之用兮全體之真。"]'),
('cf40be6f-6b63-4ead-a03e-373cdf2fcac7','妙湛禪師月巖舍利贊','釋居簡','宋','宋诗','song-poetry','','[]','及笄洗粧，一花一香。',100,'全唐诗/poet.song.181000.json','["及笄洗粧，一花一香。", "舍父求度，回度厥父。", "父子學空，機先有鋒。", "父死開法，鏌鎁出匣。", "歸奉其母，孤山之滸。", "示生有滅，笑與母訣。", "火後舍利，粲如繁星。", "如金之晶，如玉之明。", "堂堂月巖，如空行月。", "何庸留此，自暴醜拙。"]'),
('a8dcee89-864e-4a35-8415-8676ff14a302','下天竺古鏡法師畫像贊','釋居簡','宋','宋诗','song-poetry','','[]','伽黎擁肩，不舍夜旦。',106,'全唐诗/poet.song.181000.json','["伽黎擁肩，不舍夜旦。", "革履梏足，炎熇不跣。", "迹邇世相，而不動不退。", "心惟玄奧，則唯止唯觀。", "四辯湧兮瀾翻，四筵擁兮冰泮。", "特旨住山，靈山未散。", "洗舊講榻，萎花新換。", "至於戒香逆風，騰播林野。", "吾嘗比之波利質多羅天樹花，此之謂也。"]'),
('816ae50c-21fd-4c5f-98a6-5102ab6c43e6','陶司戶畫像','釋居簡','宋','宋诗','song-poetry','','[]','宅塵滓拔千丈之俗，倚梅竹託三友之交。',58,'全唐诗/poet.song.181000.json','["宅塵滓拔千丈之俗，倚梅竹託三友之交。", "稠人廣座則惟靜惟默，涼天佳月則或推或敲。", "問津榮途，姑欲行志。", "於志得時，反求諸己。"]'),
('7505f68e-6671-4b39-b9f4-2b6e54ea8187','自題頂相','釋居簡','宋','宋诗','song-poetry','','[]','謂有爲，吾奚爲。',39,'全唐诗/poet.song.181000.json','["謂有爲，吾奚爲。", "謂無爲，吾奚不爲。", "待悟而勇爲，絕學而無爲。", "於戲盡之矣，非吾爲。"]'),
('d5ed83c7-3294-497c-8f5c-2eb2d3e262db','王梁山畫像贊','釋居簡','宋','宋诗','song-poetry','','[]','從事毛錐，壯夫不爲。',120,'全唐诗/poet.song.181000.json','["從事毛錐，壯夫不爲。", "置書學劍，弓號馬嘶。", "不斬樓蘭，夫何自欺。", "堂堂梁山，襟利带夔。", "帝軫遐方，詳延瑰琦。", "良馬素絲，組以五之。", "維賢作牧，任以撫綏。", "撫綏伊何，恩斯勤斯。", "豈惟懷恩，亦復畏威。", "庶靖氛埃，以偃鼓鼙。", "昔人可師，感夜半雞。", "哂乃阿瞞，橫槊賦詩。"]'),
('dc9f6480-23f8-4331-981f-b959befb8ad6','台宗傑首座畫像贊','釋居簡','宋','宋诗','song-poetry','','[]','性具染指，鼎味咸在。',68,'全唐诗/poet.song.181000.json','["性具染指，鼎味咸在。", "容膝歸休，日用三昧。", "不動口，不饒舌。", "人無聞聞，吾無說說。", "翻嗟普眼，弗見普賢。", "爲渠去却，眼中金屑。", "複道行空，白銀爲闕。"]'),
('05ef2007-c229-4939-abee-543abeb85e94','野月贊','釋居簡','宋','宋诗','song-poetry','','[]','廣寒殿，洪崖井。',42,'全唐诗/poet.song.181000.json','["廣寒殿，洪崖井。", "輪有晦朔，景無畦畛。", "悠然隨所寓，婆娑弄清影。", "莫羨江樓清，江樓塵汙人。"]'),
('15e48e0e-677c-4d5e-97ee-cf40bb18de9d','頌古五首  其一','釋居簡','宋','宋诗','song-poetry','','[]','轉得頭來已是遲，恰如曾未轉頭時。',32,'全唐诗/poet.song.181000.json','["轉得頭來已是遲，恰如曾未轉頭時。", "一錢覓得無及處，猶自區區誑阿誰。"]'),
('6464abb1-c39f-4815-83c9-e6ae62c63bcc','頌古五首  其二','釋居簡','宋','宋诗','song-poetry','','[]','五十三人一縷穿，小兒雖小膽如天。',32,'全唐诗/poet.song.181000.json','["五十三人一縷穿，小兒雖小膽如天。", "茫茫煙水無重數，買得風光不用錢。"]'),
('837287b4-c024-4722-b51a-3dfd5640a75f','頌古五首  其三','釋居簡','宋','宋诗','song-poetry','','[]','一字未曾談般若，謾天謾地儘饒伊。',32,'全唐诗/poet.song.181000.json','["一字未曾談般若，謾天謾地儘饒伊。", "祇園乞食歸來後，法會因由又是誰。"]'),
('b2158162-0073-4348-af73-0e2d13660f4b','頌古五首  其四','釋居簡','宋','宋诗','song-poetry','','[]','劍下十分真，難藏獨露身。',24,'全唐诗/poet.song.181000.json','["劍下十分真，難藏獨露身。", "江流石不轉，獨有藴空名。"]'),
('2bba8cff-78a3-42a0-9132-2da5dd675f4b','頌古五首  其五','釋居簡','宋','宋诗','song-poetry','','[]','進步竿頭踏斷橋，太虛凸處水天凹。',32,'全唐诗/poet.song.181000.json','["進步竿頭踏斷橋，太虛凸處水天凹。", "古今喫𨈀知多少，不似闍黎這一交。"]'),
('a14c1435-dfb2-4c82-ba1e-92638abcb3ad','應真贊三首  其一','釋居簡','宋','宋诗','song-poetry','','[]','傳的的之宗自舉，冰壺春未回而痕垢無些，玉林月已上而清光有許。',88,'全唐诗/poet.song.181000.json','["傳的的之宗自舉，冰壺春未回而痕垢無些，玉林月已上而清光有許。", "湛存此箇宗乘，肯壞人家男女。", "黄梅之鉢笑夜偷，少室之衣疑浪與。", "方徹地區，圓該天宇。", "神發幽而空谷應呼，聲出礙而霜鐘忽杵。"]'),
('c1a38eef-b385-4f27-bad9-1cd6e6c42cee','應真贊三首  其二','釋居簡','宋','宋诗','song-poetry','','[]','面目古怪，氣宇深清。',50,'全唐诗/poet.song.181000.json','["面目古怪，氣宇深清。", "澗月夜白，松雪寒明。", "舜巖之身兮誰前誰後，首蘿之眼兮不縱不橫。", "相隨來也，流水浮萍。"]'),
('9f0d1733-4988-48b3-973a-eb4992798506','應真贊三首  其三','釋居簡','宋','宋诗','song-poetry','','[]','全心之相，全相之心。',56,'全唐诗/poet.song.181000.json','["全心之相，全相之心。", "寫成這个，聊應而今。", "天蒼蒼兮白鳥沒，水深深兮紅鱗沉。", "日鈎雲餌，玉線金針。", "一般料理兮妙出威音。"]'),
('388a65d7-4573-431c-bb09-b34ec0370ec6','句','釋居簡','宋','宋诗','song-poetry','','[]','漁翁不耐寒，重沓著蓑衣。',12,'全唐诗/poet.song.181000.json','["漁翁不耐寒，重沓著蓑衣。"]'),
('f1dc7dc1-9561-4b7b-ad9e-ea9ac32bd768','聞兄茂欽靖節蘄州報','李大同','宋','宋诗','song-poetry','','[]','狼烽遞驛浩茫茫，遂以孤城爲國亡。',64,'全唐诗/poet.song.181000.json','["狼烽遞驛浩茫茫，遂以孤城爲國亡。", "骨肉空教撐遠目，貔貅何自□巖疆。", "飛纓慘絕羈南越，寶劍誰能借上方。", "揮淚汨羅招不得，惱人風雨舊池塘。"]'),
('18903bc6-95a3-46e6-bc7d-11b777cfcb74','白澤荷花','李大同','宋','宋诗','song-poetry','','[]','故老相傳白澤湖，旌陽一濯潔難污。',32,'全唐诗/poet.song.181000.json','["故老相傳白澤湖，旌陽一濯潔難污。", "只今尚見荷花在，未識神仙更有無。"]'),
('d72692ca-f345-4bf4-ab62-3b08559ece5e','蔡謨公歸田贈別','李大同','宋','宋诗','song-poetry','','[]','法持三尺弼皇堯，盛德英風滿市朝。',64,'全唐诗/poet.song.181000.json','["法持三尺弼皇堯，盛德英風滿市朝。", "千里關山思召伯，十年海內重臯陶。", "遨遊上界星辰近，出入中天雨露饒。", "何用燒燈歌法活，只須洗耳聽鳴韶。"]'),
('6ef55b55-bc05-47aa-a406-ffae9838a8f7','壽曾撙齋七十八','尹直卿','宋','宋诗','song-poetry','','[]','先生雖老正康强，紫綬金魚兩鬢霜。',64,'全唐诗/poet.song.181000.json','["先生雖老正康强，紫綬金魚兩鬢霜。", "椿幹豈因更節健，松江自飲菊潭香。", "方過一百官省歲，尚有八千年壽長。", "徼福定從句漏令，丹砂問了却分嘗。"]'),
('abe1d721-8f98-4f02-91c9-c0862a8b4bf7','送錢文季赴班','尹直卿','宋','宋诗','song-poetry','','[]','鰲頭那久幕蓮間，國子先生促趁班。',64,'全唐诗/poet.song.181000.json','["鰲頭那久幕蓮間，國子先生促趁班。", "元自胸中有奇觀，須教集裏富江山。", "三年再見雖成別，正月諸生亦入關。", "爲賦江空歲年晚，功名惟恐鬢毛斑。"]'),
('9fe5fd67-6626-43f5-abba-8a01aec1f2f2','賀曾幼張中漕舉','尹直卿','宋','宋诗','song-poetry','','[]','官樣文章曾靖州，計臺一鶚再橫秋。',64,'全唐诗/poet.song.181000.json','["官樣文章曾靖州，計臺一鶚再橫秋。", "雖爲竹使年殊少，要續荷囊意未休。", "丹陛行尋螭陛舊，清香仍裛桂香浮。", "二千石掃三千字，千載江西作話頭。"]'),
('aa193dc1-a1db-4e21-9a49-8287ea4b085c','壽俞尚書七十九','尹直卿','宋','宋诗','song-poetry','','[]','后皇深助順，命世燁生賢。',144,'全唐诗/poet.song.181000.json','["后皇深助順，命世燁生賢。", "臨汝葱佳氣，羅浮降散仙。", "春蘭早無對，秋竹晚彌堅。", "穩擊三千水，高騰尺五天。", "清癯迂叟侶，溫厚醉翁然。", "獻納星辰上，司存雨露邊。", "常情難勇退，定力竟孤騫。", "此夕尋常夕，明年八十年。", "金猴轉空柄，璿象燦丁躔。", "中令汾陽考，平章潞國權。", "龍鍾笑裴度，矍鑠過文淵。", "陰陽無盡藏，真源不老仙。"]'),
('e1bb9b32-99d1-49db-837f-b92a6ced2cad','壽姪','尹直卿','宋','宋诗','song-poetry','','[]','浙水春風第一家，只言當日長蘭芽。',64,'全唐诗/poet.song.181000.json','["浙水春風第一家，只言當日長蘭芽。", "誰知李白三山侶，來看姚黄二月花。", "金甕荼䕷香作酒，玉甌松子肉爲茶。", "滿板松竹并奇物，壽似蟾宮之桂華。"]'),
('87c08e94-0af0-40cf-b33f-f83240ccaacb','賀周益公歸休','尹直卿','宋','宋诗','song-poetry','','[]','六一先生薄吉州，歸田去作潁昌游。',32,'全唐诗/poet.song.181000.json','["六一先生薄吉州，歸田去作潁昌游。", "我公不向螺江住，羞殺青原白鷺洲。"]'),
('48f96fa7-7c65-43be-8f06-8b1364b1e935','問寢龍樓曉','尹直卿','宋','宋诗','song-poetry','','[]','父母人皆有，儀刑自冕旒。',72,'全唐诗/poet.song.181000.json','["父母人皆有，儀刑自冕旒。", "問安趨燕寢，拂曉過龍樓。", "鶴駕嚴晨衛，鷄人徹夜籌。", "慈闈天語接，飛棟月華收。", "萬姓齊呼舞，三宮款獻酬。", "小儒憂國切，幾白九分頭。"]'),
('b336873f-39d7-4f0a-b19a-f8923fc65cbb','盱眙旅舍','路德章','宋','宋诗','song-poetry','','[]','道旁草屋兩三家，見客擂麻旋點茶。',32,'全唐诗/poet.song.181000.json','["道旁草屋兩三家，見客擂麻旋點茶。", "漸近中原語音好，不知淮水是天涯。"]'),
('16e0dce9-14a1-4328-b824-3eb4274b34fd','游寒岩釣磯','路德章','宋','宋诗','song-poetry','','[]','竹裏茅茨竹外溪，粼粼白石護漁磯。',32,'全唐诗/poet.song.181000.json','["竹裏茅茨竹外溪，粼粼白石護漁磯。", "想應日日來垂釣，石上蓑衣不带歸。"]'),
('4bbdcf5b-1d0b-41c0-8189-4e087f8db246','句','鄧伯秀','宋','宋诗','song-poetry','','[]','在我時舒卷，從他自去留。',12,'全唐诗/poet.song.181000.json','["在我時舒卷，從他自去留。"]'),
('5be3d5f9-af26-46fb-af6f-5ebff0d4a1ed','挽徐吏部  其一','熊夢渭','宋','宋诗','song-poetry','','[]','南浦簪纓盛，西山衣鉢傳。',48,'全唐诗/poet.song.181000.json','["南浦簪纓盛，西山衣鉢傳。", "純忱儀後進，達德邁前賢。", "靜默嘗聞道，安怡偶似禪。", "嗟哉遊汗漫，不使侍甘泉。"]'),
('272052aa-3de3-43ed-828a-58c26102ac26','挽徐吏部  其二','熊夢渭','宋','宋诗','song-poetry','','[]','安車駕夷路，佩玉造明庭。',48,'全唐诗/poet.song.181000.json','["安車駕夷路，佩玉造明庭。", "天定歸郎位，雲開出使星。", "心嘗思綠野，夢不戀青冥。", "千古行藏際，豐碑定有銘。"]'),
('7456516d-c792-4a2b-9140-f83518489df0','資聖寺','林夔孫','宋','宋诗','song-poetry','','[]','華峰跨蒼穹，下有雲一壑。',192,'全唐诗/poet.song.181000.json','["華峰跨蒼穹，下有雲一壑。", "翬飛二百秋，蜂巢幾千落。", "靈泉際空留，宿霧臨除薄。", "山呈萬古姿，竹隕六月籜。", "當年有賢令，神交契冥漠。", "懷哉精魄歸，永矣香火託。", "至今書壁間，讀者爲嗟愕。", "好事繼前志，刳巖成此閣。", "仰看斗插椽，俯聽泉入鐸。", "晤言千載心，英氣凜欲作。", "西崖望蒙頂，躋攀計已昨。", "忽聞良友同，共寫襟期樂。", "遐登破嶸屼，幽討待綽約。", "磅礴富蒸鬰，陰衣茫紛錯。", "再拜五華君，許蒞他日約。", "霜威凈餘氛，晴宇洞寥廓。"]'),
('15618535-c179-42bf-93c8-e58e8ec2792d','夢蝶','柯夢得','宋','宋诗','song-poetry','','[]','一覺千年一轉機，覺來還是夢還非。',32,'全唐诗/poet.song.181000.json','["一覺千年一轉機，覺來還是夢還非。", "當時夢裏如爲蝶，便好穿花傍水飛。"]'),
('719a4eaf-8c16-4a69-9b7a-3a01b33ef138','李長吉','柯夢得','宋','宋诗','song-poetry','','[]','天遣皇孫二十七，若木望來高幾尺。',64,'全唐诗/poet.song.181000.json','["天遣皇孫二十七，若木望來高幾尺。", "行空萬里是祥雲，入地千年成琥珀。", "玉樓渺漠無人到，高臺自古悲風早。", "碧雲盡處是天衢，更沒青青河畔草。"]'),
('8198a653-5dd2-46db-965f-9fa288faf573','陌上桑','柯夢得','宋','宋诗','song-poetry','','[]','朝採陌上桑，暮採陌上桑。',40,'全唐诗/poet.song.181000.json','["朝採陌上桑，暮採陌上桑。", "一桑十日採，不見薄情郎。", "正是吳頭桑葉綠，行人莫唱江南曲。"]'),
('047eb914-7268-4339-9926-24abb75eb8fe','見舊題壁','柯夢得','宋','宋诗','song-poetry','','[]','小遲點筆醉還嗔，畫斷蕭梁古佛塵。',32,'全唐诗/poet.song.181000.json','["小遲點筆醉還嗔，畫斷蕭梁古佛塵。", "今日重來應抵掌，十年分付未逢人。"]'),
('8f1e2293-829d-4d23-b5ec-ac7932f54d17','晚望','柯夢得','宋','宋诗','song-poetry','','[]','無數寒鴉來遠鍾，物華心跡偶然同。',32,'全唐诗/poet.song.181000.json','["無數寒鴉來遠鍾，物華心跡偶然同。", "不知海北江南路，更有愁人立晚風。"]'),
('49aa8aef-940a-43d0-b490-1cdb73932b08','方公祠堂迎送神曲','柯夢得','宋','宋诗','song-poetry','','[]','思公不見兮我心愁，渺八荒兮遠遊。',195,'全唐诗/poet.song.181000.json','["思公不見兮我心愁，渺八荒兮遠遊。", "嚴祀事兮歲修，幾來下兮淹留，勤恤祈天兮惠澤周。", "如父母兮子孫謀，非公休我兮我何以休，誰知公心兮不獨桂人是憂。", "蘅杜兮薦羞，桂醑兮芬浮。", "臨饗兮誰酢酬，胥樂兮和氣流。", "是感是慕兮無昭幽，惠我桂人兮百千秋。", "菲薦畢陳兮歆斯鑒斯，歌鼓方洽兮送歌繼之。", "擁翠雲兮祥風馳，乘霧轂兮揚桂旗。", "秀峙兮瑩澌，可游兮可嬉。", "來何從兮去莫追，悵望不及兮天一涯。", "化災沴兮景貺綏，願倏爾兮祀事孔時。"]'),
('a563e6fd-6321-48e1-b42c-2ae396e9f9f1','句','柯夢得','宋','宋诗','song-poetry','','[]','龍首山頭桑苧翁。',8,'全唐诗/poet.song.181000.json','["龍首山頭桑苧翁。"]'),
('76b731e5-2bd8-49ce-80f5-c2877659cdc1','杭州','謝驛','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','誰把杭州曲子謳，荷花十里桂三秋。',32,'全唐诗/poet.song.181000.json','["誰把杭州曲子謳，荷花十里桂三秋。", "那知卉木無情物，牽動長江萬里愁。"]'),
('39320b1a-fd1e-41a1-be7a-06213c3349d0','軍峰','謝驛','宋','宋诗','song-poetry','','[]','倚天青壁瘦巉巖，下有神龍捲作潭。',32,'全唐诗/poet.song.181000.json','["倚天青壁瘦巉巖，下有神龍捲作潭。", "龍欲出時山吐氣，黑雲隨手暗江南。"]'),
('483efc0d-3a09-477b-a417-80240f1508c7','香入雲亭爲高子章賦','杜去輕','宋','宋诗','song-poetry','','[]','山麓有庭存古意，不種凡花惟種桂。',208,'全唐诗/poet.song.181000.json','["山麓有庭存古意，不種凡花惟種桂。", "苔封蘚剝迸鱗皴，雪勁霜頑聳蒼翠。", "栽培豈解一日成，愛惜至今尤不易。", "來人不必問典型，對此儼然前輩是。", "樹前翁仲不可求，樹下子孫能幾世。", "子孫立足滿庭除，前人於此見心事。", "近年喬木幾家存，是中林壑何陰翳。", "前人種樹愛讀書，種時已喻書中義。", "後人讀書念前人，對樹類能歌蔽芾。", "八月九日秋風高，金丹變化乘飄飄。", "朝元顧祖歸寒殿，仙香直入干雲霄。", "老兔癡蟾開鼻孔，奏徹虛皇應得寵。", "虛皇錫賫萬瓊瑶，賞君愛護月中種。"]'),
('140b2040-480a-4639-8985-8aa897d94529','句','杜去輕','宋','宋诗','song-poetry','','[]','緣曾分月種，故發入雲香。',12,'全唐诗/poet.song.181000.json','["緣曾分月種，故發入雲香。"]'),
('1f0841c2-2144-4849-9a1a-a058ac8342ca','詩一首','張卿','宋','宋诗','song-poetry','','[]','小小園林矮矮屋，一日房錢一貫足。',32,'全唐诗/poet.song.181000.json','["小小園林矮矮屋，一日房錢一貫足。", "官至正郎子讀書，一妻一妾常和睦。"]'),
('56b28328-02fe-4e22-9031-bb6cbdfce28d','阻史彌遠占寺偈','育王寺僧','宋','宋诗','song-poetry','','[]','寺前一塊地，常有天子氣。',24,'全唐诗/poet.song.181000.json','["寺前一塊地，常有天子氣。", "丞相要作墳，不知主何意。"]'),
('376847c9-323d-4286-b0a7-83c5ae7eb174','辭主萬壽寺偈','僧大','宋','宋诗','song-poetry','','[]','相君提我上天梯，上得千層總是迷。',32,'全唐诗/poet.song.181000.json','["相君提我上天梯，上得千層總是迷。", "爭似虎丘安穩坐，清風明月與心齊。"]'),
('c2449a1e-ff92-4fb1-90e1-cdc0faac9465','元旦望闕叩頭而作','史彌忠','宋','宋诗','song-poetry','','[]','青帝初傳令，山河萬象新。',48,'全唐诗/poet.song.181000.json','["青帝初傳令，山河萬象新。", "聖恩寬似海，世態樂同春。", "拜闕難辭老，居官豈爲貧。", "京華望不遠，感激切微臣。"]'),
('7c32fa9d-89c5-4af8-bacd-79dfdeb9e0db','送安撫使袁彥淳之任','史彌忠','宋','宋诗','song-poetry','','[]','雄心中夜豈難平，一隊旌旗萬里行。',64,'全唐诗/poet.song.181000.json','["雄心中夜豈難平，一隊旌旗萬里行。", "爲國許身增慷慨，逢人說劍轉分明。", "尊前白髮懷南浦，馬上青山過楚城。", "從此海邦多治略，好聽歌誦快輿情。"]'),
('fb0305ca-f91a-4155-97f5-71f96cd1b09a','西湖','史彌忠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','碧波青嶂對紅樓，千古西湖樂未休。',32,'全唐诗/poet.song.181000.json','["碧波青嶂對紅樓，千古西湖樂未休。", "試把腰纏買春色，不知世上有揚州。"]'),
('5c35901b-85da-4365-9d5a-710f89d9f724','秋桂','史彌忠','宋','宋诗','song-poetry','','[]','庭前高挺碧玉樹，秋日奈茲風露何。',32,'全唐诗/poet.song.181000.json','["庭前高挺碧玉樹，秋日奈茲風露何。", "兩度開花君莫問，爲渠天近得香多。"]'),
('4d4c3e05-65da-4333-855b-95323ec5169c','遊青城山','李興宗','宋','宋诗','song-poetry','','[]','古岷橫枕坤維首，連標遠接崑崙右。',32,'全唐诗/poet.song.181000.json','["古岷橫枕坤維首，連標遠接崑崙右。", "我歷江山欠此遊，青夢遶之良已久。"]'),
('d4736e57-b1b0-40aa-87e4-31b377b60878','觀八陣圖有感','李興宗','宋','宋诗','song-poetry','','[]','江從岷來觸瞿唐，夏潦潰裂怒勢張。',323,'全唐诗/poet.song.181000.json','["江從岷來觸瞿唐，夏潦潰裂怒勢張。", "霜濃水落洲渚露，纍纍江石堆作行。", "半斜半直半疎密，方營周匝門東出。", "相傳呵護有鬼神，驚波不能移寸尺。", "想見當年諸葛公，綸巾羽扇揮秋風。", "令嚴部伍寂如水，出沒變化機無窮。", "乾坤不足當經理，寫留古法艮岑趾。", "上灘下峽一千年，多少英雄測玄旨。", "小兒元子强多知，常山蛇勢吾能窺。", "灞上枋頭真絕倒，空使虬髯論握奇。", "斵輪不可傳其子，此公天機緘骨髓。", "奈何螟蝗生蝮蝎，炎劉已灰吹不起。", "天教三馬食一槽，老馬蹄囓暫咆哮。", "渭陽巾幗勢將蹶，大星夜隕西軍號。", "嗚呼興廢盡天意，中原□□□□□。", "□□骨肉止相殘，欲拯塗炭嗟誰使。", "大官酣燕芻豢餘，小官跼蹐塵埃裏。", "舉目厭厭九泉人，誰訪草廬談世事。", "向來韜畧機莫投，而今投機欠良籌。", "君不見峽山深深茅舍底，有人抱膝高聲謳。"]'),
('5f585124-83be-475e-8077-550ec35522b2','爲侍郎徐公邦憲賦','張淏','宋','宋诗','song-poetry','','[]','五花麟駒籋飛雲，鳴珂敲月曙色分。',208,'全唐诗/poet.song.181000.json','["五花麟駒籋飛雲，鳴珂敲月曙色分。", "晨光炯炯照玉勒，華風熠熠生衡門。", "磊磊落落萬人英，氣射斗牛貫九精。", "筆扛龍文百斛鼎，鯨呿鼇擲風雨驚。", "英辭琳瑯潤金石，寒芒正色如明星。", "淫哇亂雅快一掃，英莖韶濩重鏗鍧。", "質高器大聲必廣，古來才士豈虛名。", "我嗟壯歲困五窮，終年齪齪文字中。", "絕編壞簡徒自苦，炊沙鏤水初何功。", "志高意廣材不足，奴輩豈特笑孔融。", "龍潛蚖肆亦物理，草廬未必非英雄。", "天生我材必有用，誰能便與朽腐同。", "願得側翅附鴻鵠，追風掣電凌太空。"]'),
('798f6c1a-7d96-4f91-84ff-913c881cdb01','句','張淏','宋','宋诗','song-poetry','','[]','今朝執手難言處，此去傾懷更有誰。',16,'全唐诗/poet.song.181000.json','["今朝執手難言處，此去傾懷更有誰。"]'),
('37b13911-86f8-4dd9-aa46-531d4f757a22','松','游九功','宋','宋诗','song-poetry','','[]','煙翠松林碧玉灣，捲簾波影動清寒。',32,'全唐诗/poet.song.181000.json','["煙翠松林碧玉灣，捲簾波影動清寒。", "住山未必知山好，却是行人得細看。"]'),
('8507a5e2-0a90-4450-9325-44a104d469cf','浯亭望橫山','游九功','宋','宋诗','song-poetry','','[]','峩峩岸東山，躍來勢奔虬。',84,'全唐诗/poet.song.181000.json','["峩峩岸東山，躍來勢奔虬。", "橫約一溪水，抱邑止復流。", "近郭看逾好，向望此其尤。", "翠展曲屏寬，一目千里收。", "此山此之水，我歌我來游。", "知不市聲雜，亦忘溪上幽。", "方將解其縛，於焉我何求。"]'),
('320a646f-36ce-432c-b61c-979340d0342b','答黄叔暘','游九功','宋','宋诗','song-poetry','','[]','冥鴻倦雲飛，歛翼退遵渚。',132,'全唐诗/poet.song.181000.json','["冥鴻倦雲飛，歛翼退遵渚。", "秋蟲感時至，自野來在宇。", "老我久合歸，溪山况延佇。", "俯此沙水清，面被烟塵聚。", "龍斷既衝衝，瀾倒亦訏訏。", "豈無砥中立，而不改風雨。", "忽忻遠寄聲，秀句盈章吐。", "燦爛炯寒芒，晴空見冰柱。", "頗聞詞場筆，漫焉葉如土。", "黄粱枕上過，得之亦不處。", "獨行固不移，猶在審去取。"]'),
('c14cb2ae-fa74-4e54-ade1-31278b990ce4','題魏醇父菊莊','游九功','宋','宋诗','song-poetry','','[]','東籬采采人歸來，長歌三嗔書生老。',144,'全唐诗/poet.song.181000.json','["東籬采采人歸來，長歌三嗔書生老。", "子方青春志紫霄，種菊幽探計何早。", "一枝可愛况千叢，想應苦吟被花惱。", "西風浩然天池秋，白露霏空下百草。", "此時此花抱幽貞，寧衒世間顔色好。", "日斜寒照萼明韡，霜輕浄澈香遠到。", "淡焉見謂山澤癯，淵乎我愛其似道。", "荒畦野逕尤愜性，何似移根伴枯槁。", "雖知晚節亦何用，爲制頹齡聊自保。"]'),
('dc8094c7-8ab6-462e-bf14-5c5ebe71be1a','棄官歸故廬','游九功','宋','宋诗','song-poetry','','[]','野塘漫漫板橋東，家在春風𤱶畝中。',64,'全唐诗/poet.song.181000.json','["野塘漫漫板橋東，家在春風𤱶畝中。", "階草不芟新織翠，庭花初種小開紅。", "酒嘗村釀餘酸味，詩乏才華有淡工。", "鄰里相過無雜語，但云饑後慶年豐。"]'),
('42aa48d2-4815-4aee-88f9-84441a90c61d','送常老住疎山','游九功','宋','宋诗','song-poetry','','[]','師住疎山祇樹園，卧看雲霧起江村。',64,'全唐诗/poet.song.181000.json','["師住疎山祇樹園，卧看雲霧起江村。", "百年鼎鼎春風轉，一鉢垂垂老眼昏。", "古殿撲空參鐵鳳，夜潭翻月落金盤。", "何時繫纜西風下，松柏陰陰獨扣門。"]'),
('d9e1d652-302e-4396-9c68-fd0eac73ae7b','與同年陳公過山亭','赵汝㬊','宋','宋诗','song-poetry','','[]','青苔滿地護階陰，塵俗曾無半點侵。',64,'全唐诗/poet.song.181000.json','["青苔滿地護階陰，塵俗曾無半點侵。", "林鳥避人穿谷去，野猿尋果出雲深。", "千竿翠竹依簷立，一對黄鸝入樹吟。", "晝靜風清詩思罷，憑闌傾耳聽松琴。"]'),
('83b0cdfc-b510-41e0-9204-07e377a9e50f','賦梅','彭巖肖','宋','宋诗','song-poetry','','[]','清獻堂前樹，無梢可著春。',24,'全唐诗/poet.song.181000.json','["清獻堂前樹，無梢可著春。", "豈知三百載，復有種花人。"]'),
('3299fc4e-37f7-4602-8e97-22ef93bba368','與新安朱元晦談易有感','趙汝洙','宋','宋诗','song-poetry','','[]','南窗數度斷韋編，茅塞余心未豁然。',64,'全唐诗/poet.song.181000.json','["南窗數度斷韋編，茅塞余心未豁然。", "洞極潛虛渾是夢，觀梅卜瓦總非僊。", "先天妙處無多畫，太古真時只一圈。", "今日從知斯不謬，庖羲更出亦何言。"]'),
('3d185407-c4f2-4bc5-b8fa-3773c890622c','奚大卿許賦生香亭詩以促之','吳晦之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','暗香浮動月初斜，彷彿西湖處士家。',32,'全唐诗/poet.song.181000.json','["暗香浮動月初斜，彷彿西湖處士家。", "誰道廣平心似鐵，不將佳句賦梅花。"]'),
('ff095723-6635-4bcd-bd0e-b23010e34591','山庵睡起','吳晦之','宋','宋诗','song-poetry','','[]','策蹇尋幽過草堂，困來欹枕卧禪床。',32,'全唐诗/poet.song.181000.json','["策蹇尋幽過草堂，困來欹枕卧禪床。", "鳥啼花落東風裏，睡起不知春晝長。"]'),
('6896549d-3107-4f5e-b39b-983f67c543b9','蓬窗','吳晦之','宋','宋诗','song-poetry','','[]','小室瀟然一釣蓬，主人閑散似漁翁。',32,'全唐诗/poet.song.181000.json','["小室瀟然一釣蓬，主人閑散似漁翁。", "有時風雨驚殘夢，如在松江烟浪中。"]'),
('02173c00-59a2-43ec-87fa-cf3f2c58838e','春日即事','吳晦之','宋','宋诗','song-poetry','','[]','山居無事到襟懷，日午柴門尚未開。',32,'全唐诗/poet.song.181000.json','["山居無事到襟懷，日午柴門尚未開。", "啼鳥一聲春晝寂，隔牆風送落花來。"]'),
('00218204-26b9-4b2a-ae5a-841679957ba9','山亭偶成','吳晦之','宋','宋诗','song-poetry','','[]','二十四考成何事，三百六十長是閑。',32,'全唐诗/poet.song.181000.json','["二十四考成何事，三百六十長是閑。", "古今窮達置勿論，坐看烟雲生西山。"]'),
('86cf95f8-824f-4e4c-9f59-0e298cf7fa56','贈江西詩客','吳晦之','宋','宋诗','song-poetry','','[]','五言詩作七寶塔，四壁惟餘八尺床。',32,'全唐诗/poet.song.181000.json','["五言詩作七寶塔，四壁惟餘八尺床。", "一月二十九日醉，百年三萬六千場。"]'),
('57df4856-0e04-4069-844e-85af77149371','送友人西上','吳晦之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曉行山路梅花白，晚宿溪橋柳色青。',32,'全唐诗/poet.song.181000.json','["曉行山路梅花白，晚宿溪橋柳色青。", "此去西湖春漸暖，畫船沽酒水邊亭。"]'),
('6161b071-f122-4f85-937c-7f40c9f61e31','後圃尋春','吳晦之','宋','宋诗','song-poetry','','[]','雨餘未訪後園春，百紫千紅錦幛新。',32,'全唐诗/poet.song.181000.json','["雨餘未訪後園春，百紫千紅錦幛新。", "記得錢塘買花看，于今風景屬閑人。"]'),
('24a4779c-efb8-4e5d-8ed7-b5ea1779801e','憶江湖舊遊','吳晦之','宋','宋诗','song-poetry','','[]','水滿汀洲白鷺雙，蘆花飛雪撲船窗。',32,'全唐诗/poet.song.181000.json','["水滿汀洲白鷺雙，蘆花飛雪撲船窗。", "歸來常有江湖興，遥想鍾聲隔岸撞。"]'),
('39c7524f-ab04-4284-b05b-ea07e28425a2','雪後尋梅','吳晦之','宋','宋诗','song-poetry','','[]','畧彴溪橋小徑斜，竹籬茅舍兩三家。',32,'全唐诗/poet.song.181000.json','["畧彴溪橋小徑斜，竹籬茅舍兩三家。", "紅梅似與詩人約，臘雪初消始看花。"]'),
('5ec62a0e-52c6-4127-8905-a0d455b18c54','溪頭喚渡','吳晦之','宋','宋诗','song-poetry','','[]','輕烟漠漠曉晴天，立馬汀沙喚渡船。',32,'全唐诗/poet.song.181000.json','["輕烟漠漠曉晴天，立馬汀沙喚渡船。", "白鳥忘機思慮息，避人飛過急灘前。"]'),
('b32fcd28-6f58-4049-8ed2-fb29afbf145b','寄石魯瞻','吳晦之','宋','宋诗','song-poetry','','[]','憶昔從遊杖履中，有山亭上醉春風。',32,'全唐诗/poet.song.181000.json','["憶昔從遊杖履中，有山亭上醉春風。", "主人已作騎鯨客，誰識當年兩病翁。"]'),
('90574661-7fb6-43c1-8214-55cb154ea25c','游春黄胖','俞朝士','宋','宋诗','song-poetry','','[]','兩脚捎空欲弄春，一人頭上又安人。',32,'全唐诗/poet.song.181000.json','["兩脚捎空欲弄春，一人頭上又安人。", "不知終入兒童手，筋骨翻爲陌上塵。"]'),
('6e9e579c-dc38-4b8c-8c7b-2c7f5da2c2b7','天屋歌爲盧洪賦','趙希㯝','宋','宋诗','song-poetry','','[]','霞扃雲牖高窿穹，八荒四野垂簾櫳。',131,'全唐诗/poet.song.181000.json','["霞扃雲牖高窿穹，八荒四野垂簾櫳。", "羲璘勃窣行西東，茫茫塵世如飛蓬。", "玉川公子乘清風，飄然據作吟詩宮。", "穿心出脅千萬語，叫開閶闔驚蒼龍。", "銀河瀉入北斗柄，醉來擲下琉璃鍾。", "仙人王喬作鄰伍，馮軒共笑噓長虹。", "旌陽拔宅想亦在，千年萬歲都洪濛。", "君不見阿房結綺今何許，劫灰一丈漫秋雨。"]'),
('4b043447-30c8-413b-b36a-4dd7dae0424a','次韻李鶴田德真寄遠','趙希㯝','宋','宋诗','song-poetry','','[]','長安日下浮雲生，故人久作西南行。',112,'全唐诗/poet.song.181000.json','["長安日下浮雲生，故人久作西南行。", "漚邊兩載音訊絕，鬢絲應與秋風爭。", "蒼苔冉冉荒茅屋，愁來忍把離騷讀。", "驚鴻剛自墮邊聲，碧嶂那堪遮遠目。", "青雲高處期翱翔，去人歲月今堂堂。", "吳鈎拂拭霜雪冷，龍光飛躍秋天長。", "思君一夜離心折，東樓又送無情月。"]'),
('f29f887a-b170-4004-8998-47899c577ea1','道民金氏居','趙希㯝','宋','宋诗','song-poetry','','[]','碧港雖通邑，紅塵不到門。',48,'全唐诗/poet.song.181000.json','["碧港雖通邑，紅塵不到門。", "桑麻唐杜曲，雞犬晉桃源。", "山遠雲千點，天寬月一軒。", "居人非隠者，吾欲叫東園。"]'),
('0d0c226c-3855-466c-9d2e-ec9d334c87fd','竹閣','趙希㯝','宋','宋诗','song-poetry','','[]','古寺因人重，清風尚可尋。',48,'全唐诗/poet.song.181000.json','["古寺因人重，清風尚可尋。", "斜陽明晚閣，老竹暗秋林。", "兜率西歸久，香山北望深。", "登臨成感慨，烟月獨知心。"]'),
('f0ac1dd1-7e36-4243-bdfd-a7ad370c6956','游臨平乾洞水洞','趙希㯝','宋','宋诗','song-poetry','','[]','兩洞深如許，神龍此奠居。',48,'全唐诗/poet.song.181000.json','["兩洞深如許，神龍此奠居。", "山空仙去久，路嶮客來疏。", "風雨千崖暗，雲烟四壁虛。", "自揩巖石蘚，閑把姓名書。"]'),
('0ec8c17e-135e-4d80-9719-ac8cb6853471','雪','趙希㯝','宋','宋诗','song-poetry','','[]','不是春風柳，因何絮客衫。',48,'全唐诗/poet.song.181000.json','["不是春風柳，因何絮客衫。", "一雲同萬里，半夜失千巖。", "征馬寒蹤印，饑鴟凍吻緘。", "江心一片白，知有莫歸帆。"]'),
('94fdaa22-db77-467d-8728-01ec5044ca0b','送詩僧隆瘦岩','趙希㯝','宋','宋诗','song-poetry','','[]','五載京華客，山中坐得牢。',48,'全唐诗/poet.song.181000.json','["五載京華客，山中坐得牢。", "禪心天竺石，吟思浙江濤。", "入派名隨重，游方步轉高。", "秋風飛錫遠，相憶讀離騷。"]'),
('04116470-a305-408b-b0e8-c5c98b3ffd02','送自牧黄監鎮之官四安','趙希㯝','宋','宋诗','song-poetry','','[]','桃花春浪急，催上霅溪船。',48,'全唐诗/poet.song.181000.json','["桃花春浪急，催上霅溪船。", "湖海稱佳士，功名負壯年。", "政平民易感，詩好客爭傳。", "別後加餐飯，因風寄一箋。"]'),
('ac03da16-1986-49d5-b3fd-008e3a7a0f95','秋夕','趙希㯝','宋','宋诗','song-poetry','','[]','霄虛白露漙，木葉下危闌。',48,'全唐诗/poet.song.181000.json','["霄虛白露漙，木葉下危闌。", "月澹鐘聲曉，燈青劍影寒。", "人心山莽莽，世事海漫漫。", "何日平胡虜，西風望眼寬。"]'),
('afa085f1-b46d-4d27-8b51-2c08a8356ee9','中秋','趙希㯝','宋','宋诗','song-poetry','','[]','白露漙空萬葉飛，生香渾在桂花枝。',64,'全唐诗/poet.song.181000.json','["白露漙空萬葉飛，生香渾在桂花枝。", "一千里月正圓夜，九十日秋纔半時。", "湓浦風流元亮興，鄜州牢落少陵詩。", "不妨吟盡蟾蜍影，此別分明隔歲期。"]'),
('57ec6267-97f2-48d5-a6ef-860a79d70ed7','送李鶴田東游後還鄉','趙希㯝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','劍倚梅花鶴夢醒，東游吟骨带秋清。',64,'全唐诗/poet.song.181000.json','["劍倚梅花鶴夢醒，東游吟骨带秋清。", "台山路杳神仙迹，楚國書來母子情。", "半榻烟霞應有約，一筇風雪且兼程。", "丁寧及早催行李，莫待西湖草色平。"]'),
('3f829d53-9c9b-40c7-ac50-f78d3b06ee02','江湖偉觀','趙希㯝','宋','宋诗','song-poetry','','[]','華屋巋然占上方，一尊同此寄相羊。',64,'全唐诗/poet.song.181000.json','["華屋巋然占上方，一尊同此寄相羊。", "江潮翻海莫天闊，湖水拍堤春草長。", "莽莽越山凝紫翠，摇摇蘇柳間青黄。", "歸鴻影裏闌干晚，回首中州入渺茫。"]'),
('ef07087b-f9c8-4e4a-9fde-aec1da4181fc','送譙岩趙日休歸蜀','趙希㯝','宋','宋诗','song-poetry','','[]','烟塵渺渺暗魚鳬，有客翩然赴上都。',64,'全唐诗/poet.song.181000.json','["烟塵渺渺暗魚鳬，有客翩然赴上都。", "乞得玉宸新翰墨，要還琳宇舊規模。", "十年蠲賦綸恩重，萬里歸程劍影孤。", "他日青城公案了，紫雲深處勘陰符。"]'),
('d94f3887-fd0f-4dc1-9f38-f9bae65127c5','春雪','趙希㯝','宋','宋诗','song-poetry','','[]','飛下瑶天整復斜，一番餘凍損芳華。',64,'全唐诗/poet.song.181000.json','["飛下瑶天整復斜，一番餘凍損芳華。", "荒荒月曉三千界，漠漠烟寒十萬家。", "柳外直疑先著絮，梅邊渾似後開花。", "東風吹作巴江水，浩蕩龍濤赴海涯。"]'),
('4be4ad9a-8154-453a-af48-3082f39828e8','秋懷次韻','趙希㯝','宋','宋诗','song-poetry','','[]','雨歇空階浄綠苔，西風凉氣滿樓臺。',64,'全唐诗/poet.song.181000.json','["雨歇空階浄綠苔，西風凉氣滿樓臺。", "鴻飛遠渚知初到，燕別明年約早來。", "秋色祇今同世態，時文何意悞人才。", "停雲影裏頻搔首，閑把新吟取次裁。"]'),
('d8cc3701-d486-4e32-9ed3-09ea6b2eaa3e','春莫','趙希㯝','宋','宋诗','song-poetry','','[]','薄薄寒侵酒面和，可憐春事委流波。',64,'全唐诗/poet.song.181000.json','["薄薄寒侵酒面和，可憐春事委流波。", "兩堤楊柳東風老，一曲池塘夜雨多。", "花落鶑聲還在否，桑空蠶事又如何。", "壯心不逐流年去，倚劍青天發浩歌。"]'),
('f22bb416-7afe-4079-b29e-98399ebd749a','寄黄溪雲','趙希㯝','宋','宋诗','song-poetry','','[]','十年成遠別，幾度上高樓。',48,'全唐诗/poet.song.181000.json','["十年成遠別，幾度上高樓。", "風遞江南信，雲消渭北愁。", "春心驚海燕，曉夢入溪鷗。", "何日西窗燭，相看說舊游。"]'),
('8a64244b-f0d0-44b6-bf64-b1011d69718d','九日懷友','趙希㯝','宋','宋诗','song-poetry','','[]','江蟹初肥天欲霜，莫雲紅樹寫秋光。',32,'全唐诗/poet.song.181000.json','["江蟹初肥天欲霜，莫雲紅樹寫秋光。", "西風携手登臨地，今日黄花兩處香。"]'),
('4de44214-9995-4bbe-a0b4-c36a12c1e7b9','釣者','趙希㯝','宋','宋诗','song-poetry','','[]','河豚荻笋春風老，鱸鱠蓴絲秋水寒。',32,'全唐诗/poet.song.181000.json','["河豚荻笋春風老，鱸鱠蓴絲秋水寒。", "多少侯門天樣闊，算來何似釣船寬。"]'),
('6e90af43-6aa2-4b60-bed7-2a04d00d9080','過臨平','趙希㯝','宋','宋诗','song-poetry','','[]','市井蕭條景物非，居人猶號永和堤。',32,'全唐诗/poet.song.181000.json','["市井蕭條景物非，居人猶號永和堤。", "春山十里斜陽樹，漠漠殘紅杜宇啼。"]'),
('8932a722-2e7a-4fb8-b269-c602f474899b','吳道士釣雲','趙希㯝','宋','宋诗','song-poetry','','[]','澹溪溪上一竿絲，牽動閑雲片片飛。',32,'全唐诗/poet.song.181000.json','["澹溪溪上一竿絲，牽動閑雲片片飛。", "折盡柳條穿不得，荷衣裹向碧山歸。"]'),
('6d7eeb8f-8c47-43ba-a0da-0e4315d9ccf6','次雪林李龏苕溪寄來之韻  其一','趙希㯝','宋','宋诗','song-poetry','','[]','雲散烟收渺渺秋，蛩聲四壁起新愁。',32,'全唐诗/poet.song.181000.json','["雲散烟收渺渺秋，蛩聲四壁起新愁。", "西風萬里乾坤眼，不到斜陽十二樓。"]'),
('6d1ae655-6951-4bb4-8814-2ea65cd7ba0e','次雪林李龏苕溪寄來之韻  其二','趙希㯝','宋','宋诗','song-poetry','','[]','風梧聲裏萬家秋，一片吟心不著愁。',32,'全唐诗/poet.song.181000.json','["風梧聲裏萬家秋，一片吟心不著愁。", "夜半酒醒銀燭冷，月移凉夢過西樓。"]'),
('404d5b89-db82-4fd2-a90f-a87bfa762076','賦墨雁圖分得宿雁','趙希㯝','宋','宋诗','song-poetry','','[]','漠漠秋汀起晚烟，半欹寒影立風前。',32,'全唐诗/poet.song.181000.json','["漠漠秋汀起晚烟，半欹寒影立風前。", "月明應有蘆花夢，飛遍江湖萬里天。"]'),
('dff3acc0-4e94-44ae-a79e-7ce4c90f8893','次蕭冰崖梅花韻','趙希㯝','宋','宋诗','song-poetry','','[]','冰姿瓊骨浄無瑕，竹外溪邊處士家。',32,'全唐诗/poet.song.181000.json','["冰姿瓊骨浄無瑕，竹外溪邊處士家。", "若使牡丹開得早，有誰風雪看梅花。"]'),
('e1cc3a94-be2b-41f4-a3a6-a9082e00095b','湧月僧樓','趙希㯝','宋','宋诗','song-poetry','','[]','百尺闌干右櫟林，亂山如浪翠痕深。',32,'全唐诗/poet.song.181000.json','["百尺闌干右櫟林，亂山如浪翠痕深。", "冰輪飛上光猶濕，照破西來一片心。"]'),
('03e63352-c04f-4b8e-b237-9ad3d998cd2b','秋夕  其一','趙希㯝','宋','宋诗','song-poetry','','[]','西風梳髮冷颼颼，半醉微吟獨倚樓。',32,'全唐诗/poet.song.181000.json','["西風梳髮冷颼颼，半醉微吟獨倚樓。", "一片舊時南浦月，清光猶印別離愁。"]'),
('76089c97-c17c-40d2-b615-b80874f3f20e','秋夕  其二','趙希㯝','宋','宋诗','song-poetry','','[]','半枕小窗幽夢蝶，數聲何處寄書鴻。',32,'全唐诗/poet.song.181000.json','["半枕小窗幽夢蝶，數聲何處寄書鴻。", "關山千里人歸晚，腸斷烟林一笛風。"]'),
('ff446b9e-37f5-4b9a-ba10-b726a78b266b','春游  其一','趙希㯝','宋','宋诗','song-poetry','','[]','夢冷繁華金谷園，春深葵麥暗朱門。',32,'全唐诗/poet.song.181000.json','["夢冷繁華金谷園，春深葵麥暗朱門。", "東風日日吹花急，紅雨蒼苔泪幾痕。"]'),
('81b2401f-01e4-460b-b277-00f45173817f','春游  其二','趙希㯝','宋','宋诗','song-poetry','','[]','蝶懶鶑喑欲莫春，更兼風雨別愁新。',32,'全唐诗/poet.song.181000.json','["蝶懶鶑喑欲莫春，更兼風雨別愁新。", "天涯草色深如此，憶得淮南有故人。"]'),
('76aea9a7-8874-498c-b27b-0b308e920929','湖中曲','趙希㯝','宋','宋诗','song-poetry','','[]','長眉柳葉交青條，玉花嬌面垂雲髫。',96,'全唐诗/poet.song.181000.json','["長眉柳葉交青條，玉花嬌面垂雲髫。", "湖波藍色春寥寥，大堤新曲干銀霄。", "翠絲絡馬金褭腰，香風隨步烟飛飄。", "芳亭深杳傳金貂，一笑嫣然輕百綃。", "歡娛未了日晷短，城鼓咿咿續復斷。", "鳴鞭夜月入雞關，碧山皎皎水潺潺。"]'),
('ce64195b-f005-45ff-ac6c-6fd935118687','春陰曲','趙希㯝','宋','宋诗','song-poetry','','[]','東風吹寒雲九有，凍龍迷海亂飛走。',96,'全唐诗/poet.song.181000.json','["東風吹寒雲九有，凍龍迷海亂飛走。", "雨脚斜拖入遥阜，碧草浮烟滿堤口。", "春皇妙運造化手，解使江山失妍醜。", "冷色禁持萬花柳，紅紫未張春國壽。", "愁春織心心怮怮，爲花訴冤天聽否。", "晴曦赫赫重陰剖，夢裏桃源拚載酒。"]'),
('3bbf130e-ae42-4285-b3b2-7209a4f8b746','積翠樓','危和','宋','宋诗','song-poetry','','[]','著我高遠堂，恍若非人世。',48,'全唐诗/poet.song.181000.json','["著我高遠堂，恍若非人世。", "一榻卧白雲，清寒不成寐。", "松竹四山秋，颼颼驚客耳。", "誰在隔窗中，朱絃寫流水。"]'),
('34f2c4b5-4d18-45ea-8388-e73154887921','效王建詩體三首  其一','趙希㑂','宋','宋诗','song-poetry','','[]','玉釵半落珊瑚枕，金屋低垂翡翠簾。',32,'全唐诗/poet.song.181000.json','["玉釵半落珊瑚枕，金屋低垂翡翠簾。", "莫喚女醫來問病，逢春自是可曾忺。"]'),
('2073a0fb-4a10-4fcd-b152-2eb0cda2e84d','效王建詩體三首  其二','趙希㑂','宋','宋诗','song-poetry','','[]','從渠羅襪印香泥，偷鄉階前問柳枝。',32,'全唐诗/poet.song.181000.json','["從渠羅襪印香泥，偷鄉階前問柳枝。", "昨日看郎來繫馬，杏花亭北立多時。"]'),
('4bcbfcd4-940d-4e76-a2f7-7e60b75c8bd8','效王建詩體三首  其三','趙希㑂','宋','宋诗','song-poetry','','[]','銀釘未徹碧紗窗，秋入樓心送斷腸。',32,'全唐诗/poet.song.181000.json','["銀釘未徹碧紗窗，秋入樓心送斷腸。", "誰念纈花簾不捲，簷前收下玉玎璫。"]'),
('e5a2e394-f73d-4b22-85b9-07ab631b2f25','旴江山寺','趙希㑂','宋','宋诗','song-poetry','','[]','寺古鍾魚在，林深麋鹿遊。',48,'全唐诗/poet.song.181000.json','["寺古鍾魚在，林深麋鹿遊。", "亂雲從地湧，野水接天流。", "樹老半粘屋，山狂欲入樓。", "無人話心事，黄葉自吟秋。"]'),
('3123b01a-e7c6-44cd-9bee-ac4b6e3e1ed0','句','趙希㑂','宋','宋诗','song-poetry','','[]','芭蕉自作抽書樣，不與行人寄短愁。',16,'全唐诗/poet.song.181000.json','["芭蕉自作抽書樣，不與行人寄短愁。"]'),
('5a32bfed-d548-4f3c-a1cc-a6ab86017d1c','聚景園','王澡','宋','宋诗','song-poetry','','[]','光堯與壽皇，昔者屢遊幸。',60,'全唐诗/poet.song.181000.json','["光堯與壽皇，昔者屢遊幸。", "縟川騎服鮮，藻野宮妝靚。", "春池冰鑑開，笑對驚鴻影。", "不見兩河閒，父老久延頸。", "仰望鸞旂回，呼蹕牟尼頂。"]'),
('0f4743d3-1fe8-44e9-91cb-1ee5d586c8f6','賑荒到天台有作二首  其一','李琪','宋','宋诗','song-poetry','','[]','我亦田夫偶得官，深知茅屋有饑寒。',64,'全唐诗/poet.song.181000.json','["我亦田夫偶得官，深知茅屋有饑寒。", "紛然遮道呻吟狀，一作同胞疾痛觀。", "水際山陬多隠瘼，風餐雨宿敢圖安。", "破襦裹米皆王□，粒粒當知帝澤寬。"]'),
('8a0d3b60-f348-4f35-a0cb-aea4a1df51d0','賑荒到天台有作二首  其二','李琪','宋','宋诗','song-poetry','','[]','馳驅徒步問民饑，似我寒儒負笈時。',64,'全唐诗/poet.song.181000.json','["馳驅徒步問民饑，似我寒儒負笈時。", "偪仄荒村隨戶到，蕭疏幾屋有烟炊。", "平林带暝投山驛，蒼鬢衝寒濕雨絲。", "野老不知巡歷至，相逢爾汝話家私。"]'),
('3f8ba94c-b277-4dec-a31f-35a930aa23f6','移竹後雨','王鎬','宋','宋诗','song-poetry','','[]','洗紅窣窣烏苣雨，落紫颼颼皂角風。',32,'全唐诗/poet.song.181000.json','["洗紅窣窣烏苣雨，落紫颼颼皂角風。", "挂起北窗聊問訊，新移來竹定惺鬆。"]'),
('c1ce4907-5168-4c20-a8d8-08fcab5a6cc7','簡州','王鎬','宋','宋诗','song-poetry','','[]','山水三池郡，平湖塢可園。',24,'全唐诗/poet.song.181000.json','["山水三池郡，平湖塢可園。", "要成真吏隠，故作小桃源。"]'),
('8da5cf1b-30d2-4475-9da5-aa729f331490','小桃源','王鎬','宋','宋诗','song-poetry','','[]','二水清渾合，三山錦繡張。',24,'全唐诗/poet.song.181000.json','["二水清渾合，三山錦繡張。", "迹沉簿書冗，身在水雲鄉。"]'),
('0930f603-d11b-44e9-a3f2-f8cbfdbd577b','句  其一','王鎬','宋','宋诗','song-poetry','','[]','只言弱水蓬萊遠，無奈仙風道骨何。',16,'全唐诗/poet.song.181000.json','["只言弱水蓬萊遠，無奈仙風道骨何。"]'),
('54d72203-0ee0-4a92-8fac-bbc06a5f9527','句  其二','王鎬','宋','宋诗','song-poetry','','[]','仁心廣大麟難比，壽骨清奇鶴不如。',16,'全唐诗/poet.song.181000.json','["仁心廣大麟難比，壽骨清奇鶴不如。"]'),
('f7221f58-3ed6-432a-9502-ff15bca6f46e','句  其三','王鎬','宋','宋诗','song-poetry','','[]','髮爽带風梳，齒疎和月潄。',12,'全唐诗/poet.song.181000.json','["髮爽带風梳，齒疎和月潄。"]'),
('5727733c-8eaa-4336-b960-06ee80a5377b','句  其四','王鎬','宋','宋诗','song-poetry','','[]','避喧那厭雨，宜睡不思茶。',12,'全唐诗/poet.song.181000.json','["避喧那厭雨，宜睡不思茶。"]'),
('c8e31e71-cce5-495f-a1bf-b84d52278f8c','句  其五','王鎬','宋','宋诗','song-poetry','','[]','雲學催詩黑，風仍作頌清。',12,'全唐诗/poet.song.181000.json','["雲學催詩黑，風仍作頌清。"]'),
('6a501a52-273c-4a0e-bfc7-042355f81da8','句  其六','王鎬','宋','宋诗','song-poetry','','[]','未知真是嶽，祇見半爲雲。',12,'全唐诗/poet.song.181000.json','["未知真是嶽，祇見半爲雲。"]'),
('34f0e9d9-ff70-4f49-beda-8cc11f77ca63','句  其七','王鎬','宋','宋诗','song-poetry','','[]','凍雪寒梅雙蠟屐，澄江明月一竿絲。',16,'全唐诗/poet.song.181000.json','["凍雪寒梅雙蠟屐，澄江明月一竿絲。"]'),
('3e363c5d-7345-4579-96a0-3d23517af3bc','句  其八','王鎬','宋','宋诗','song-poetry','','[]','催租更擾潘邠老，付麥誰憐石曼卿。',16,'全唐诗/poet.song.181000.json','["催租更擾潘邠老，付麥誰憐石曼卿。"]'),
('47ea34ff-d85f-4648-b88d-04cc52ca7b3f','句  其九','王鎬','宋','宋诗','song-poetry','','[]','山色兩間供步障，松陰半畝當郵亭。',16,'全唐诗/poet.song.181000.json','["山色兩間供步障，松陰半畝當郵亭。"]'),
('88efb06a-38a4-445a-b2e6-e8eb9e6209e5','句  其一○','王鎬','宋','宋诗','song-poetry','','[]','籍通上界神仙府，身現甘泉侍從臣。',16,'全唐诗/poet.song.181000.json','["籍通上界神仙府，身現甘泉侍從臣。"]'),
('dd69022d-1fdf-4c1b-baec-e2601380241d','句  其一一','王鎬','宋','宋诗','song-poetry','','[]','蓬山蘭若入勝概，西寺巖壁饒幽奇。',16,'全唐诗/poet.song.181000.json','["蓬山蘭若入勝概，西寺巖壁饒幽奇。"]'),
('c3ce3fad-7945-4eee-bbdf-ddd261298cce','過董叔達故居','王休','宋','宋诗','song-poetry','','[]','短石拂荒阡，誦君孝行全。',48,'全唐诗/poet.song.181000.json','["短石拂荒阡，誦君孝行全。", "甘泉潛易地，至德上通天。", "明詔再三下，承歡八十年。", "草堂遺址在，溪水遶涓涓。"]'),
('a734c168-a27e-458e-9a74-3af4ad8ca17b','遊普濟寺','王休','宋','宋诗','song-poetry','','[]','排險凌空入磴斜，參差金碧倚煙霞。',64,'全唐诗/poet.song.181000.json','["排險凌空入磴斜，參差金碧倚煙霞。", "一山門裏分三剎，萬柳湖邊带幾家。", "世上無人吞栗棘，國中有佛吐蓮花。", "憑欄凝望遥天表，數點青山似亂鴉。"]'),
('71d914d4-12eb-41d7-ba92-f0c533960c74','題龍巖寺文與可怪石墨竹','程壬孫','宋','宋诗','song-poetry','','[]','風雨勞先別，敢辭樽酒深。',24,'全唐诗/poet.song.181000.json','["風雨勞先別，敢辭樽酒深。", "一梢牆上竹，留作歲寒心。"]'),
('9548bca2-0c07-4359-8298-ebb1ba95393a','讀書巖  其一','程遇孫','宋','宋诗','song-poetry','','[]','綠橘陰雖改，青山色自新。',24,'全唐诗/poet.song.181000.json','["綠橘陰雖改，青山色自新。", "偷閑時挾冊，來訪讀書人。"]'),
('6c0fe68e-52ea-4878-b1f8-90ef6d807c76','讀書巖  其二','程遇孫','宋','宋诗','song-poetry','','[]','穿雲裂石下層巔，來作人間小洞天。',64,'全唐诗/poet.song.181000.json','["穿雲裂石下層巔，來作人間小洞天。", "雙幹翠濃幾欲滴，兩峯玉立巧當前。", "環觀邑屋烏訛尾，倚挹江濤雪滿川。", "城市誰知有清賞，請看山色舊題鎸。"]'),
('6743b87f-a4af-431d-971e-ab205a8f2bad','□□庚午春之七日前成都通川陵陽程遇孫艤東去之舟於涪陵岸下太守謝宋卿以踏磧故事招飲北巖謁伊川先生像于鈎深堂敬賦古詩一章刻諸巖石','程遇孫','宋','宋诗','song-poetry','','[]','春風吹客舟，沙際初倚柁。',168,'全唐诗/poet.song.181000.json','["春風吹客舟，沙際初倚柁。", "懷人愛其屋，木杪危若墮。", "欣從太守遊，江色清照坐。", "當年紹述議，洛黨亦奔播。", "時人欲殺翁，甘此采薇餓。", "流離終愛君，怨語無騷些。", "寥寥十翼後，學易孰無過。", "諸儒踐陳迹，如蟻困旋磨。", "巖棲獨鈎深，混沌與鑿破。", "書成置篋中，山鬼嚴夜邏。", "向來新說行，六籍乃生禍。", "氛埃滿神州，久被犬羊涴。", "何如北巖石，樵牧不敢唾。", "詩寒不成章，聊爲茲石賀。"]'),
('78de3071-986f-4a08-ab28-5675f586309e','次林千之贈水簾洞黄秀才韵','龔日章','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','攀蘿訪山扉，極目窮海表。',120,'全唐诗/poet.song.181000.json','["攀蘿訪山扉，極目窮海表。", "峯疑廬山高，巖若盤谷杳。", "藥臼歷窮凹，石樓迫天小。", "水簾雲頂飛，丹葉天涯渺。", "古峒匝蝴蝶，閑庭喧百鳥。", "誦聲雜石溜，炊烟出林杪。", "藜燭雖未輝，翠屏自環繞。", "內樂屏紛華，天機蔑膠擾。", "虀鹽比膏粱，所得孰多少。", "會須携竹爐，一鳴聽鷄曉。"]'),
('5e255926-b279-4428-8748-33b9405a5cc3','題五曲溪','傅壅','宋','宋诗','song-poetry','','[]','五曲溪流深復深，數椽茅屋舊書林。',32,'全唐诗/poet.song.181000.json','["五曲溪流深復深，數椽茅屋舊書林。", "市朝山澤皆堪隠，誰識先生出處心。"]'),
('743b040f-371e-482e-9ee2-0621f2860d50','經筵徹章御賜詩卷','王與鈞','宋','宋诗','song-poetry','','["\u6885\u82b1", "\u548f\u7269", "\u548f\u7269\u8bd7"]','一種寒梅白玉條，迥臨村路傍溪橋。',32,'全唐诗/poet.song.181000.json','["一種寒梅白玉條，迥臨村路傍溪橋。", "應緣近水花先發，疑是經春雪未消。"]'),
('d9265098-1454-41fc-8620-25bf6a963522','代謝劉小坡送鄉會勸酒賡韻  其一','王與鈞','宋','宋诗','song-poetry','','[]','履端開帝曆，會拜謹王春。',48,'全唐诗/poet.song.181000.json','["履端開帝曆，會拜謹王春。", "百世枌榆舊，一番桃李新。", "珍頒來腆渥，妙句带清真。", "騎省雲霄上，寧辭染翰頻。"]'),
('842a7954-07eb-4a70-9a48-10b09095a6b9','代謝劉小坡送鄉會勸酒賡韻  其二','王與鈞','宋','宋诗','song-poetry','','[]','一枝鷦漫集，千仞鳳方翔。',48,'全唐诗/poet.song.181000.json','["一枝鷦漫集，千仞鳳方翔。", "諫紙清時省，經帷鎮日香。", "湖波憐鴨綠，宮醖挹鵝黄。", "應軫鄉中士，毛錐未脫囊。"]'),
('26dca51c-8cf8-454d-97f2-335368a81c20','游王官谷','王午','宋','宋诗','song-poetry','','[]','耐辱幽人不願名，一丘一壑遂高情。',32,'全唐诗/poet.song.181000.json','["耐辱幽人不願名，一丘一壑遂高情。", "門前流水無冬夏，想見先生到骨清。"]'),
('43af3b7e-1ce0-44ad-9a3f-08da82858cfb','奠謁曲江墓','張訢','宋','宋诗','song-poetry','','[]','中興創業兩興唐，遺烈誰如魏與張。',32,'全唐诗/poet.song.181000.json','["中興創業兩興唐，遺烈誰如魏與張。", "笏在孰知囊可寶，書成未覺鑑今亡。"]'),
('d21aae11-8f45-40ca-99f2-fa35830d6ab8','岑公洞','趙希混','宋','宋诗','song-poetry','','[]','自有烟霞護石扉，更深曉色近清暉。',32,'全唐诗/poet.song.181000.json','["自有烟霞護石扉，更深曉色近清暉。", "巖前老檜吟風處，似請仙翁化鶴歸。"]'),
('ac460073-e078-42d8-8e4e-545afdc98176','賦玉岩','趙希融','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君不見陶令門前栽五柳，聊爲折腰辭五斗。',198,'全唐诗/poet.song.181000.json','["君不見陶令門前栽五柳，聊爲折腰辭五斗。", "歸來三徑足歡娛，琴書得趣人誰有。", "又不見和靖卜築臨西湖，湖山勝景天下無。", "至今疏影橫斜句，人與梅花共清癯。", "古來逸士皆如此，一節純全能終始。", "三歎古風挽莫回，幸有玉岩人足比。", "二十餘年養浩深，厭居朝市入山林。", "此身出處無非道，憂世誰知一寸心。", "愧予朱墨塵埃裏，恨不巖前濯清泚。", "想象入室芝蘭馨，有□清廟遺音美。", "聞說當年贈監書，蒲公之見特其粗。", "要知命義吾儒事，願學同遊周邵蘇。"]'),
('4138be11-8457-4e25-836e-3bca13668249','止泓亭','趙希發','宋','宋诗','song-poetry','','[]','止泓清而明，如彼秋月滿。',24,'全唐诗/poet.song.181000.json','["止泓清而明，如彼秋月滿。", "以此觀我心，澄源斯近本。"]'),
('d6616768-8168-4aca-826e-388aae3ba591','白鷺','趙希崱','宋','宋诗','song-poetry','','[]','漠漠江湖自在飛，一身到處占漁磯。',32,'全唐诗/poet.song.181000.json','["漠漠江湖自在飛，一身到處占漁磯。", "稻田水淺魚能幾，莫被泥沙汙雪衣。"]'),
('8f9402ef-3db8-47e4-b2bb-b638f59c243a','題雲間閣','趙希濬','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','昔年嚴大夫，偶來怨遷謫。',132,'全唐诗/poet.song.181000.json','["昔年嚴大夫，偶來怨遷謫。", "我本麋鹿姿，得此已自適。", "乘閒陟上方，□尋唐人石。", "豈期當三伏，一天雲四冪。", "快哉風南來，萬籟相呼吸。", "雨餘禾麻潤，是山皆喜色。", "一杯傾晚飲，綠瓜間未實。", "是非不到耳，休厭山城寂。", "樹影抹橫烟，角聲暗落日。", "長江去不返，况此百年客。", "企首老玉仙，白髮何由摘。"]'),
('5fbfd0e4-0cb6-46f4-ae82-7dae197bdc1f','寄廣南轉運陳學士','趙希晝','宋','宋诗','song-poetry','','[]','極望隨南斗，迢迢思欲迷。',48,'全唐诗/poet.song.181000.json','["極望隨南斗，迢迢思欲迷。", "春生桂嶺外，人在海門西。", "殘日依山盡，長天向水低。", "遥知仙館夢，清夜怯猿啼。"]'),
('cfe3107c-0c8e-48f6-b6c7-0629189f1b4c','寄潮州于公九流','趙希晝','宋','宋诗','song-poetry','','[]','扁舟如葉路東西，一片灘聲下惡谿。',32,'全唐诗/poet.song.181000.json','["扁舟如葉路東西，一片灘聲下惡谿。", "當日亭臺舊時客，相逢莫惜醉如泥。"]'),
('7595e6f7-2d2b-4542-8e55-8ca92303596b','秦洞','趙希鶚','宋','宋诗','song-poetry','','[]','白鷗曾此識機心，渭水翻波自不禁。',64,'全唐诗/poet.song.181000.json','["白鷗曾此識機心，渭水翻波自不禁。", "當日尚嫌文網闊，後來誰測武陵深。", "西風落葉吹秦晉，流水桃花迭古今。", "世豈避人人避世，九垓同此夕陽陰。"]'),
('cd2a942d-2024-4c81-a51b-94b5d552d012','半山寺有感','趙希淦','宋','宋诗','song-poetry','','[]','一水波澄接御溝，近城宮柳弄春柔。',64,'全唐诗/poet.song.181000.json','["一水波澄接御溝，近城宮柳弄春柔。", "烏衣巷裏人何在，白鷺洲前水自流。", "千古風流歌舞地，六朝興廢帝王州。", "今番不負看山約，他日重來說舊游。"]'),
('cc89f2fb-5a88-485d-a093-49d915dd8af4','迎饗送神歌','趙希鵠','宋','宋诗','song-poetry','','[]','陶峰聳兮髻而藍，縈二水兮秋月環。',99,'全唐诗/poet.song.181000.json','["陶峰聳兮髻而藍，縈二水兮秋月環。", "雲棟起兮鬰松關，侯兮歸來樂且閒。", "肆維牲兮釃爲醴，達馨香兮薦嘉旨。", "侯不我吐兮心則喜，歲歲春秋兮受多祉。", "雲旗騖兮蹌蹌，玉虬駕兮飆之揚。", "侯雖往兮終返故鄉，欲雨則雨兮暘則暘。"]'),
('d70954ce-3404-410d-ada9-3ca9743a6045','旅中聞笛','趙希彩','宋','宋诗','song-poetry','','[]','清宵難獨寐，誰把曲來謳。',24,'全唐诗/poet.song.181000.json','["清宵難獨寐，誰把曲來謳。", "曲裏聲聲思，離人輾轉愁。"]'),
('167f18bb-255e-47e4-9e3a-74ade7e3f5ab','題狄梁公白雲圖','趙希彩','宋','宋诗','song-poetry','','[]','悵望登臨日，大行山頂頭。',24,'全唐诗/poet.song.181000.json','["悵望登臨日，大行山頂頭。", "親幃何處是，一片白雲浮。"]'),
('28fb7d59-3764-4b66-a22e-6c58d17210e0','哭宗兄崇漣','趙希彩','宋','宋诗','song-poetry','','[]','何事西風惡，天涯拆雁行。',48,'全唐诗/poet.song.181000.json','["何事西風惡，天涯拆雁行。", "靈魂招未得，存稿睹難忘。", "感德空垂淚，聞哀欲斷腸。", "相思無頼處，暮雨倍凄凉。"]'),
('bc6f2c5f-ad96-4515-a268-dee8c043c642','翠蛟亭和鞏栗齋韻','趙彥假','宋','宋诗','song-poetry','','[]','天下名洞天，有山必有水。',204,'全唐诗/poet.song.181000.json','["天下名洞天，有山必有水。", "餘杭山水窟，神仙所棲止。", "仙人乘雲去，玉蛟留潭底。", "至今雷雨夕，蛟睡時驚起。", "爪劈巖石裂，石罅滴乳髓。", "涓涓泉流出，半垂白鳳尾。", "風來琴筑響，月照纓絡侈。", "曲折納深池，徹底清且泚。", "築亭當澗衝，木石相表裏。", "翠壁潤含烟，層峯去天咫。", "道人幻出奇，指顧猶未已。", "忽驅蛟走鬭，瞬息八百里。", "怒氣挾奔霆，草木爲披靡。", "兒童驚震掉，面若槁灰死。", "達人本大觀，談笑自隠几。", "須臾羣動息，靜坐窮物理。", "水石本無心，相激一至此。"]'),
('0cc0c219-1887-40f8-ba16-fa0df6930b1e','昭君曲','劉宰','宋','宋诗','song-poetry','','[]','朝日曜兮春花，玉壺炯兮清冰。',135,'全唐诗/poet.song.181000.json','["朝日曜兮春花，玉壺炯兮清冰。", "耿余心兮不欺，付妍醜兮丹青。", "君王兮宵衣，壯士悲歌兮戰死。", "豈余身兮憚殃，抗風沙兮萬里。", "崔嵬兮增城，璀燦兮昭陽。", "羌末路兮多艱，幸朕時之不當。", "氊裘兮娛嬉，穹廬兮容與。", "怨羣胡兮我欺，諗九天兮誰許。", "南風兮徐來，掩涕兮無語。", "四十五十兮無家，抑有慚兮夔女。"]'),
('ae54bd43-2c6e-4dea-a7eb-c22afe23cc86','和樓倅宗簿  其一','劉宰','宋','宋诗','song-poetry','','[]','草莽莽兮平臺，鳥翩翩兮去來。',90,'全唐诗/poet.song.181000.json','["草莽莽兮平臺，鳥翩翩兮去來。", "側身兮引睇，長太息兮徘徊。", "攬余轡兮高騖，豈不夙夜兮謂行多露。", "漱流泉兮枕石，憺無營兮得我所。", "同心兮離居，未傾蓋兮有書。", "歲既晏兮無娛，我思君兮君開關而望余。"]'),
('98c6e66a-a985-47c1-b508-c6910c326928','和樓倅宗簿  其二','劉宰','宋','宋诗','song-poetry','','[]','余幼好此奇服兮，歲荏苒而華顛。',119,'全唐诗/poet.song.181000.json','["余幼好此奇服兮，歲荏苒而華顛。", "聞若人之好修兮，搴衆芳而獨專。", "結微情以陳詞兮，鱗鴻杳以無傳。", "惟聖哲之茂行兮，在舉能而任賢。", "橫江湖以揚舲兮，寧維楫之可捐。", "爛晨光兮破羣幽，清風發兮涼氣颼颼。", "瓊珮兮鏘鏘，玉鸞鳴兮啾啾。", "時不可兮驟得，君胡爲乎此留。"]'),
('b13a9f20-e8b8-4eed-b4d0-51cbc047f5f5','月桂辭送陳兄部運京口','劉宰','宋','宋诗','song-poetry','','[]','芳菲菲兮月之桂，子之家兮傳芳世世。',81,'全唐诗/poet.song.181000.json','["芳菲菲兮月之桂，子之家兮傳芳世世。", "月之桂兮古猶今，往則得兮子寧不嗣音。", "冠鶡冠兮謝章甫，司征商兮河之滸。", "更兼官兮部運，幸訖事兮無忤。", "歸來兮歸來，倚門悵望兮高堂慈母。"]'),
('473932bd-190b-4423-a9da-b2f390e802a4','書竇文卿墓','劉宰','宋','宋诗','song-poetry','','[]','棟宇兮煌煌，鬢髮兮蒼蒼。',102,'全唐诗/poet.song.181000.json','["棟宇兮煌煌，鬢髮兮蒼蒼。", "羌一言兮會心，駕吾車兮建陽。", "車既駕兮遄歸，今良是兮昨非。", "釋衆累兮春冰，耿吾心兮夕暉。", "斯道兮孔壽，斯人兮不忘。", "十載兮重來，泬漻兮此堂。", "風撼兮寒松，霜凋兮百草。", "佳城兮葱葱，萬古兮是保。"]'),
('4b4893dd-8fb9-4e8e-a195-fa42c699cb20','雲邊種松','劉宰','宋','宋诗','song-poetry','','[]','漸止牛羊牧，還添雨露滋。',24,'全唐诗/poet.song.181000.json','["漸止牛羊牧，還添雨露滋。", "但令萌蘗長，自有歲寒姿。"]'),
('29b6fbe8-cb04-4cec-9768-001355dae3e2','題屏間','劉宰','宋','宋诗','song-poetry','','[]','野曠乾坤大，身閒日月遲。',24,'全唐诗/poet.song.181000.json','["野曠乾坤大，身閒日月遲。", "有生均自得，造物本無私。"]'),
('f0910aeb-0370-4741-a9ad-ddb128c17ee0','謝陳僉惠紅綠柿','劉宰','宋','宋诗','song-poetry','','[]','紅綠分佳果，丹青讓好辭。',24,'全唐诗/poet.song.181000.json','["紅綠分佳果，丹青讓好辭。", "遥憐霜落葉，岸幘坐題詩。"]'),
('dc17b2b9-e38d-4133-82e8-20b99fe4087b','送李季允侍郎歸蜀五絕用禪房花竹幽爲韻  其一','劉宰','宋','宋诗','song-poetry','','[]','密葉秋逾潤，幽花晚更妍。',24,'全唐诗/poet.song.181000.json','["密葉秋逾潤，幽花晚更妍。", "去來誰是主，試問白頭禪。"]'),
